void ReadAllFiles()
{
	ReadPaedAssumps();
	ReadAdultAssumps();
	ReadRollout();
	ReadStartingPop();
	ReadMarriage();
	ReadCD4dbn();
	ReadNonHIVmort();
	if (FixedUncertainty == 1){ ReadWestTable(); }
	ReadFertility();
	ReadMigration();
	ReadCalibData();
	ReadInitPrev();
	if (FixedARTinitiation == 1 && FixedUncertainty == 1){ ReadAdultRoot(); }
	if (IncludeTB == 1) {
		ReadInitTB();
		ReadTBadultAssumps();
		ReadTBrollout();
		ReadTBriskFactorPrev();
		ReadTBmortData();
		ReadTB_ETRdata();
		ReadTBlabDiag();
		ReadTBprevData();
		if (CalibTB_HIV_OR == 1) { ReadTB_HIV_ORs(); }
		if (FixedTBscreening == 1 && FixedUncertainty == 1) { ReadTBscreening(); }
	}
}

