void SetARTinitiation()
{
	int ig, is, im;
	double Temp;

	// Set adult ART initiation
	if (InputARTinitiationRates == 0){
		Temp = StartingART_M + StartingART_F;
		if (Temp == 0.0 && CurrYear <= ARTdataYr){
			CurrARTinitiation[0] = 0.0;
			CurrARTinitiation[1] = 0.0;
		}
		else if (Temp == 0.0 && CurrYear > ARTdataYr){
			for (ig = 0; ig<2; ig++){
				if (CurrYear>UltARTyr[ig]){
					CurrARTinitiation[ig] = 1.0 / UltARTdelay[ig];
				}
				else{
					CurrARTinitiation[ig] = StoredRoot[ig] + ((1.0 / UltARTdelay[ig]) -
						StoredRoot[ig]) * (CurrYear - ARTdataYr) / (UltARTyr[ig] - ARTdataYr);
				}
			}
		}
		else{
			SetAdultARTinitiation2();
		}
	}
	else{
		CurrARTinitiation[0] = RateARTstartF[CurrYear - StartYear] * RR_ARTstartM;
		CurrARTinitiation[1] = RateARTstartF[CurrYear - StartYear];
		if (CurrYear == 2019 && CurrMonth >= 9){ 
			CurrARTinitiation[0] *= (1.0 - COVIDimpactARTstart);
			CurrARTinitiation[1] *= (1.0 - COVIDimpactARTstart);
		}
		if ((CurrYear == 2024 && CurrMonth >= 6) || CurrYear > 2024) {
			CurrARTinitiation[0] *= (1.0 - USAIDexitImpact);
			CurrARTinitiation[1] *= (1.0 - USAIDexitImpact);
		}
	}
	AsymStart[0] = CurrARTinitiation[0] * RR_ARTstart1stMo;
	AsymStart[1] = CurrARTinitiation[1] * RR_ARTstart1stMo;
	if (CurrYear == 2011){
		// A hacky attempt to push up enrolment in 2011-12 relative to later years (part 2)
		if (InputARTinitiationRates == 1){
			CurrARTinitiation[0] *= RR_ARTstart1stMo / RR_ART1stMo2011;
			CurrARTinitiation[1] *= RR_ARTstart1stMo / RR_ART1stMo2011;
		}
		else{
			AsymStart[0] = CurrARTinitiation[0] * RR_ART1stMo2011;
			AsymStart[1] = CurrARTinitiation[1] * RR_ART1stMo2011;
		}
	}
	for (ig = 0; ig < 2; ig++){
		ARTinitByStage[0][ig] = 0.0;
		for (is = 1; is < 5; is++){
			ARTinitByStage[is][ig] = CurrARTinitiation[ig] * RR_ARTinitiation[is] /
				RR_ARTinitiation[4];
		}
		ARTinitByStage[1][ig] *= EligibleAsymPre500[CurrYear - StartYear];
		ARTinitByStage[2][ig] *= EligibleAsym500[CurrYear - StartYear];
		ARTinitByStage[3][ig] *= EligibleAsym350[CurrYear - StartYear];
	}

	// Set paediatric ART initiation
	if (InputARTinitiationRates == 0){
		if (CurrYear <= InterpolationStart){
			if (StartingART_P == 0.0){
				PaedARTinitiation = 0.0;
			}
			else{
				SetPaedARTinitiation2();
			}
		}
		else{
			if (CurrYear >= UltimateYr){
				PaedARTinitiation = 1.0 / UltARTdelayC;
			}
			else{
				PaedARTinitiation = ARTinitiationStore + ((1.0 / UltARTdelayC) - ARTinitiationStore) *
					(CurrYear - InterpolationStart) / (UltimateYr - InterpolationStart);
			}
		}
		PaedARTuptakeC = 1.0 - exp(-PaedARTinitiation * RR_ARTstart1stMo);
		// Note that we're not applying ImmARTcorrectionP (which is now only used for linkage after EID).
		// Also note PaedARTuptakeC is always a probability, unlike AsymStart, which is a rate.
	}
	else{
		PaedARTinitiation = RateARTstartC[CurrYear - StartYear];
	}
	ARTinitByStage[0][2] = 0.0;
	ARTinitByStage[4][2] = PaedARTinitiation;
	for (is = 1; is < 4; is++){
		ARTinitByStage[is][2] = ARTinitByStage[4][2] * RRearlyPaedART*EarlyART5to14[CurrYear-StartYear];}

	//if(FixedARTinitiation==1 && FixedUncertainty==1 && CurrYear<InterpolationStart){
	//	PaedARTinitiation = TotalARTinitiation.out[CurrSim-1][CurrYear-1985]/12.0;}
	ARTinitiation[0] = 0.0;
	ARTinitiation[1] = 0.0;
	for(im=2; im<132; im++){
		ARTinitiation[im] = PaedARTinitiation;}
}

void SetAdultARTinitiation()
{
	// This function is redundant.

	int ia, ig, is, is1;
	double SumQuad[2][2]; // Last index is sex (cell AG94:AK94 of 'ART start')
	double RelARTinitiation[5], TempA, TempB, Temp, DiagnosedToART[2];
	double Cparameter[2]; // Starting ART amongst previously diagnosed (AJ8:AK8)
	double Discriminant[2]; // b^2 - 4ac (cells AG97, AI97)

	// Calculate numbers starting ART immediately after diagnosis
	for(ig=0; ig<2; ig++){
		DiagnosedToART[ig] = 0.0;
		for(ia=0; ia<76; ia++){
			for(is=0; is<15; is++){
				if(ig==0){
					TempA = SumGroupsM[ia+5][5+is];
					if(ia<15){
						TempB = SumGroupsVM[ia+5][5+is];}
					else{
						TempB = 0.0;}
				}
				else{
					TempA = SumGroupsF[ia+5][5+is];
					if(ia<15){
						TempB = SumGroupsVF[ia+5][5+is];}
					else{
						TempB = 0.0;}
				}
				if(is==3 || is==4){
					Temp = MnthlyAIDSmort[ia+5][is-3][ig];}
				else if(is==8 || is==9){
					Temp = MnthlyAIDSmort[ia+5][is-8][ig];}
				else if(is==13 || is==14){
					Temp = MnthlyAIDSmort[ia+5][is-13][ig];}
				else{
					Temp = 0.0;}
				DiagnosedToART[ig] += (TempA - TempB) * HCTtoART_SE[ia+5][is][ig] *
					(1.0 - 0.5 * (HCTtoART_SE[ia+5][is][ig] + Temp));
				if(ia<15){
					if(is<5){is1 = is;}
					else if(is<10){is1 = is - 5;}
					else{is1 = is - 10;}
					DiagnosedToART[ig] += TempB * HCTtoART_V[ia+5][is1][ig] *
						(1.0 - 0.5 * (HCTtoART_V[ia+5][is1][ig] + Temp));
				}
			}
		}
	}
	Cparameter[0] = (StartingART_M/12.0) - DiagnosedToART[0];
	Cparameter[1] = (StartingART_F/12.0) - DiagnosedToART[1];

	// Calculate quadratic terms for rate of ART initiation in previously-diagnosed.
	RelARTinitiation[0] = 0.0;
	RelARTinitiation[1] = RR_ARTinitiation[1] * EligibleAsymPre500[CurrYear-StartYear];
	RelARTinitiation[2] = RR_ARTinitiation[2] * EligibleAsym500[CurrYear-StartYear];
	RelARTinitiation[3] = RR_ARTinitiation[3] * EligibleAsym350[CurrYear-StartYear];
	RelARTinitiation[4] = RR_ARTinitiation[4];
	
	SumQuad[0][0] = 0.0;
	SumQuad[0][1] = 0.0;
	SumQuad[1][0] = 0.0;
	SumQuad[1][1] = 0.0;
	for(ia=0; ia<76; ia++){
		// Males
		TempA = 0.0;
		TempB = 0.0;
		for(is=0; is<5; is++){
			TempA += 0.5 * SumGroupsM[ia+5][15+is] * pow(RelARTinitiation[is], 2.0);
			TempB += SumGroupsM[ia+5][15+is] * RelARTinitiation[is];
		}
		TempB = -TempB;
		for(is=0; is<2; is++){
			TempB += 0.5 * SumGroupsM[ia+5][18+is] * RelARTinitiation[is+3] * 
				MnthlyAIDSmort[ia+5][is][0];}
		SumQuad[0][0] += TempA;
		SumQuad[1][0] += TempB;
		// Females
		TempA = 0.0;
		TempB = 0.0;
		for(is=0; is<5; is++){
			TempA += 0.5 * SumGroupsF[ia+5][15+is] * pow(RelARTinitiation[is], 2.0);
			TempB += SumGroupsF[ia+5][15+is] * RelARTinitiation[is];
		}
		TempB = -TempB;
		for(is=0; is<2; is++){
			TempB += 0.5 * SumGroupsF[ia+5][18+is] * RelARTinitiation[is+3] * 
				MnthlyAIDSmort[ia+5][is][1];}
		SumQuad[0][1] += TempA;
		SumQuad[1][1] += TempB;
	}
	
	// Calculate rates of ART initiation in non-pregant, asymptomatic previously-diagnosed adults.
	for(ig=0; ig<2; ig++){
		Discriminant[ig] = pow(SumQuad[1][ig], 2.0) - 4.0 * SumQuad[0][ig] * Cparameter[ig];
		if(Cparameter[ig]<0.0){
			AdultRoot[ig] = 0.0;}
		else if(Discriminant[ig]>0.0){
			AdultRoot[ig] = (-SumQuad[1][ig] - pow(Discriminant[ig], 0.5))/(2.0 * 
				SumQuad[0][ig]);}
		else{
			AdultRoot[ig] = 1.0/MinARTdelay[ig];}
		if (AdultRoot[ig] >= 1.0 / MinARTdelay[ig]){ 
			ARTerrorInd = 1; 
			if (pow(AdultRoot[ig] - 1.0 / MinARTdelay[ig], 2.0) > MaxARTerror){
				MaxARTerror = pow(AdultRoot[ig] - 1.0 / MinARTdelay[ig], 2.0);
			}
		}
		CurrARTinitiation[ig] = AdultRoot[ig];
		if(CurrYear==ARTdataYr){
			StoredRoot[ig] = AdultRoot[ig];}
	}
	if (FixedUncertainty == 1 && FixedARTinitiation == 1){
		AdultRoot[0] = AdultRootM.out[CurrSim - 1][CurrYear - StartYear];
		AdultRoot[1] = AdultRootF.out[CurrSim - 1][CurrYear - StartYear];
	}
	if (FixedUncertainty == 1 && CurrMonth == 6 && FixedARTinitiation == 0){
		AdultRootM.out[CurrSim - 1][CurrYear - StartYear] = AdultRoot[0];
		AdultRootF.out[CurrSim - 1][CurrYear - StartYear] = AdultRoot[1];
	}
}

void SetAdultARTinitiation2()
{
	int ia, ig, is, is1, ii;
	double SumQuad[2][2]; // 1st index in order of term in quadratic, last index is sex
	double RelARTinitiation[5], TempA, TempB, Temp, TempRR_1stMo;
	double NewDiagnosedElig[4][2], PrevDiagnosedElig[4][2];
	double Cparameter[2]; // Starting ART 
	double Discriminant[2]; // b^2 - 4ac (when solving quadratic)

	// Calculate numbers newly diagnosed/rediagnosed who are ART-eligible
	for (ig = 0; ig<2; ig++){
		for (is1 = 0; is1 < 4; is1++){ // is1 = CD4 stage
			NewDiagnosedElig[is1][ig] = 0.0;
			for (ia = 0; ia < 76; ia++){
				for (is = 0; is < 3; is++){
					// is is the testing history indicator (0 = never tested, 1 = last tested negative,
					// 2 = previously diagnosed)
					if (ig == 0){
						TempA = SumGroupsM[ia + 5][6 + is * 5 + is1];
						if (ia < 15){
							TempB = SumGroupsVM[ia + 5][6 + is * 5 + is1];
						}
						else{
							TempB = 0.0;
						}
					}
					else{
						TempA = SumGroupsF[ia + 5][6 + is * 5 + is1];
						if (ia < 15){
							TempB = SumGroupsVF[ia + 5][6 + is * 5 + is1];
						}
						else{
							TempB = 0.0;
						}
					}
					NewDiagnosedElig[is1][ig] += (TempA - TempB) * (1.0 - exp(-TestingRateEligSE[ia + 5][1 + is * 5 + is1][ig]));
					if (ia < 15){
						NewDiagnosedElig[is1][ig] += TempB * (1.0 - exp(-TestingRateEligV[ia + 5][1 + is1][ig]));
					}
				}
				/*if (is1 == 0){ 
					// We only need to execute this loop once, since ART interrupters aren't 
					// stratified by CD4 (i.e. no need to loop over is1).
					NewDiagnosedElig[is1][ig] += TotalInterrupt[ia + 15][ig] * 
						TestingRateEligSE[ia + 5][14][ig] * RetestART / RetestPos;
				}*/
			}
		}
	}
	Cparameter[0] = (StartingART_M / 12.0);
	Cparameter[1] = (StartingART_F / 12.0);
	if (CurrYear == 2019){
		Temp = 9.0 + 3.0 * (1.0 - COVIDimpactARTstart);
		for (ig = 0; ig < 2; ig++){
			if (CurrMonth < 9){ Cparameter[ig] *= 12.0 / Temp; }
			else{ Cparameter[ig] *= 12.0 * (1.0 - COVIDimpactARTstart) / Temp; }
		}
	}
	if (CurrYear == 2024) {
		Temp = 6.0 + 6.0 * (1.0 - USAIDexitImpact);
		for (ig = 0; ig < 2; ig++) {
			if (CurrMonth < 6) { Cparameter[ig] *= 12.0 / Temp; }
			else { Cparameter[ig] *= 12.0 * (1.0 - USAIDexitImpact) / Temp; }
		}
	}

	// Calculate quadratic terms for rate of ART initiation in previously-diagnosed.
	RelARTinitiation[0] = 0.0;
	RelARTinitiation[1] = RR_ARTinitiation[1] * EligibleAsymPre500[CurrYear - StartYear];
	RelARTinitiation[2] = RR_ARTinitiation[2] * EligibleAsym500[CurrYear - StartYear];
	RelARTinitiation[3] = RR_ARTinitiation[3] * EligibleAsym350[CurrYear - StartYear];
	RelARTinitiation[4] = RR_ARTinitiation[4];

	SumQuad[0][0] = 0.0;
	SumQuad[0][1] = 0.0;
	SumQuad[1][0] = 0.0;
	SumQuad[1][1] = 0.0;
	for (ia = 0; ia<76; ia++){
		// Males
		TempA = 0.0;
		TempB = 0.0;
		for (is = 0; is<5; is++){ // Now is = CD4 stage
			TempA += 0.5 * SumGroupsM[ia + 5][15 + is] * pow(RelARTinitiation[is], 2.0);
			TempB += SumGroupsM[ia + 5][15 + is] * RelARTinitiation[is];
		}
		TempB = -TempB;
		/*for (is = 0; is<2; is++){
			// Consider removing this mortality correction in next version of Thembisa?
			// But doing so leads to poorer consistency between ART inputs and outputs.
			TempB += 0.5 * SumGroupsM[ia + 5][18 + is] * RelARTinitiation[is + 3] *
				MnthlyAIDSmort[ia + 5][is][0];
		}*/
		SumQuad[0][0] += TempA;
		SumQuad[1][0] += TempB;
		// Females
		TempA = 0.0;
		TempB = 0.0;
		for (is = 0; is<5; is++){
			TempA += 0.5 * SumGroupsF[ia + 5][15 + is] * pow(RelARTinitiation[is], 2.0);
			TempB += SumGroupsF[ia + 5][15 + is] * RelARTinitiation[is];
		}
		TempB = -TempB;
		/*for (is = 0; is<2; is++){
			// Consider removing this mortality correction in next version of Thembisa?
			TempB += 0.5 * SumGroupsF[ia + 5][18 + is] * RelARTinitiation[is + 3] *
				MnthlyAIDSmort[ia + 5][is][1];
		}*/
		SumQuad[0][1] += TempA;
		SumQuad[1][1] += TempB;
		/*for (ig = 0; ig < 2; ig++){
			SumQuad[0][ig] += 0.5 * TotalInterrupt[ia + 15][ig] * pow(RelARTinitiation[4], 2.0);
			SumQuad[1][ig] = SumQuad[1][ig] - TotalInterrupt[ia + 15][ig] * RelARTinitiation[4];
		}*/
	}
	if (CurrYear != 2011){
		for (is = 1; is < 5; is++){
			SumQuad[0][0] += 0.5 * NewDiagnosedElig[is - 1][0] * pow(RR_ARTinitiation[is] * RR_ARTstart1stMo, 2.0);
			SumQuad[0][1] += 0.5 * NewDiagnosedElig[is - 1][1] * pow(RR_ARTinitiation[is] * RR_ARTstart1stMo, 2.0);
			SumQuad[1][0] = SumQuad[1][0] - NewDiagnosedElig[is - 1][0] * RR_ARTinitiation[is] * RR_ARTstart1stMo;
			SumQuad[1][1] = SumQuad[1][1] - NewDiagnosedElig[is - 1][1] * RR_ARTinitiation[is] * RR_ARTstart1stMo;
		}
	}
	else{
		// A hacky attempt to push up enrolment in 2011-12 relative to later years (part 1)
		for (is = 1; is < 5; is++){
			SumQuad[0][0] += 0.5 * NewDiagnosedElig[is - 1][0] * pow(RR_ARTinitiation[is] * RR_ART1stMo2011, 2.0);
			SumQuad[0][1] += 0.5 * NewDiagnosedElig[is - 1][1] * pow(RR_ARTinitiation[is] * RR_ART1stMo2011, 2.0);
			SumQuad[1][0] = SumQuad[1][0] - NewDiagnosedElig[is - 1][0] * RR_ARTinitiation[is] * RR_ART1stMo2011;
			SumQuad[1][1] = SumQuad[1][1] - NewDiagnosedElig[is - 1][1] * RR_ARTinitiation[is] * RR_ART1stMo2011;
		}
	}

	// Calculate rates of ART initiation in non-pregant, asymptomatic previously-diagnosed adults.
	for (ig = 0; ig<2; ig++){
		Discriminant[ig] = pow(SumQuad[1][ig], 2.0) - 4.0 * SumQuad[0][ig] * Cparameter[ig];
		if (Cparameter[ig]<0.0){
			AdultRoot[ig] = 0.0;
		}
		else if (Discriminant[ig]>0.0){
			AdultRoot[ig] = (-SumQuad[1][ig] - pow(Discriminant[ig], 0.5)) / (2.0 *
				SumQuad[0][ig]);
		}
		else{
			AdultRoot[ig] = 1.0 / MinARTdelay[ig];
		}
	}

	// The code that follows uses the Newton-Raphson method to improve the initial
	// approximation (new in Thembisa 4.7). Start by calculating PrevDiagnosedElig.

	for (is = 1; is < 5; is++){
		if (is == 1){ Temp = EligibleAsymPre500[CurrYear - StartYear]; }
		else if (is == 2){ Temp = EligibleAsym500[CurrYear - StartYear]; }
		else if (is == 3){ Temp = EligibleAsym350[CurrYear - StartYear]; }
		else{ Temp = 1.0; }
		TempA = 0.0; // Males
		TempB = 0.0; // Females
		for (ia = 0; ia < 76; ia++){
			TempA += SumGroupsM[ia + 5][15 + is] * Temp;
			TempB += SumGroupsF[ia + 5][15 + is] * Temp;
		}
		PrevDiagnosedElig[is - 1][0] = TempA;
		PrevDiagnosedElig[is - 1][1] = TempB;
	}

	// Next do the Newton-Raphson calculation

	if (CurrYear != 2011){ TempRR_1stMo = RR_ARTstart1stMo; }
	else{ TempRR_1stMo = RR_ART1stMo2011; } // Same hack as before
	/*for (ii = 0; ii < 2; ii++){ // ii refers to Newton-Raphson step
		for (ig = 0; ig < 2; ig++){
			Temp = AdultRoot[ig];
			// Now TempA is the function of AdultRoot and TempB is its derivative.
			TempA = 0.0;
			TempB = 0.0;
			for (is = 0; is < 4; is++){
				TempA += NewDiagnosedElig[is][ig] * (1.0 - exp(-Temp * TempRR_1stMo *
					RR_ARTinitiation[is + 1])) + PrevDiagnosedElig[is][ig] * (1.0 - exp(-Temp *
					RR_ARTinitiation[is + 1]));
				TempB += TempRR_1stMo * RR_ARTinitiation[is + 1] * NewDiagnosedElig[is][ig] *
					exp(-Temp * TempRR_1stMo * RR_ARTinitiation[is + 1]) + RR_ARTinitiation[is + 1] *
					PrevDiagnosedElig[is][ig] * exp(-Temp * RR_ARTinitiation[is + 1]);
			}
			TempA = TempA - Cparameter[ig]; // subtracting ART initiations
			AdultRoot[ig] = Temp - TempA / TempB;
			if (AdultRoot[ig] < 0.0){ AdultRoot[ig] = 0.0; }
			if (AdultRoot[ig] > 1.0){ AdultRoot[ig] = 1.0; }
		}
	}*/

	// Now back to the same code we had in Thembisa 4.6

	for (ig = 0; ig < 2; ig++){
		if (AdultRoot[ig] >= 1.0 / MinARTdelay[ig]){
			ARTerrorInd = 1;
			if (pow(AdultRoot[ig] - 1.0 / MinARTdelay[ig], 2.0) > MaxARTerror){
				MaxARTerror = pow(AdultRoot[ig] - 1.0 / MinARTdelay[ig], 2.0);
			}
		}
		CurrARTinitiation[ig] = AdultRoot[ig];
		if (CurrYear == ARTdataYr && CurrMonth == 5){
			StoredRoot[ig] = AdultRoot[ig];
		}
	}
	if (FixedUncertainty == 1 && FixedARTinitiation == 1){
		AdultRoot[0] = AdultRootM.out[CurrSim - 1][CurrYear - StartYear];
		AdultRoot[1] = AdultRootF.out[CurrSim - 1][CurrYear - StartYear];
	}
	if (FixedUncertainty == 1 && CurrMonth == 6 && FixedARTinitiation == 0){
		AdultRootM.out[CurrSim - 1][CurrYear - StartYear] = AdultRoot[0];
		AdultRootF.out[CurrSim - 1][CurrYear - StartYear] = AdultRoot[1];
	}
}

void CalcARTdisruptionImpact(int Type)
{
	int ia, is, ig;
	double Impact;

	if (Type == 1) { Impact = COVIDimpactARTstart; }
	else if (Type == 2) { Impact = USAIDexitImpact; }
	else { Impact = 0.0; }

	for (ia = 0; ia < 81; ia++){
		for (is = 0; is < 15; is++){
			for (ig = 0; ig < 2; ig++){
				HCTtoART_SE[ia][is][ig] *= (1.0 - Impact);
			}
		}
	}
	for (ia = 0; ia < 20; ia++){
		for (is = 0; is < 5; is++){
			for (ig = 0; ig < 2; ig++){
				HCTtoART_V[ia][is][ig] *= (1.0 - Impact);
			}
		}
	}
}

void SetPaedARTinitiation()
{
	int ia, im, iy, is;
	double sumA, sumB, TargetStartingART, root;
	double MnthlyTestProb[2]; // for early and late disease

	iy = CurrYear - StartYear;
	sumA = 0.0;
	sumB = 0.0;
	for(im=0; im<132; im++){
		MnthlyTestProb[0] = 0.0;
		if (im == 18){ MnthlyTestProb[0] = CurrTesting18mo[1]; }
		if (im > 18 && im<60){ MnthlyTestProb[0] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin * RRtestAgePaed); }
		if (im >= 60){ MnthlyTestProb[0] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin); }
		if (im < 60){ MnthlyTestProb[1] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin * RRtestPaedAdvanced * RRtestAgePaed); }
		else{ MnthlyTestProb[1] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin * RRtestPaedAdvanced); }
		StartingARTnoBirthPCR[im][0] = MnthlyTestProb[1] * (MaleChild.ARTeligible[im] + FemChild.ARTeligible[im]) * PaedARTuptakeC *
			pow(1.0 - AIDSmortNoART[im], MortAdjLate[0]); // New
		if (im >= 18 && im<60){
			StartingARTnoBirthPCR[im][0] += MnthlyTestProb[0] * (MaleChild.PosChildAtBirthPMTCT[im] +
				MaleChild.PosChildAtBirthNoPMTCT[im] + MaleChild.PosChildAfterBirth[im] + FemChild.PosChildAtBirthPMTCT[im] +
				FemChild.PosChildAtBirthNoPMTCT[im] + FemChild.PosChildAfterBirth[im]) * EarlyART1to4[iy] * RRearlyPaedART *
				PaedARTuptakeC;
		}
		if (im >= 60){
			StartingARTnoBirthPCR[im][0] += MnthlyTestProb[0] * (MaleChild.PosChildAtBirthPMTCT[im] +
				MaleChild.PosChildAtBirthNoPMTCT[im] + MaleChild.PosChildAfterBirth[im] + FemChild.PosChildAtBirthPMTCT[im] +
				FemChild.PosChildAtBirthNoPMTCT[im] + FemChild.PosChildAfterBirth[im]) * EarlyART5to14[iy] * RRearlyPaedART *
				PaedARTuptakeC;
		}
		StartingARTnoBirthPCR[im][1] = (MaleChild.DiagChildAtBirthPMTCT[im] + MaleChild.DiagChildAtBirthNoPMTCT[im] +
			MaleChild.DiagChildAfterBirth[im] + FemChild.DiagChildAtBirthPMTCT[im] +
			FemChild.DiagChildAtBirthNoPMTCT[im] + FemChild.DiagChildAfterBirth[im]) * RRearlyPaedART;
		if (im < 12){ StartingARTnoBirthPCR[im][1] *= EligInfants; }
		else if (im < 60){ StartingARTnoBirthPCR[im][1] *= EarlyART1to4[iy]; }
		else{ StartingARTnoBirthPCR[im][1] *= EarlyART5to14[iy]; }
		StartingARTnoBirthPCR[im][1] += (MaleChild.DiagARTeligible[im] + FemChild.DiagARTeligible[im]) *
			pow(1.0 - AIDSmortNoART[im], MortAdjLate[0]); // New
		sumA += StartingARTnoBirthPCR[im][0];
		sumB += StartingARTnoBirthPCR[im][1];
	}
	for(ia=0; ia<5; ia++){
		for (is = 1; is < 5; is++){
			sumA += ((SumGroupsM[ia][is + 5] + SumGroupsM[ia][is + 10]) * TestingRateV[ia][is][0] +
				(SumGroupsF[ia][is + 5] + SumGroupsF[ia][is + 10]) * TestingRateV[ia][is][1]) *
				EarlyART5to14[iy] * PaedARTuptakeC;
		}
		sumA += (1.0 - EarlyART5to14[iy]) * PaedARTuptakeC * ((SumGroupsM[ia][9] + SumGroupsM[ia][14]) * 
			TestingRateV[ia][4][0] * (1.0 - MnthlyAIDSmort[ia][1][0]) + (SumGroupsF[ia][9] + SumGroupsF[ia][14]) * TestingRateV[ia][4][1] * 
			(1.0 - MnthlyAIDSmort[ia][1][1])); // New
		for (is = 0; is < 4; is++){
			sumB += (SumGroupsM[ia][is + 15] + SumGroupsF[ia][is + 15]) * EarlyART5to14[iy] * RRearlyPaedART;}
		sumB += SumGroupsM[ia][19] * (1.0 - MnthlyAIDSmort[ia][1][0]) + SumGroupsF[ia][19] * (1.0 - MnthlyAIDSmort[ia][1][1]); // New
	}

	if(CurrYear<=InterpolationStart){
		TargetStartingART = (StartingART_P / 12.0) - ((MaleChild.PosChildAtBirthNoPMTCT[1] * SixWeekSe[0] +
			MaleChild.PosChildAtBirthPMTCT[1] * SixWeekSe[1]) * EligInfants + MaleChild.ARTeligible[1] * SixWeekSe[2] +
			(FemChild.PosChildAtBirthNoPMTCT[1] * SixWeekSe[0] + FemChild.PosChildAtBirthPMTCT[1] * SixWeekSe[1]) *
			EligInfants + FemChild.ARTeligible[1] * SixWeekSe[2]) * PCRuptake * PaedARTuptakeEID;
		TargetStartingART = TargetStartingART - (ChildPosNoPMTCT * BirthSe[0] + ChildPosPMTCT * BirthSe[1]) *
			EligInfants * PCRuptakeB * PaedARTuptakeEID/12.0;
		root = (TargetStartingART - sumA) / sumB;
		if (root < 0.0){ root = 0.0; }
		else if (root < 1.0){ root = -log(1.0 - root); }
		else if (root >= 1.0){ 
			ARTerrorInd = 1; 
			if (pow(root - 1.0, 2.0) > MaxARTerror){
				MaxARTerror = pow(root - 1.0, 2.0);
			}
		}
	}
	else{
		if(CurrYear>=UltimateYr){
			root = 1.0/UltARTdelayC;}
		else{
			root = ARTinitiationStore + ((1.0/UltARTdelayC) - ARTinitiationStore) *
				(CurrYear - InterpolationStart) * (UltimateYr - InterpolationStart);}
	}

	PaedARTinitiation = root;
	if (FixedUncertainty == 1 && CurrMonth == 6 && FixedARTinitiation == 0){
		ChildRoot.out[CurrSim - 1][CurrYear - StartYear] = root;
	}
	if(CurrYear==InterpolationStart){
		ARTinitiationStore = root;}
}

void SetPaedARTinitiation2()
{
	int ia, im, iy, is;
	double sumA, sumB, TargetStartingART, root;
	double MnthlyTestProb[2]; // for early and late disease

	// Note that where we refer to StartingARTnoBirthPCR, we are either referring to numbers of new diagnoses (2nd index = 0)
	// or numbers of ART-naive, previously diagnosed children (2nd index = 1).

	iy = CurrYear - StartYear;
	sumA = 0.0;
	sumB = 0.0;
	for (im = 0; im<132; im++){
		MnthlyTestProb[0] = 0.0;
		if (im == 18){ MnthlyTestProb[0] = CurrTesting18mo[1]; }
		if (im > 18 && im<60){ MnthlyTestProb[0] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin * RRtestAgePaed); }
		if (im >= 60){ MnthlyTestProb[0] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin); }
		if (im < 60){ MnthlyTestProb[1] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin * RRtestPaedAdvanced * RRtestAgePaed); }
		else{ MnthlyTestProb[1] = 1.0 - exp(-TestingRateNPF[5] * RRtestVirgin * RRtestPaedAdvanced); }
		StartingARTnoBirthPCR[im][0] = MnthlyTestProb[1] * (MaleChild.ARTeligible[im] + FemChild.ARTeligible[im]) *
			RR_ARTstart1stMo;
		if (im >= 18 && im<60){
			StartingARTnoBirthPCR[im][0] += MnthlyTestProb[0] * (MaleChild.PosChildAtBirthPMTCT[im] +
				MaleChild.PosChildAtBirthNoPMTCT[im] + MaleChild.PosChildAfterBirth[im] + FemChild.PosChildAtBirthPMTCT[im] +
				FemChild.PosChildAtBirthNoPMTCT[im] + FemChild.PosChildAfterBirth[im]) * EarlyART1to4[iy] * RRearlyPaedART *
				RR_ARTstart1stMo;
		}
		if (im >= 60){
			StartingARTnoBirthPCR[im][0] += MnthlyTestProb[0] * (MaleChild.PosChildAtBirthPMTCT[im] +
				MaleChild.PosChildAtBirthNoPMTCT[im] + MaleChild.PosChildAfterBirth[im] + FemChild.PosChildAtBirthPMTCT[im] +
				FemChild.PosChildAtBirthNoPMTCT[im] + FemChild.PosChildAfterBirth[im]) * EarlyART5to14[iy] * RRearlyPaedART *
				RR_ARTstart1stMo;
		}
		StartingARTnoBirthPCR[im][1] = (MaleChild.DiagChildAtBirthPMTCT[im] + MaleChild.DiagChildAtBirthNoPMTCT[im] +
			MaleChild.DiagChildAfterBirth[im] + FemChild.DiagChildAtBirthPMTCT[im] +
			FemChild.DiagChildAtBirthNoPMTCT[im] + FemChild.DiagChildAfterBirth[im]) * RRearlyPaedART;
		if (im < 12){ StartingARTnoBirthPCR[im][1] *= EligInfants; }
		else if (im < 60){ StartingARTnoBirthPCR[im][1] *= EarlyART1to4[iy]; }
		else{ StartingARTnoBirthPCR[im][1] *= EarlyART5to14[iy]; }
		StartingARTnoBirthPCR[im][1] += (MaleChild.DiagARTeligible[im] + FemChild.DiagARTeligible[im]); 
		sumA += StartingARTnoBirthPCR[im][0];
		sumB += StartingARTnoBirthPCR[im][1];
	}
	for (ia = 0; ia<5; ia++){
		for (is = 1; is < 4; is++){
			sumA += ((SumGroupsM[ia][is + 5] + SumGroupsM[ia][is + 10]) * TestingRateV[ia][is][0] +
				(SumGroupsF[ia][is + 5] + SumGroupsF[ia][is + 10]) * TestingRateV[ia][is][1]) *
				EarlyART5to14[iy] * RR_ARTstart1stMo;
		}
		sumA += ((SumGroupsM[ia][9] + SumGroupsM[ia][14]) * TestingRateV[ia][4][0] +
			(SumGroupsF[ia][9] + SumGroupsF[ia][14]) * TestingRateV[ia][4][1]) * RR_ARTstart1stMo;
		for (is = 0; is < 4; is++){
			sumB += (SumGroupsM[ia][is + 15] + SumGroupsF[ia][is + 15]) * EarlyART5to14[iy] * RRearlyPaedART;
		}
		sumB += SumGroupsM[ia][19] + SumGroupsF[ia][19];
	}

	if (CurrYear <= InterpolationStart){
		TargetStartingART = (StartingART_P / 12.0) - ((MaleChild.PosChildAtBirthNoPMTCT[1] * SixWeekSe[0] +
			MaleChild.PosChildAtBirthPMTCT[1] * SixWeekSe[1]) * EligInfants + MaleChild.ARTeligible[1] * SixWeekSe[2] +
			(FemChild.PosChildAtBirthNoPMTCT[1] * SixWeekSe[0] + FemChild.PosChildAtBirthPMTCT[1] * SixWeekSe[1]) *
			EligInfants + FemChild.ARTeligible[1] * SixWeekSe[2]) * PCRuptake * PaedARTuptakeEID;
		TargetStartingART = TargetStartingART - (ChildPosNoPMTCT * BirthSe[0] + ChildPosPMTCT * BirthSe[1]) *
			EligInfants * PCRuptakeB * PaedARTuptakeEID / 12.0;
		TargetStartingART = TargetStartingART - ((MaleChild.PosChildAtBirthNoPMTCT[5] + MaleChild.PosChildAtBirthPMTCT[5] + 
			MaleChild.PosChildAfterBirth[5]) * EligInfants + MaleChild.ARTeligible[5] +
			(FemChild.PosChildAtBirthNoPMTCT[5] + FemChild.PosChildAtBirthPMTCT[5] + FemChild.PosChildAfterBirth[5]) *
			EligInfants + FemChild.ARTeligible[5]) * PCRuptake6 * PaedARTuptakeEID;
		root = TargetStartingART / (sumA + sumB);
		if (root < 0.0){ root = 0.0; }
		else if (root < 1.0){ root = -log(1.0 - root); }
		else if (root >= 1.0){
			ARTerrorInd = 1;
			if (pow(root - 1.0, 2.0) > MaxARTerror){
				MaxARTerror = pow(root - 1.0, 2.0);
			}
		}
	}
	else{
		if (CurrYear >= UltimateYr){
			root = 1.0 / UltARTdelayC;
		}
		else{
			root = ARTinitiationStore + ((1.0 / UltARTdelayC) - ARTinitiationStore) *
				(CurrYear - InterpolationStart) * (UltimateYr - InterpolationStart);
		}
	}

	PaedARTinitiation = root;
	if (FixedUncertainty == 1 && CurrMonth == 6 && FixedARTinitiation == 0){
		ChildRoot.out[CurrSim - 1][CurrYear - StartYear] = root;
	}
	if (CurrYear == InterpolationStart){
		ARTinitiationStore = root;
	}
}

void UpdateFSW()
{
	int ia, is;
	double NewFSW, LeaveFSW, Temp, Temp2, MnthlyExit;
	double Retiring[81], BaseFSWentry[81], TempART[4];

	MnthlyExit = 1.0 - exp(-1/(12.0*DurFSW[CurrYear-StartYear]));
	for(ia=0; ia<81; ia++){
		// First calculate number of women retiring from sex work
		Temp = FH_SW.NegNoHCT_E[ia] + FH_SW.NegPastHCT_E[ia] + FH_SW.RegHCT_E[ia] +
			FH_SW.RegPrEP_E[ia] + FH_SW.RegVM_E[ia];
		for(is=0; is<5; is++){
			Temp += FH_SW.PosNoHCT_E[ia][is] * RelativeCSWexit[is];
			Temp += FH_SW.PosHCTpreHIV_E[ia][is] * RelativeCSWexit[is+5];
			Temp += FH_SW.PosDiagnosedPreART_E[ia][is] * RelativeCSWexit[is+10];
			Temp += FH_SW.OnARTpre500_E[ia][is] * RelativeCSWexit[is+15];
			Temp += FH_SW.OnART500_E[ia][is] * RelativeCSWexit[is+20];
			Temp += FH_SW.OnART350_E[ia][is] * RelativeCSWexit[is+25];
			Temp += FH_SW.OnART200_E[ia][is] * RelativeCSWexit[is+30];
		}
		for(is=0; is<4; is++){
			Temp += FH_SW.StoppedART_E[ia][is] * RelativeCSWexit[is+35];}
		Retiring[ia] = MnthlyExit * Temp;
		// Second calculate number eligible to enter sex work
		Temp2 = FH_ST.NegNoHCT_E[ia] + FH_ST.NegPastHCT_E[ia] + FH_ST.RegHCT_E[ia] +
			FH_ST.RegPrEP_E[ia] + FH_ST.RegVM_E[ia];
		for(is=0; is<5; is++){
			Temp2 += FH_ST.PosNoHCT_E[ia][is] * RelativeCSWentry[is];
			Temp2 += FH_ST.PosHCTpreHIV_E[ia][is] * RelativeCSWentry[is+5];
			Temp2 += FH_ST.PosDiagnosedPreART_E[ia][is] * RelativeCSWentry[is+10];
			Temp2 += FH_ST.OnARTpre500_E[ia][is] * RelativeCSWentry[is+15];
			Temp2 += FH_ST.OnART500_E[ia][is] * RelativeCSWentry[is+20];
			Temp2 += FH_ST.OnART350_E[ia][is] * RelativeCSWentry[is+25];
			Temp2 += FH_ST.OnART200_E[ia][is] * RelativeCSWentry[is+30];
		}
		for(is=0; is<4; is++){
			Temp2 += FH_ST.StoppedART_E[ia][is] * RelativeCSWentry[is+35];}
		// Third calculate rate of entry into sex work for HIV-negative women
		BaseFSWentry[ia] = TotalFSW * FSWageDbn[ia] + Retiring[ia] - FH_SW.Total_E[ia];
		if(BaseFSWentry[ia] < 0.0 || Temp2 <= 0.0){
			BaseFSWentry[ia] = 0.0;}
		else{
			BaseFSWentry[ia] = BaseFSWentry[ia]/Temp2;}
		if(BaseFSWentry[ia]>1.0){BaseFSWentry[ia] = 1.0;}
		// Fourth calculate entrants and exits
		// HIV-neg, never tested
		NewFSW = FH_ST.NegNoHCT[ia] * BaseFSWentry[ia];
		LeaveFSW = FH_SW.NegNoHCT[ia] * MnthlyExit;
		FH_ST.NegNoHCT[ia] += LeaveFSW - NewFSW;
		FH_SW.NegNoHCT[ia] += NewFSW - LeaveFSW;
		// HIV-neg, previously tested
		NewFSW = FH_ST.NegPastHCT[ia] * BaseFSWentry[ia];
		LeaveFSW = FH_SW.NegPastHCT[ia] * MnthlyExit;
		FH_ST.NegPastHCT[ia] += LeaveFSW - NewFSW;
		FH_SW.NegPastHCT[ia] += NewFSW - LeaveFSW;
		if(PrEPorVM==1){
			// Regular HCT
			NewFSW = FH_ST.RegHCT[ia] * BaseFSWentry[ia];
			LeaveFSW = FH_SW.RegHCT[ia] * MnthlyExit;
			FH_ST.RegHCT[ia] += LeaveFSW - NewFSW;
			FH_SW.RegHCT[ia] += NewFSW - LeaveFSW;
			// Regular PrEP
			NewFSW = FH_ST.RegPrEP[ia] * BaseFSWentry[ia];
			LeaveFSW = FH_SW.RegPrEP[ia] * MnthlyExit;
			FH_ST.RegPrEP[ia] += LeaveFSW - NewFSW;
			FH_SW.RegPrEP[ia] += NewFSW - LeaveFSW;
			// Regular VM
			NewFSW = FH_ST.RegVM[ia] * BaseFSWentry[ia];
			LeaveFSW = FH_SW.RegVM[ia] * MnthlyExit;
			FH_ST.RegVM[ia] += LeaveFSW - NewFSW;
			FH_SW.RegVM[ia] += NewFSW - LeaveFSW;
		}
		for(is=0; is<5; is++){
			// Positive, never tested
			NewFSW = FH_ST.PosNoHCT[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is];
			LeaveFSW = FH_SW.PosNoHCT[ia][is] * MnthlyExit * RelativeCSWexit[is];
			FH_ST.PosNoHCT[ia][is] += LeaveFSW - NewFSW;
			FH_SW.PosNoHCT[ia][is] += NewFSW - LeaveFSW;
			// Positive, last tested when negative
			NewFSW = FH_ST.PosHCTpreHIV[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is+5];
			LeaveFSW = FH_SW.PosHCTpreHIV[ia][is] * MnthlyExit  * RelativeCSWexit[is+5];
			FH_ST.PosHCTpreHIV[ia][is] += LeaveFSW - NewFSW;
			FH_SW.PosHCTpreHIV[ia][is] += NewFSW - LeaveFSW;
			// Diagnosed positive but not yet on ART
			NewFSW = FH_ST.PosDiagnosedPreART[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is+10];
			LeaveFSW = FH_SW.PosDiagnosedPreART[ia][is] * MnthlyExit  * RelativeCSWexit[is+10];
			FH_ST.PosDiagnosedPreART[ia][is] += LeaveFSW - NewFSW;
			FH_SW.PosDiagnosedPreART[ia][is] += NewFSW - LeaveFSW;
			/*if(CurrYear>=2015 && is>0 && is<=ImmARTstage){
				TempART[is-1] = NewFSW * ImmART_CSW;
				FH_SW.PosDiagnosedPreART[ia][is] = FH_SW.PosDiagnosedPreART[ia][is] - TempART[is-1];
			}*/
			// Started ART at CD4 500+
			NewFSW = FH_ST.OnARTpre500[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is+15];
			LeaveFSW = FH_SW.OnARTpre500[ia][is] * MnthlyExit  * RelativeCSWexit[is+15];
			FH_ST.OnARTpre500[ia][is] += LeaveFSW - NewFSW;
			FH_SW.OnARTpre500[ia][is] += NewFSW - LeaveFSW;
			// Started ART at CD4 350-499
			NewFSW = FH_ST.OnART500[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is+20];
			LeaveFSW = FH_SW.OnART500[ia][is] * MnthlyExit  * RelativeCSWexit[is+20];
			FH_ST.OnART500[ia][is] += LeaveFSW - NewFSW;
			FH_SW.OnART500[ia][is] += NewFSW - LeaveFSW;
			// Started ART at CD4 200-349
			NewFSW = FH_ST.OnART350[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is+25];
			LeaveFSW = FH_SW.OnART350[ia][is] * MnthlyExit  * RelativeCSWexit[is+25];
			FH_ST.OnART350[ia][is] += LeaveFSW - NewFSW;
			FH_SW.OnART350[ia][is] += NewFSW - LeaveFSW;
			// Started ART at CD4 <200
			NewFSW = FH_ST.OnART200[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is+30];
			LeaveFSW = FH_SW.OnART200[ia][is] * MnthlyExit  * RelativeCSWexit[is+30];
			FH_ST.OnART200[ia][is] += LeaveFSW - NewFSW;
			FH_SW.OnART200[ia][is] += NewFSW - LeaveFSW;
		}
		/*if(CurrYear>=2015){
			FH_SW.OnARTpre500[ia][0] += TempART[0];
			FH_SW.OnART500[ia][0] += TempART[1];
			FH_SW.OnART350[ia][0] += TempART[2];
			FH_SW.OnART200[ia][0] += TempART[3];
		}*/
		// Stopped ART
		for(is=0; is<4; is++){
			NewFSW = FH_ST.StoppedART[ia][is] * BaseFSWentry[ia] * RelativeCSWentry[is+35];
			LeaveFSW = FH_SW.StoppedART[ia][is] * MnthlyExit  * RelativeCSWexit[is+35];
			FH_ST.StoppedART[ia][is] += LeaveFSW - NewFSW;
			FH_SW.StoppedART[ia][is] += NewFSW - LeaveFSW;
		}
	}
}

void UpdateMonthlyCum()
{
	int ia, ii, ij, is, ig, im;
	double DiagnosisRate[5], TempPaed, TempPaed2, TempPaed3, TempNeg[2], TempPos[2], Temp1stPos[2], FalseNeg[2];
	double Temp1, Temp2, Temp3, Temp4;

	// ChildPIP calibration outputs
	if (FixedUncertainty == 1 || CalibChildPIP == 1){
		for (ia = 12; ia < 60; ia++){
			AIDSdeathsDiagP[0] += MaleChild.AIDSdeaths[ia] - MaleChild.AIDSdeathsUndiagnosed[ia] +
				FemChild.AIDSdeaths[ia] - FemChild.AIDSdeathsUndiagnosed[ia];
			AIDSdeathsART_P[0] += MaleChild.AIDSdeaths[ia] - MaleChild.AIDSdeathsUntreated[ia] +
				FemChild.AIDSdeaths[ia] - FemChild.AIDSdeathsUntreated[ia];
		}
		for (ia = 60; ia < 120; ia++){
			AIDSdeathsDiagP[1] += MaleChild.AIDSdeaths[ia] - MaleChild.AIDSdeathsUndiagnosed[ia] +
				FemChild.AIDSdeaths[ia] - FemChild.AIDSdeathsUndiagnosed[ia];
			AIDSdeathsART_P[1] += MaleChild.AIDSdeaths[ia] - MaleChild.AIDSdeathsUntreated[ia] +
				FemChild.AIDSdeaths[ia] - FemChild.AIDSdeathsUntreated[ia];
		}
	}

	// Flow variables that are not age-specific
	if (FixedUncertainty == 1){
		for (ia = 0; ia < 132; ia++){
			AIDSdeathsOnART += MaleChild.AIDSdeaths[ia] - MaleChild.AIDSdeathsUntreated[ia] +
				FemChild.AIDSdeaths[ia] - FemChild.AIDSdeathsUntreated[ia];
		}
		for (ia = 0; ia < 81; ia++){
			AIDSdeathsOnART += MHU_virgin.AIDSdeathsTreated[ia] + MHC_virgin.AIDSdeathsTreated[ia] +
				MHU_ST.AIDSdeathsTreated[ia] + MHC_ST.AIDSdeathsTreated[ia] + MHU_STM.AIDSdeathsTreated[ia] + 
				MHC_STM.AIDSdeathsTreated[ia] + MHU_ID.AIDSdeathsTreated[ia] + MHC_ID.AIDSdeathsTreated[ia] + 
				MHU_LTH.AIDSdeathsTreated[ia] + MHC_LTH.AIDSdeathsTreated[ia] + MHU_LTL.AIDSdeathsTreated[ia] +
				MHC_LTL.AIDSdeathsTreated[ia] + MHU_LTM.AIDSdeathsTreated[ia] + MHC_LTM.AIDSdeathsTreated[ia] +
				MLU_virgin.AIDSdeathsTreated[ia] + MLC_virgin.AIDSdeathsTreated[ia] + MLU_ST.AIDSdeathsTreated[ia] +
				MLC_ST.AIDSdeathsTreated[ia] + MLU_STM.AIDSdeathsTreated[ia] + MLC_STM.AIDSdeathsTreated[ia] +
				MLU_ID.AIDSdeathsTreated[ia] + MLC_ID.AIDSdeathsTreated[ia] + MLU_LTH.AIDSdeathsTreated[ia] +
				MLC_LTH.AIDSdeathsTreated[ia] + MLU_LTL.AIDSdeathsTreated[ia] + MLC_LTL.AIDSdeathsTreated[ia] +
				MLU_LTM.AIDSdeathsTreated[ia] + MLC_LTM.AIDSdeathsTreated[ia];
			AIDSdeathsOnART += FH_virgin.AIDSdeathsTreated[ia] + FH_ST.AIDSdeathsTreated[ia] +
				FH_SW.AIDSdeathsTreated[ia] + FH_ID.AIDSdeathsTreated[ia] + FH_LTH.AIDSdeathsTreated[ia] + 
				FH_LTL.AIDSdeathsTreated[ia] + FL_virgin.AIDSdeathsTreated[ia] + FL_ST.AIDSdeathsTreated[ia] +
				FL_ID.AIDSdeathsTreated[ia] + FL_LTH.AIDSdeathsTreated[ia] + FL_LTL.AIDSdeathsTreated[ia];
		}
		NewPerinatal += MaleChild.PosChildAtBirthNoPMTCT_E[0] +
			MaleChild.PosChildAtBirthPMTCT_E[0] + MaleChild.DiagChildAtBirthNoPMTCT_E[0] + 
			MaleChild.DiagChildAtBirthPMTCT_E[0] + FemChild.PosChildAtBirthNoPMTCT_E[0] +
			FemChild.PosChildAtBirthPMTCT_E[0] + FemChild.DiagChildAtBirthNoPMTCT_E[0] +
			FemChild.DiagChildAtBirthPMTCT_E[0] + MaleChild.OnARTearly_E[0] +
			FemChild.OnARTearly_E[0];
		for (ia = 0; ia < 36; ia++){
			NewPostnatal += MaleChild.NewHIVpostnatal[ia] + FemChild.NewHIVpostnatal[ia];
			NewHIVlactating += MaleChild.NewMatHIV[ia] + FemChild.NewMatHIV[ia];
		}
		for (ia = 0; ia < 18; ia++){
			NewPostnatal18 += MaleChild.NewPostnatalDiag[ia] + FemChild.NewPostnatalDiag[ia]; }
		BirthsNegMothers += ChildNegMotherNeg / 12.0;
		BirthsPosMothers += (ChildPosNoPMTCT + ChildPosPMTCT + ChildNegMotherPosKnown +
			ChildNegMotherPosUnknown) / 12.0;
		BirthsARTmothers += (ARTmothers + TestedPosOnART[0] + TestedPosOnART[1] + RecentPosDetART) / 12.0;
		TotBirthsARTconcep.out[CurrSim - 1][CurrYear - StartYear] += ARTmothers / 12.0;
		//for (ia = 0; ia < 36; ia++){ BirthsDiagMothers += BirthsByHIVstage[ia][7] / 12.0; }
	}
	for (is = 0; is < 4; is++){
		AdultsNewARTbyCD4[is][0] += MHU_virgin.NewARTbyCD4[is] + MHC_virgin.NewARTbyCD4[is] +
			MHU_ST.NewARTbyCD4[is] + MHC_ST.NewARTbyCD4[is] + MHU_STM.NewARTbyCD4[is] + 
			MHC_STM.NewARTbyCD4[is] + MHU_ID.NewARTbyCD4[is] + MHC_ID.NewARTbyCD4[is] + 
			MHU_LTH.NewARTbyCD4[is] + MHC_LTH.NewARTbyCD4[is] + MHU_LTL.NewARTbyCD4[is] +
			MHC_LTL.NewARTbyCD4[is] + MHU_LTM.NewARTbyCD4[is] + MHC_LTM.NewARTbyCD4[is] +
			MLU_virgin.NewARTbyCD4[is] + MLC_virgin.NewARTbyCD4[is] +
			MLU_ST.NewARTbyCD4[is] + MLC_ST.NewARTbyCD4[is] + MLU_STM.NewARTbyCD4[is] + 
			MLC_STM.NewARTbyCD4[is] + MLU_ID.NewARTbyCD4[is] + MLC_ID.NewARTbyCD4[is] + 
			MLU_LTH.NewARTbyCD4[is] + MLC_LTH.NewARTbyCD4[is] + MLU_LTL.NewARTbyCD4[is] +
			MLC_LTL.NewARTbyCD4[is] + MLU_LTM.NewARTbyCD4[is] + MLC_LTM.NewARTbyCD4[is];
		AdultsNewARTbyCD4[is][1] += FH_virgin.NewARTbyCD4[is] + FH_ST.NewARTbyCD4[is] +
			FH_SW.NewARTbyCD4[is] + FH_ID.NewARTbyCD4[is] + FH_LTH.NewARTbyCD4[is] + 
			FH_LTL.NewARTbyCD4[is] + FL_virgin.NewARTbyCD4[is] + FL_ST.NewARTbyCD4[is] +
			FL_ID.NewARTbyCD4[is] + FL_LTH.NewARTbyCD4[is] + FL_LTL.NewARTbyCD4[is];
	}
	for (im = 0; im < 132; im++){
		ChildNewARTlate += MaleChild.StartingARTlate[im] + FemChild.StartingARTlate[im];
	}
	if (FixedUncertainty == 1){
		for (is = 0; is < 4; is++){
			for (ii = 0; ii < 5; ii++){
				for (ia = 0; ia < 5; ia++){
					if (is < 4){ 
						ChildReinitARTearly += SumGroupsM[ia][20 + is * 5 + ii] * RestartRateByIntDur[ii][0][ia] +
							SumGroupsF[ia][20 + is * 5 + ii] * RestartRateByIntDur[ii][1][ia];
					}
					else{ 
						ChildReinitARTlate += SumGroupsM[ia][20 + is * 5 + ii] * RestartRateByIntDur[ii][0][ia] +
							SumGroupsF[ia][20 + is * 5 + ii] * RestartRateByIntDur[ii][1][ia];
					}
				}
				for (ia = 5; ia < 81; ia++){
					AdultsReinitARTbyCD4[is][0] += SumGroupsM[ia][20 + is * 5 + ii] * RestartRateByIntDur[ii][0][ia];
					AdultsReinitARTbyCD4[is][1] += SumGroupsF[ia][20 + is * 5 + ii] * RestartRateByIntDur[ii][1][ia];
				}
			}
		}
	}

	TempNeg15_19 = 0.0; TempPos15_19 = 0.0; //LJ
	if (FixedUncertainty == 1 || CalibHCTprev == 1 || CalibHCTprevP == 1 || CalibHCTtotP == 1 || CalibHCTageSex == 1){
		for (ig = 0; ig < 2; ig++){
			TempNeg[ig] = 0.0;
			TempPos[ig] = 0.0;
			FalseNeg[ig] = 0.0;
			Temp1stPos[ig] = 0.0;
		}
		// Calculate NewlyTested at ages <10
		for (ia = 18; ia < 132; ia++){
			TempPaed = MaleChild.DiagChildAtBirthNoPMTCT[ia] + MaleChild.DiagChildAtBirthPMTCT[ia] +
				MaleChild.DiagChildAfterBirth[ia] + MaleChild.DiagARTeligible[ia] +
				FemChild.DiagChildAtBirthNoPMTCT[ia] + FemChild.DiagChildAtBirthPMTCT[ia] +
				FemChild.DiagChildAfterBirth[ia] + FemChild.DiagARTeligible[ia];
			TempPaed2 = MaleChild.PosChildAtBirthNoPMTCT[ia] + MaleChild.PosChildAtBirthPMTCT[ia] +
				MaleChild.PosChildAfterBirth[ia] + MaleChild.ARTeligible[ia] +
				FemChild.PosChildAtBirthNoPMTCT[ia] + FemChild.PosChildAtBirthPMTCT[ia] +
				FemChild.PosChildAfterBirth[ia] + FemChild.ARTeligible[ia];
			TempPaed3 = MaleChild.OnARTearly[ia] + MaleChild.OnARTlate1st3m[ia] +
				MaleChild.OnARTlateAfter3m[ia] + MaleChild.StoppedART[ia] +
				FemChild.OnARTearly[ia] + FemChild.OnARTlate1st3m[ia] +
				FemChild.OnARTlateAfter3m[ia] + FemChild.StoppedART[ia];
			NewlyTestedPos[2] += TempPaed2 * MnthlyTestingPaed[ia][0];
			if (ia > 18){
				NewlyTestedPos[2] += TempPaed * MnthlyTestingPaed[ia][0] * RetestPosP;
				NewlyTestedPos[2] += TempPaed3 * MnthlyTestingPaed[ia][0] * RetestPosP *
					RetestART / RetestPos;
				NewlyTestedPos[2] += (MaleChild.ARTeligible[ia] + FemChild.ARTeligible[ia])*
					(MnthlyTestingPaed[ia][1] - MnthlyTestingPaed[ia][0]);
			}
			if (ia == 18){
				NewlyTestedNeg[2] += (MaleChild.Total[ia] + FemChild.Total[ia] - TempPaed - TempPaed2 -
					TempPaed3) * CurrTesting18mo[0];
			}
			else{
				NewlyTestedNeg[2] += (MaleChild.Total[ia] + FemChild.Total[ia] - TempPaed - TempPaed2 -
					TempPaed3) * MnthlyTestingPaed[ia][0];
			}
			if (ia == 18){
				NewlyTestedPaed[0][0] += (MaleChild.Total[ia] + FemChild.Total[ia] - TempPaed - TempPaed2 -
					TempPaed3) * CurrTesting18mo[0];
				NewlyTestedPaed[0][1] += TempPaed2 * MnthlyTestingPaed[ia][0];
			}
			else if (ia < 60){
				NewlyTestedPaed[1][0] += (MaleChild.Total[ia] + FemChild.Total[ia] - TempPaed - TempPaed2 -
					TempPaed3) * MnthlyTestingPaed[ia][0];
				NewlyTestedPaed[1][1] += TempPaed2 * MnthlyTestingPaed[ia][0];
				NewlyTestedPaed[1][1] += TempPaed * MnthlyTestingPaed[ia][0] * RetestPosP;
				NewlyTestedPaed[1][1] += TempPaed3 * MnthlyTestingPaed[ia][0] * RetestART * (RetestPosP/RetestPos);
				NewlyTestedPaed[1][1] += (MaleChild.ARTeligible[ia] + FemChild.ARTeligible[ia])*
					(MnthlyTestingPaed[ia][1] - MnthlyTestingPaed[ia][0]);
			}
			else{
				NewlyTestedPaed[2][0] += (MaleChild.Total[ia] + FemChild.Total[ia] - TempPaed - TempPaed2 -
					TempPaed3) * MnthlyTestingPaed[ia][0];
				NewlyTestedPaed[2][1] += TempPaed2 * MnthlyTestingPaed[ia][0];
				NewlyTestedPaed[2][1] += TempPaed * MnthlyTestingPaed[ia][0] * RetestPosP;
				NewlyTestedPaed[2][1] += TempPaed3 * MnthlyTestingPaed[ia][0] * RetestART * (RetestPosP/RetestPos);
				NewlyTestedPaed[2][1] += (MaleChild.ARTeligible[ia] + FemChild.ARTeligible[ia])*
					(MnthlyTestingPaed[ia][1] - MnthlyTestingPaed[ia][0]);
			}
		}
		// Calculate NewlyTested at ages 10+ (excluding self-testing unless confirmed positive)
		for (ia = 0; ia < 81; ia++){
			TempNeg[0] += SumGroupsM[ia][0] * TestingRateSE[ia][0][0] + SumGroupsM[ia][1] *
				TestingRateSE[ia][1][0];
			TempNeg[1] += SumGroupsF[ia][0] * TestingRateSE[ia][0][1] + SumGroupsF[ia][1] *
				TestingRateSE[ia][1][1];

			if (ia >= 5 && ia <= 9) {//LJ	
				TempNeg15_19 += SumGroupsM[ia][0] * TestingRateSE[ia][0][0] + SumGroupsM[ia][1] *
					TestingRateSE[ia][1][0] +
					SumGroupsF[ia][0] * TestingRateSE[ia][0][1] + SumGroupsF[ia][1] *
					TestingRateSE[ia][1][1];
			}	

			if (PrEPorVM == 1){
				TempNeg[0] += (SumGroupsM[ia][2] + SumGroupsM[ia][3]) * FreqHCTinPrEP[0] / 12.0;
				TempNeg[1] += (SumGroupsF[ia][2] + SumGroupsF[ia][3]) *
					FreqHCTinPrEP[1] / 12.0 + SumGroupsF[ia][4] * FreqHCTinVM / 12.0;

				if (ia >= 5 && ia <= 9) {//LJ	
					TempNeg15_19 += (SumGroupsM[ia][2] + SumGroupsM[ia][3]) * FreqHCTinPrEP[0] / 12.0 +
						(SumGroupsF[ia][2] + SumGroupsF[ia][3]) * FreqHCTinPrEP[1] / 12.0 + SumGroupsF[ia][4] * FreqHCTinVM / 12.0;
				}				
				NewlyTestedNeg_PrEP[0] += (SumGroupsM[ia][2] + SumGroupsM[ia][3]) * FreqHCTinPrEP[0] / 12.0; //LJ PrEP HCT
				NewlyTestedNeg_PrEP[1] += (SumGroupsF[ia][2] + SumGroupsF[ia][3]) *	FreqHCTinPrEP[1] / 12.0 + SumGroupsF[ia][4] * FreqHCTinVM / 12.0; //LJ PrEP HCT
			}
			for (is = 2; is < 12; is++){
				TempPos[0] += SumGroupsM[ia][is + 3] * TestingRateSE[ia][is][0];
				TempPos[1] += SumGroupsF[ia][is + 3] * TestingRateSE[ia][is][1];
				if (ia >= 5 && ia <= 9) {//LJ	
					TempPos15_19 += SumGroupsM[ia][is + 3] * TestingRateSE[ia][is][0] +	SumGroupsF[ia][is + 3] * TestingRateSE[ia][is][1];					
				}
			}
			for (is = 2; is < 12; is++){
				Temp1stPos[0] += SumGroupsM[ia][is + 3] * TestingRateSE[ia][is][0];
				Temp1stPos[1] += SumGroupsF[ia][is + 3] * TestingRateSE[ia][is][1];
			}
			for (is = 15; is < 20; is++){
				TempPos[0] += SumGroupsM[ia][is] * (TestingRateM[ia] * RetestPos +
					SelfTestingRate[ia][is - 8][0] * RetestPosST[0] * SelfTestConfirm);
				TempPos[1] += SumGroupsF[ia][is] * (TestingRateSE[ia][0][1] * RetestPos +
					SelfTestingRate[ia][is - 8][1] * RetestPosST[0] * SelfTestConfirm);

				if (ia >= 5 && ia <= 9) {//LJ	
					TempPos15_19 += SumGroupsM[ia][is] * (TestingRateM[ia] * RetestPos +
						SelfTestingRate[ia][is - 8][0] * RetestPosST[0] * SelfTestConfirm)
						+ SumGroupsF[ia][is] * (TestingRateSE[ia][0][1] * RetestPos +
							SelfTestingRate[ia][is - 8][1] * RetestPosST[0] * SelfTestConfirm);
				}
			}
			for (is = 20; is < 44; is++){
				TempPos[0] += SumGroupsM[ia][is] * (TestingRateM[ia] * RetestART +
					SelfTestingRate[ia][8][0] * RetestPosST[1] * SelfTestConfirm);
				TempPos[1] += SumGroupsF[ia][is] * (TestingRateSE[ia][0][1] * RetestART +
					SelfTestingRate[ia][8][1] * RetestPosST[1] * SelfTestConfirm);

				if (ia >= 5 && ia <= 9) {//LJ	
					TempPos15_19 += SumGroupsM[ia][is] * (TestingRateM[ia] * RetestART +
						SelfTestingRate[ia][8][0] * RetestPosST[1] * SelfTestConfirm)
						+ SumGroupsF[ia][is] * (TestingRateSE[ia][0][1] * RetestART +
							SelfTestingRate[ia][8][1] * RetestPosST[1] * SelfTestConfirm);				
				}
			}
			FalseNeg[0] += SumGroupsM[ia][5] * TestingRateSE[ia][2][0] +
				SumGroupsM[ia][10] * TestingRateSE[ia][7][0];
			FalseNeg[1] += SumGroupsF[ia][5] * TestingRateSE[ia][2][1] +
				SumGroupsF[ia][10] * TestingRateSE[ia][7][1];
			if (ia < 20){
				// Adjustment for HIV-negative virgins
				TempNeg[0] = TempNeg[0] - SumGroupsVM[ia][0] * (TestingRateSE[ia][0][0] - TestingRateNegV[ia][0]) -
					SumGroupsVM[ia][1] * (TestingRateSE[ia][1][0] - TestingRateNegV[ia][0]);
				TempNeg[1] = TempNeg[1] - SumGroupsVF[ia][0] * (TestingRateSE[ia][0][1] - TestingRateNegV[ia][1]) -
					SumGroupsVF[ia][1] * (TestingRateSE[ia][1][1] - TestingRateNegV[ia][1]);
				
				if (ia >= 5 && ia <= 9) {//LJ	
					TempNeg15_19 = TempNeg15_19 - SumGroupsVM[ia][0] * (TestingRateSE[ia][0][0] - TestingRateNegV[ia][0]) -
						SumGroupsVM[ia][1] * (TestingRateSE[ia][1][0] - TestingRateNegV[ia][0]);
					TempNeg15_19 = TempNeg15_19 - SumGroupsVF[ia][0] * (TestingRateSE[ia][0][1] - TestingRateNegV[ia][1]) -
						SumGroupsVF[ia][1] * (TestingRateSE[ia][1][1] - TestingRateNegV[ia][1]);
				}

				// Subtract tests in HIV-pos virgins
				for (is = 2; is < 12; is++){
					TempPos[0] = TempPos[0] - SumGroupsVM[ia][is + 3] * TestingRateSE[ia][is][0];
					TempPos[1] = TempPos[1] - SumGroupsVF[ia][is + 3] * TestingRateSE[ia][is][1];
					if (ia >= 5 && ia <= 9) {//LJ	
						TempPos15_19 = TempPos15_19 - 
							SumGroupsVM[ia][is + 3] * TestingRateSE[ia][is][0] - 
							SumGroupsVF[ia][is + 3] * TestingRateSE[ia][is][1];					
					}
				}
				for (is = 2; is < 12; is++){
					Temp1stPos[0] = Temp1stPos[0] - SumGroupsVM[ia][is + 3] * TestingRateSE[ia][is][0];
					Temp1stPos[1] = Temp1stPos[1] - SumGroupsVF[ia][is + 3] * TestingRateSE[ia][is][1];
				}
				for (is = 15; is < 20; is++){
					TempPos[0] = TempPos[0] - SumGroupsVM[ia][is] * (TestingRateM[ia] * RetestPos +
						SelfTestingRate[ia][is - 8][0] * RetestPosST[0] * SelfTestConfirm);
					TempPos[1] = TempPos[1] - SumGroupsVF[ia][is] * (TestingRateSE[ia][0][1] * RetestPos +
						SelfTestingRate[ia][is - 8][1] * RetestPosST[0] * SelfTestConfirm);
					if (ia >= 5 && ia <= 9) {//LJ	
						TempPos15_19 = TempPos15_19 -
							SumGroupsVM[ia][is] * (TestingRateM[ia] * RetestPos + SelfTestingRate[ia][is - 8][0] * RetestPosST[0] * SelfTestConfirm) -
							SumGroupsVF[ia][is] * (TestingRateSE[ia][0][1] * RetestPos + SelfTestingRate[ia][is - 8][1] * RetestPosST[0] * SelfTestConfirm);
					}
				}
				for (is = 20; is < 44; is++){
					TempPos[0] = TempPos[0] - SumGroupsVM[ia][is] * (TestingRateM[ia] * RetestART +
						SelfTestingRate[ia][8][0] * RetestPosST[1] * SelfTestConfirm);
					TempPos[1] = TempPos[1] - SumGroupsVF[ia][is] * (TestingRateSE[ia][0][1] * RetestART +
						SelfTestingRate[ia][8][1] * RetestPosST[1] * SelfTestConfirm);
					if (ia >= 5 && ia <= 9) {//LJ	
						TempPos15_19 = TempPos15_19 -
							SumGroupsVM[ia][is] * (TestingRateM[ia] * RetestART +	SelfTestingRate[ia][8][0] * RetestPosST[1] * SelfTestConfirm) -
							SumGroupsVF[ia][is] * (TestingRateSE[ia][0][1] * RetestART + SelfTestingRate[ia][8][1] * RetestPosST[1] * SelfTestConfirm);
					}
				}
				// Add back tests in HIV-pos virgins
				for (is = 0; is < 5; is++){
					TempPos[0] += (SumGroupsVM[ia][is + 5] + SumGroupsVM[ia][is + 10]) *
						TestingRateV[ia][is][0];
					TempPos[1] += (SumGroupsVF[ia][is + 5] + SumGroupsVF[ia][is + 10]) *
						TestingRateV[ia][is][1];
					if (ia >= 5 && ia <= 9) {//LJ	
						TempPos15_19 += (SumGroupsVM[ia][is + 5] + SumGroupsVM[ia][is + 10]) *	TestingRateV[ia][is][0] +
							(SumGroupsVF[ia][is + 5] + SumGroupsVF[ia][is + 10]) *	TestingRateV[ia][is][1];
					}
				}
				for (is = 0; is < 5; is++){
					Temp1stPos[0] += (SumGroupsVM[ia][is + 5] + SumGroupsVM[ia][is + 10]) *
						TestingRateV[ia][is][0];
					Temp1stPos[1] += (SumGroupsVF[ia][is + 5] + SumGroupsVF[ia][is + 10]) *
						TestingRateV[ia][is][1];
				}
				for (is = 15; is < 20; is++){
					if (ia < 5){
						TempPos[0] += SumGroupsVM[ia][is] * TestingRateNegV[ia][0] * RetestPosP;
						TempPos[1] += SumGroupsVF[ia][is] * TestingRateNegV[ia][1] * RetestPosP;
					}
					else{
						TempPos[0] += SumGroupsVM[ia][is] * TestingRateNegV[ia][0] * RetestPos;
						TempPos[1] += SumGroupsVF[ia][is] * TestingRateNegV[ia][1] * RetestPos;
						if (ia >= 5 && ia <= 9) {//LJ	
							TempPos15_19 += SumGroupsVM[ia][is] * TestingRateNegV[ia][0] * RetestPos +	SumGroupsVF[ia][is] * TestingRateNegV[ia][1] * RetestPos;
						}
					}
				}
				for (is = 20; is < 44; is++){
					TempPos[0] += SumGroupsVM[ia][is] * TestingRateNegV[ia][0] * RetestPosP * 
						RetestART / RetestPos;
					TempPos[1] += SumGroupsVF[ia][is] * TestingRateNegV[ia][1] * RetestPosP *
						RetestART / RetestPos;
					if (ia >= 5 && ia <= 9) {//LJ	
						TempPos15_19 += SumGroupsVM[ia][is] * TestingRateNegV[ia][0] * RetestPosP *	RetestART / RetestPos +
							SumGroupsVF[ia][is] * TestingRateNegV[ia][1] * RetestPosP *	RetestART / RetestPos;

					}
				}
			}
			if (ia == 4){
				NewlyTestedPos[2] += TempPos[0] + TempPos[1] - FalseNeg[0] - FalseNeg[1];
				NewlyTestedNeg[2] += TempNeg[0] + TempNeg[1] + FalseNeg[0] + FalseNeg[1];
				NewlyTestedPaed[2][1] += TempPos[0] + TempPos[1] - FalseNeg[0] - FalseNeg[1];
				NewlyTestedPaed[2][0] += TempNeg[0] + TempNeg[1] + FalseNeg[0] + FalseNeg[1];
				NewlyTestedFalseNeg[2] += FalseNeg[0] + FalseNeg[1];
				for (ig = 0; ig < 2; ig++){
					TempPos[ig] = 0.0;
					TempNeg[ig] = 0.0;
					FalseNeg[ig] = 0.0;
					Temp1stPos[ig] = 0.0;
				}
			}
			if (ia == 14){
				Temp1 = TempNeg[0] + TempPos[0];
				Temp2 = TempNeg[1] + TempPos[1];
				NewlyTestedAdult[0][0] += Temp1;
				NewlyTestedAdult[0][1] += Temp2;
				Temp3 = TempPos[0];
				Temp4 = TempPos[1];
				PosTestedAdult[0][0] += Temp3;
				PosTestedAdult[0][1] += Temp4;
			}
			if (ia == 39){
				NewlyTestedAdult[1][0] += TempNeg[0] + TempPos[0] - Temp1;
				NewlyTestedAdult[1][1] += TempNeg[1] + TempPos[1] - Temp2;
				Temp1 = TempNeg[0] + TempPos[0];
				Temp2 = TempNeg[1] + TempPos[1];
				PosTestedAdult[1][0] += TempPos[0] - Temp3;
				PosTestedAdult[1][1] += TempPos[1] - Temp4;
				Temp3 = TempPos[0];
				Temp4 = TempPos[1];
			}
			if (ia == 80){
				NewlyTestedNeg15_19 += TempNeg15_19; //LJ
				NewlyTestedPos15_19 += TempPos15_19; //LJ

				for (ig = 0; ig < 2; ig++){
					NewlyTestedPos[ig] += TempPos[ig] - FalseNeg[ig];
					NewlyTestedNeg[ig] += TempNeg[ig] + FalseNeg[ig];
					NewlyTestedFalseNeg[ig] += FalseNeg[ig];
					NewlyTested1stPos[ig] += Temp1stPos[ig] - FalseNeg[ig];
				}
				NewlyTestedAdult[2][0] += TempNeg[0] + TempPos[0] - Temp1;
				NewlyTestedAdult[2][1] += TempNeg[1] + TempPos[1] - Temp2;
				PosTestedAdult[2][0] += TempPos[0] - Temp3;
				PosTestedAdult[2][1] += TempPos[1] - Temp4;
			}
		}
		// Calculate ANCtestsByAge
		for (ia = 5; ia < 15; ia++){
			ANCtestsByAge[0][0] += (SumGroupsF[ia][0] + SumGroupsF[ia][1]) * HIVnegSEfert[ia - 4] * VCTuptake/12.0;
			Temp1 = 0.0;
			for (is = 0; is < 10; is++){ Temp1 += SumGroupsF[ia][5 + is] * RelativeFert[5 + is][ia - 4]; }
			for (is = 10; is < 15; is++){ Temp1 += SumGroupsF[ia][5 + is] * RelativeFert[5 + is][ia - 4] * RetestPos; }
			for (is = 15; is < 35; is++){ Temp1 += SumGroupsF[ia][5 + is] * RelativeFert[5 + is][ia - 4] * RetestART; }
			ANCtestsByAge[0][1] += Temp1 * HIVnegSEfert[ia - 4] * VCTuptake / 12.0;
		}
		for (ia = 15; ia < 40; ia++){
			ANCtestsByAge[1][0] += (SumGroupsF[ia][0] + SumGroupsF[ia][1]) * HIVnegSEfert[ia - 4] * VCTuptake / 12.0;
			Temp1 = 0.0;
			for (is = 0; is < 10; is++){ Temp1 += SumGroupsF[ia][5 + is] * RelativeFert[5 + is][ia - 4]; }
			for (is = 10; is < 15; is++){ Temp1 += SumGroupsF[ia][5 + is] * RelativeFert[5 + is][ia - 4] * RetestPos; }
			for (is = 15; is < 35; is++){ Temp1 += SumGroupsF[ia][5 + is] * RelativeFert[5 + is][ia - 4] * RetestART; }
			ANCtestsByAge[1][1] += Temp1 * HIVnegSEfert[ia - 4] * VCTuptake / 12.0;
		}
		// Calculate self-testing outputs
		if (FixedUncertainty == 1){ UpdateMonthlySTesting(); }
		// Calculate NewElig350
		for (ia = 5; ia < 81; ia++){
			NewElig350[0] += (SumGroupsM[ia][7] + SumGroupsM[ia][12] + SumGroupsM[ia][17]) *
				MnthlyCD4trans[ia][2][0];
			NewElig350[1] += (SumGroupsF[ia][7] + SumGroupsF[ia][12] + SumGroupsF[ia][17]) *
				MnthlyCD4trans[ia][2][1];
		}
		// Calculate NewElig500
		for (ia = 5; ia < 81; ia++){
			NewElig500[0] += (SumGroupsM[ia][6] + SumGroupsM[ia][11] + SumGroupsM[ia][16]) *
				MnthlyCD4trans[ia][1][0];
			NewElig500[1] += (SumGroupsF[ia][6] + SumGroupsF[ia][11] + SumGroupsF[ia][16]) *
				MnthlyCD4trans[ia][1][1];
		}
	}

	// Age-specific flows
	for (ia = 0; ia < 81; ia++){
		NewHIVbyAgeSex[ia][0] += MHU_ST.NewHIV[ia] + MHC_ST.NewHIV[ia] + MHU_STM.NewHIV[ia] + 
			MHC_STM.NewHIV[ia] + MHU_ID.NewHIV[ia] + MHC_ID.NewHIV[ia] + MHU_LTH.NewHIV[ia] + 
			MHC_LTH.NewHIV[ia] + MHU_LTL.NewHIV[ia] + MHC_LTL.NewHIV[ia] + MHU_LTM.NewHIV[ia] +
			MHC_LTM.NewHIV[ia] + MLU_ST.NewHIV[ia] + MLC_ST.NewHIV[ia] + MLU_ID.NewHIV[ia] +	
			MLC_ID.NewHIV[ia] + MLU_STM.NewHIV[ia] + MLC_STM.NewHIV[ia] + MLU_LTH.NewHIV[ia] +
			MLC_LTH.NewHIV[ia] + MLU_LTL.NewHIV[ia] + MLC_LTL.NewHIV[ia] + MLU_LTM.NewHIV[ia] + 
			MLC_LTM.NewHIV[ia];
		NewHIVbyAgeSex[ia][1] += FH_ST.NewHIV[ia] + FH_SW.NewHIV[ia] + FH_ID.NewHIV[ia] + 
			FH_LTH.NewHIV[ia] + FH_LTL.NewHIV[ia] + FL_ST.NewHIV[ia] + FL_ID.NewHIV[ia] +
			FL_LTH.NewHIV[ia] + FL_LTL.NewHIV[ia];
	}
	Temp1 = 0.0;
	Temp2 = 0.0;
	for (ia = 0; ia<35; ia++){
		Temp1 += NewHIVbyAgeSex[ia + 5][1] * HIVnegSEfert[ia + 1] * 12.0 / (CurrMonth + 1.0);
		Temp2 += TotalSexuallyExp_S[ia + 15][1] * HIVnegSEfert[ia + 1] *
			(1.0 - TotalPositive_S[ia + 15][1] / TotalPop_S[ia + 15][1]);
	}
	MatIncidenceAN = Temp1 / Temp2;
	if (FixedUncertainty == 1 && CurrMonth == 5){
		ANCincidence.out[CurrSim - 1][CurrYear - StartYear] = MatIncidenceAN;
		Temp3 = 0.0;
		for (ia = 0; ia<35; ia++){
			Temp3 += NewHIVbyAgeSex[ia + 5][1] * HIVnegSEfert[ia + 1] * ((1.0 - exp(-HCTtoART_SE[ia + 5][6][1] * 12.0)) / 
				(HCTtoART_SE[ia + 5][6][1] * 12.0) - exp(-HCTtoART_SE[ia + 5][6][1] * 12.0)) * 12.0 / (CurrMonth + 1.0);
		}
		ANCincidenceAdj.out[CurrSim - 1][CurrYear - StartYear] = (Temp1 - Temp3) / Temp2;
	}
	for (ia = 0; ia < 76; ia++){
		AIDSdeathsMarriedM[ia][0][0] += MHU_LTH.AIDSdeathsTreated[ia + 5] + MHC_LTH.AIDSdeathsTreated[ia + 5] +
			MHU_LTH.AIDSdeathsUntreated[ia + 5] + MHC_LTH.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedM[ia][0][1] += MHU_LTL.AIDSdeathsTreated[ia + 5] + MHC_LTL.AIDSdeathsTreated[ia + 5] +
			MHU_LTL.AIDSdeathsUntreated[ia + 5] + MHC_LTL.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedM[ia][1][0] += MLU_LTH.AIDSdeathsTreated[ia + 5] + MLC_LTH.AIDSdeathsTreated[ia + 5] +
			MLU_LTH.AIDSdeathsUntreated[ia + 5] + MLC_LTH.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedM[ia][1][1] += MLU_LTL.AIDSdeathsTreated[ia + 5] + MLC_LTL.AIDSdeathsTreated[ia + 5] +
			MLU_LTL.AIDSdeathsUntreated[ia + 5] + MLC_LTL.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedMSM[ia] += MHU_LTM.AIDSdeathsTreated[ia + 5] + MHC_LTM.AIDSdeathsTreated[ia + 5] +
			MHU_LTM.AIDSdeathsUntreated[ia + 5] + MHC_LTM.AIDSdeathsUntreated[ia + 5] +
			MLU_LTM.AIDSdeathsTreated[ia + 5] + MLC_LTM.AIDSdeathsTreated[ia + 5] +
			MLU_LTM.AIDSdeathsUntreated[ia + 5] + MLC_LTM.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedF[ia][0][0] += FH_LTH.AIDSdeathsTreated[ia + 5] + FH_LTH.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedF[ia][0][1] += FH_LTL.AIDSdeathsTreated[ia + 5] + FH_LTL.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedF[ia][1][0] += FL_LTH.AIDSdeathsTreated[ia + 5] + FL_LTH.AIDSdeathsUntreated[ia + 5];
		AIDSdeathsMarriedF[ia][1][1] += FL_LTL.AIDSdeathsTreated[ia + 5] + FL_LTL.AIDSdeathsUntreated[ia + 5];
	}
	for (ia = 0; ia < 81; ia++){
		// Note that for now we are only considering the unmarried deaths. In the final step
		// we will add the AIDS deaths in married individuals.
		AIDSdeathsByAge[ia][0] += MHU_virgin.AIDSdeathsTreated[ia] + MHU_virgin.AIDSdeathsUntreated[ia] +
			MHC_virgin.AIDSdeathsTreated[ia] + MHC_virgin.AIDSdeathsUntreated[ia] +
			MHU_ST.AIDSdeathsTreated[ia] + MHU_ST.AIDSdeathsUntreated[ia] + MHC_ST.AIDSdeathsTreated[ia] +
			MHC_ST.AIDSdeathsUntreated[ia] + MHU_STM.AIDSdeathsTreated[ia] + MHU_STM.AIDSdeathsUntreated[ia] + 
			MHC_STM.AIDSdeathsTreated[ia] + MHC_STM.AIDSdeathsUntreated[ia] + MHU_ID.AIDSdeathsTreated[ia] + 
			MHU_ID.AIDSdeathsUntreated[ia] + MHC_ID.AIDSdeathsTreated[ia] + MHC_ID.AIDSdeathsUntreated[ia] +
			MLU_virgin.AIDSdeathsTreated[ia] + MLU_virgin.AIDSdeathsUntreated[ia] + MLC_virgin.AIDSdeathsTreated[ia] +
			MLC_virgin.AIDSdeathsUntreated[ia] + MLU_ST.AIDSdeathsTreated[ia] + MLU_ST.AIDSdeathsUntreated[ia] +
			MLC_ST.AIDSdeathsTreated[ia] + MLC_ST.AIDSdeathsUntreated[ia] + MLU_STM.AIDSdeathsTreated[ia] +
			MLU_STM.AIDSdeathsUntreated[ia] + MLC_STM.AIDSdeathsTreated[ia] + MLC_STM.AIDSdeathsUntreated[ia] +
			MLU_ID.AIDSdeathsTreated[ia] + MLU_ID.AIDSdeathsUntreated[ia] + MLC_ID.AIDSdeathsTreated[ia] +
			MLC_ID.AIDSdeathsUntreated[ia];
		AIDSdeathsByAge[ia][1] += FH_virgin.AIDSdeathsTreated[ia] + FH_virgin.AIDSdeathsUntreated[ia] +
			FH_ST.AIDSdeathsTreated[ia] + FH_ST.AIDSdeathsUntreated[ia] + FH_SW.AIDSdeathsTreated[ia] +
			FH_SW.AIDSdeathsUntreated[ia] + FH_ID.AIDSdeathsTreated[ia] + FH_ID.AIDSdeathsUntreated[ia] + 
			FL_virgin.AIDSdeathsTreated[ia] + FL_virgin.AIDSdeathsUntreated[ia] + FL_ST.AIDSdeathsTreated[ia] +
			FL_ST.AIDSdeathsUntreated[ia] + FL_ID.AIDSdeathsTreated[ia] + FL_ID.AIDSdeathsUntreated[ia];
	}
	if (FixedUncertainty == 1){
		for (ia = 0; ia < 36; ia++){
			TotBirthsByMatAge[ia] += BirthsByHIVstage[ia][0] / 12.0;}
	}
	if (CurrMonth == 11){
		for (ia = 0; ia < 76; ia++){
			AIDSdeathsByAge[ia + 5][0] += AIDSdeathsMarriedM[ia][0][0] + AIDSdeathsMarriedM[ia][0][1] +
				AIDSdeathsMarriedM[ia][1][0] + AIDSdeathsMarriedM[ia][1][1] + AIDSdeathsMarriedMSM[ia];
			AIDSdeathsByAge[ia + 5][1] += AIDSdeathsMarriedF[ia][0][0] + AIDSdeathsMarriedF[ia][0][1] +
				AIDSdeathsMarriedF[ia][1][0] + AIDSdeathsMarriedF[ia][1][1];
		}
	}
	if (CalibAIDStrend == 1 || CalibAIDSage == 1){
		for (is = 0; is < 5; is++){
			DiagnosisRate[is] = OIincidence[is] * OIsTested[CurrYear - 1985] *
				OItoTBtestingRatio / 12.0;
		}
		for (ia = 0; ia < 9; ia++){
			for (ii = 0; ii < 5; ii++){
				for (is = 1; is < 5; is++){
					NewOIdiagnoses[ia][0] += (SumGroupsM[ia * 5 + ii][5 + is] +
						SumGroupsM[ia * 5 + ii][10 + is]) * DiagnosisRate[is];
					NewOIdiagnoses[ia][1] += (SumGroupsF[ia * 5 + ii][5 + is] +
						SumGroupsF[ia * 5 + ii][10 + is]) * DiagnosisRate[is];
				}
			}
		}
		for (ii = 0; ii < 31; ii++){
			for (is = 1; is < 5; is++){
				NewOIdiagnoses[9][0] += (SumGroupsM[50 + ii][5 + is] +
					SumGroupsM[50 + ii][10 + is]) * DiagnosisRate[is];
				NewOIdiagnoses[9][1] += (SumGroupsF[50 + ii][5 + is] +
					SumGroupsF[50 + ii][10 + is]) * DiagnosisRate[is];
			}
		}
	}
	// AIDS deaths and non-AIDS deaths in children aged <=10
	if (FixedUncertainty == 1 || CalibDeathsP == 1 || CalibChildPIP == 1){
		for (ia = 0; ia <= 10; ia++){
			for (ii = 0; ii < 12; ii++){
				AIDSdeathsByAgeP[ia][0] += MaleChild.AIDSdeaths[ia * 12 + ii];
				AIDSdeathsByAgeP[ia][1] += FemChild.AIDSdeaths[ia * 12 + ii];
				NonAIDSdeathsP[ia][0] += MaleChild.NonAIDSdeaths[ia * 12 + ii];
				NonAIDSdeathsP[ia][1] += FemChild.NonAIDSdeaths[ia * 12 + ii];
			}
		}
	}

	if (FixedUncertainty == 1 || CalibARTtotals == 1 || CalibARTtotalsP == 1 || CalibARTbyAgeP == 1){
		for (ia = 0; ia < 4; ia++){
			AdultsNewARTbyAge[ia][0] += MHU_virgin.NewARTbyAge[ia] + MHC_virgin.NewARTbyAge[ia] +
				MHU_ST.NewARTbyAge[ia] + MHC_ST.NewARTbyAge[ia] + MHU_STM.NewARTbyAge[ia] + 
				MHC_STM.NewARTbyAge[ia] + MHU_ID.NewARTbyAge[ia] + MHC_ID.NewARTbyAge[ia] + 
				MHU_LTH.NewARTbyAge[ia] + MHC_LTH.NewARTbyAge[ia] + MHU_LTL.NewARTbyAge[ia] +
				MHC_LTL.NewARTbyAge[ia] + MLU_virgin.NewARTbyAge[ia] + MHC_LTM.NewARTbyAge[ia] + 
				MHU_LTM.NewARTbyAge[ia] +
				MLC_virgin.NewARTbyAge[ia] + MLU_ST.NewARTbyAge[ia] + MLC_ST.NewARTbyAge[ia] +
				MLU_STM.NewARTbyAge[ia] + MLC_STM.NewARTbyAge[ia] + MLU_ID.NewARTbyAge[ia] + 
				MLC_ID.NewARTbyAge[ia] + MLU_LTH.NewARTbyAge[ia] + MLC_LTH.NewARTbyAge[ia] +
				MLU_LTL.NewARTbyAge[ia] + MLC_LTL.NewARTbyAge[ia] + MLU_LTM.NewARTbyAge[ia] + 
				MLC_LTM.NewARTbyAge[ia];
			AdultsNewARTbyAge[ia][1] += FH_virgin.NewARTbyAge[ia] + FH_ST.NewARTbyAge[ia] +
				FH_SW.NewARTbyAge[ia] + FH_ID.NewARTbyAge[ia] + FH_LTH.NewARTbyAge[ia] + 
				FH_LTL.NewARTbyAge[ia] + FL_virgin.NewARTbyAge[ia] + FL_ST.NewARTbyAge[ia] +
				FL_ID.NewARTbyAge[ia] + FL_LTH.NewARTbyAge[ia] + FL_LTL.NewARTbyAge[ia];
		}
		for (ia = 0; ia < 11; ia++){
			for (ii = 0; ii < 12; ii++){
				PaedNewARTbyAge[ia] += MaleChild.StartingART[ia * 12 + ii] + FemChild.StartingART[ia * 12 + ii];
				PaedNewARTlate[ia] += MaleChild.StartingARTlate[ia * 12 + ii] + FemChild.StartingARTlate[ia * 12 + ii];
			}
		}
	}
	if (CalibARTtotals == 1 || CalibARTtotalsP == 1){
		for (ii = 0; ii<ARTdataPoints; ii++){
			if (ARTtotals[ii][0] == CurrYear && ARTtotals[ii][1] == CurrMonth){ 
				ARTmodelled[ii][1] = CumART15M.out[CurrSim - 1][CurrYear - StartYear - 1] +
					CumART15F.out[CurrSim - 1][CurrYear - StartYear - 1] + AdultsNewARTbyAge[0][0] +
					AdultsNewARTbyAge[1][0] + AdultsNewARTbyAge[2][0] + AdultsNewARTbyAge[3][0] +
					AdultsNewARTbyAge[0][1] + AdultsNewARTbyAge[1][1] + AdultsNewARTbyAge[2][1] +
					AdultsNewARTbyAge[3][1];
				ARTmodelled[ii][1] += CumARTunder15.out[CurrSim - 1][CurrYear - StartYear - 1];
				for (ia = 0; ia < 15; ia++){ ARTmodelled[ii][1] += PaedNewARTbyAge[ia]; }
			}
			if (ARTtotals[ii][0] > CurrYear){ break; }
		}
		for (ii = 0; ii<ARTdataPointsP; ii++){
			if (ARTtotalsP[ii][0] == CurrYear && ARTtotalsP[ii][1] == CurrMonth){
				ARTmodelledP[ii][1] = CumARTunder15.out[CurrSim - 1][CurrYear - StartYear - 1];
				for (ia = 0; ia < 15; ia++){ ARTmodelledP[ii][1] += PaedNewARTbyAge[ia]; }
			}
			if (ARTtotalsP[ii][0] > CurrYear){ break; }
		}
	}
	if ((FixedUncertainty == 1 || CalibARTtotals == 1 || CalibARTtotalsP == 1) && CurrMonth == 11 && 
		CurrYear > StartYear){
		CumART15M.out[CurrSim - 1][CurrYear - StartYear] =
			CumART15M.out[CurrSim - 1][CurrYear - StartYear - 1] + AdultsNewARTbyAge[0][0] +
			AdultsNewARTbyAge[1][0] + AdultsNewARTbyAge[2][0] + AdultsNewARTbyAge[3][0];
		CumART15F.out[CurrSim - 1][CurrYear - StartYear] =
			CumART15F.out[CurrSim - 1][CurrYear - StartYear - 1] + AdultsNewARTbyAge[0][1] +
			AdultsNewARTbyAge[1][1] + AdultsNewARTbyAge[2][1] + AdultsNewARTbyAge[3][1];
		TempPaed = 0.0;
		for (ia = 0; ia < 15; ia++){ TempPaed += PaedNewARTbyAge[ia]; }
		CumARTunder15.out[CurrSim - 1][CurrYear - StartYear] =
			CumARTunder15.out[CurrSim - 1][CurrYear - StartYear - 1] + TempPaed;
		CumARTtot.out[CurrSim - 1][CurrYear - StartYear] = CumART15M.out[CurrSim - 1][CurrYear - StartYear] +
			CumART15F.out[CurrSim - 1][CurrYear - StartYear] + CumARTunder15.out[CurrSim - 1][CurrYear - StartYear];
	}
}

void UpdateMonthlySTesting()
{
	int ia, ii, is, ig, im;
	double TempNeg[6], TempPos[6], TempART[6], Temp1, Temp2, Linkage[2];

	Linkage[0] = SelfTestConfirm * AsymStart[0];
	Linkage[1] = SelfTestConfirm * AsymStart[1];
	for (im = 0; im < 6; im++){
		TempNeg[im] = 0.0;
		TempPos[im] = 0.0;
		TempART[im] = 0.0;
	}
	for (ia = 0; ia<81; ia++){
		for (ii = 0; ii<44; ii++){
			Temp1 = SumGroupsM[ia][ii];
			Temp2 = SumGroupsF[ia][ii];
			if (ia < 20){
				Temp1 = Temp1 - SumGroupsVM[ia][ii];
				Temp2 = Temp2 - SumGroupsVF[ia][ii];
			}
			for (im = 0; im<6; im++){
				if (ii < 2){
					TempNeg[im] += Temp1 * SelfTestingRateM[ia][ii][0][im] + Temp2 * SelfTestingRateM[ia][ii][1][im];
				}
				if (ii == 5 || ii == 10){
					TempNeg[im] += Temp1 * SelfTestingRateM[ia][ii - 3][0][im] + Temp2 * SelfTestingRateM[ia][ii - 3][1][im];
				}
				if (ii > 5 && ii <15 && ii != 10){
					TempPos[im] += Temp1 * SelfTestingRateM[ia][ii - 3][0][im] + Temp2 * SelfTestingRateM[ia][ii - 3][1][im];
					TempART[im] += Temp1 * SelfTestingRateM[ia][ii - 3][0][im] * Linkage[0] + 
						Temp2 * SelfTestingRateM[ia][ii - 3][1][im] * Linkage[1];
				}
				if (ii > 15 && ii < 20){
					TempPos[im] += (Temp1 * SelfTestingRateM[ia][ii - 13][0][im] + Temp2 * SelfTestingRateM[ia][ii - 13][1][im]) *
						RetestPosST[0];
				}
				if (ii >= 20 && ii < 44){
					TempPos[im] += (Temp1 * SelfTestingRateM[ia][3][0][im] + Temp2 * SelfTestingRateM[ia][3][1][im]) *
						RetestPosST[1];
				}
			}
		}
	}

	for (im = 0; im < 6; im++){
		NewlyTestedNegST[im] += TempNeg[im];
		NewlyTestedPosST[im] += TempPos[im];
		NewSTtoART[im] += TempART[im];
	}
}

void OneMonth(int im)
{
	CurrMonth = im;
	// Although the Calculate command in the VBA code comes at the end of the month, there is also
	// a Calculate command before the first OneMonth function is called. This means that we have 
	// to update all relevant parameters at the START of the month.
	GetCurrBehavDbnM();
	GetCurrBehavDbnF();
	if (FixedUncertainty == 1 && CurrMonth == 0){ CalcMultPartners(); }
	UpdatePop();
	UpdateFSWdemand();
	/*UpdateAgePrefsF();
	UpdatePartnerAcqM();
	UpdateMixingST();
	UpdateARTmort();
	UpdateCondomUse();*/
	UpdateFert();
	UpdateBirths();
	GetBirthsByHIV();
	if(PrEPorVM==1){
		UpdatePrEPandVM();}
	//UpdateTestingRates();
	if (CurrYear == 2019 && CurrMonth == 9 && InputARTinitiationRates == 1){ CalcARTdisruptionImpact(1); }
	if (CurrYear == 2024 && CurrMonth == 6 && InputARTinitiationRates == 1) { CalcARTdisruptionImpact(2); }
	SetARTinitiation();
	if (im==0){
		UpdateTestingToART();
		CalcInterruptions();
		SetFertByStage();
		SetActivityByStage();
	}

	// Handle operations in children
	SetMnthlyPaedParameters();
	MaleChild.GetEndProfile();
	FemChild.GetEndProfile();
	MaleChild.UpdateStartProfile();
	FemChild.UpdateStartProfile();

	// Handle operations in adult risk groups
	UpdateTransmProbs();
	CalcHIVtransitions();
	if (IncludeTB == 1) { CalcTBtransitions(); }
	UpdateMonthlyCum();
	CopyEndToStart();

	// Update entry into and exit from sex work
	UpdateFSW();
	FH_SW.UpdateStartTotal();
	FH_ST.UpdateStartTotal();

	// Update sexual debut
	if (im < 11){
		// Calcs are also in the OneYear function, so im<11 condition prevents repetition
		UpdateDebut(&MHU_virgin, &MHU_ST, &MHU_STM, 0);
		UpdateDebut(&MHC_virgin, &MHC_ST, &MHC_STM, 0);
		UpdateDebut(&MLU_virgin, &MLU_ST, &MLU_STM, 0);
		UpdateDebut(&MLC_virgin, &MLC_ST, &MLC_STM, 0);
		UpdateDebut(&FH_virgin, &FH_ST, &FH_ST, 0);
		UpdateDebut(&FL_virgin, &FL_ST, &FL_ST, 0);
		UpdateStartTot();
	}

	// Calculate command is called at the END of the month, so at this point you should
	// call the functions for doing the monthly parameter updates.
	// Note that the same functions have to be called at the START of the year, so there is
	// some redundancy, and some of this redundancy we will remove in the revised model.
}

void CalcTBforceOfInf()
{
	int ia;
	int ia1; // age group of infectious individual (10-17, 18-25, 26-45, 46+)
	int ia2; // age group of susceptible individual (0-4, 5-12, 13-25, 26-45, 46+)
	int ig1; // sex of the infectious individual
	int ig2; // sex of the susceptible individual
	double TotPop2[5][2]; // Total population by susceptible age group
	// Equivalent to N in Mmamapudi's equation
	double InfectiousSmPos[4][2]; // Smear-positive
	double InfectiousSmNeg[4][2]; // Smear-negative
	double ForceOfInf[5][2]; // Equivalent to lambda in Mmmamapudi's equation
	double CurrYearAdj;

	CurrYearAdj = 1.0;
	if (CurrYear > 2000 && CurrYear < 2011) {
		CurrYearAdj = 1.0 + (RRcontactPre2000 - 1.0) * (2011 - CurrYear) / 11.0;
	}

	for (ig2 = 0; ig2 < 2; ig2++) {
		for (ia2 = 0; ia2 < 5; ia2++) {
			TotPop2[ia2][ig2] = 0.0;
		}
		for (ia = 0; ia < 5; ia++) { TotPop2[0][ig2] += TotalPop[ia][ig2]; }
		for (ia = 5; ia < 13; ia++) { TotPop2[1][ig2] += TotalPop[ia][ig2]; }
		for (ia = 13; ia < 26; ia++) { TotPop2[2][ig2] += TotalPop[ia][ig2]; }
		for (ia = 26; ia < 46; ia++) { TotPop2[3][ig2] += TotalPop[ia][ig2]; }
		for (ia = 46; ia < 91; ia++) { TotPop2[4][ig2] += TotalPop[ia][ig2]; }
	}

	for (ig1 = 0; ig1 < 2; ig1++) {
		for (ia1 = 0; ia1 < 4; ia1++) {
			InfectiousSmPos[ia1][ig1] = 0.0;
			InfectiousSmNeg[ia1][ig1] = 0.0;
		}
	}
	for (ia = 0; ia <= 7; ia++) {
		InfectiousSmPos[0][0] += TBactiveSmPosM.Total[ia];
		InfectiousSmPos[0][1] += TBactiveSmPosF.Total[ia];
		InfectiousSmNeg[0][0] += TBactiveSmNegM.Total[ia];
		InfectiousSmNeg[0][1] += TBactiveSmNegF.Total[ia];
	}
	for (ia = 8; ia <= 15; ia++) {
		InfectiousSmPos[1][0] += TBactiveSmPosM.Total[ia];
		InfectiousSmPos[1][1] += TBactiveSmPosF.Total[ia];
		InfectiousSmNeg[1][0] += TBactiveSmNegM.Total[ia];
		InfectiousSmNeg[1][1] += TBactiveSmNegF.Total[ia];
	}
	for (ia = 16; ia <= 35; ia++) {
		InfectiousSmPos[2][0] += TBactiveSmPosM.Total[ia];
		InfectiousSmPos[2][1] += TBactiveSmPosF.Total[ia];
		InfectiousSmNeg[2][0] += TBactiveSmNegM.Total[ia];
		InfectiousSmNeg[2][1] += TBactiveSmNegF.Total[ia];
	}
	for (ia = 36; ia < 81; ia++) {
		InfectiousSmPos[3][0] += TBactiveSmPosM.Total[ia];
		InfectiousSmPos[3][1] += TBactiveSmPosF.Total[ia];
		InfectiousSmNeg[3][0] += TBactiveSmNegM.Total[ia];
		InfectiousSmNeg[3][1] += TBactiveSmNegF.Total[ia];
	}
	if (IncludeDR_TB == 1) {
		for (ia = 0; ia <= 7; ia++) {
			InfectiousSmPos[0][0] += TBactiveSmPosRR_M.Total[ia];
			InfectiousSmPos[0][1] += TBactiveSmPosRR_F.Total[ia];
			InfectiousSmNeg[0][0] += TBactiveSmNegRR_M.Total[ia];
			InfectiousSmNeg[0][1] += TBactiveSmNegRR_F.Total[ia];
		}
		for (ia = 8; ia <= 15; ia++) {
			InfectiousSmPos[1][0] += TBactiveSmPosRR_M.Total[ia];
			InfectiousSmPos[1][1] += TBactiveSmPosRR_F.Total[ia];
			InfectiousSmNeg[1][0] += TBactiveSmNegRR_M.Total[ia];
			InfectiousSmNeg[1][1] += TBactiveSmNegRR_F.Total[ia];
		}
		for (ia = 16; ia <= 35; ia++) {
			InfectiousSmPos[2][0] += TBactiveSmPosRR_M.Total[ia];
			InfectiousSmPos[2][1] += TBactiveSmPosRR_F.Total[ia];
			InfectiousSmNeg[2][0] += TBactiveSmNegRR_M.Total[ia];
			InfectiousSmNeg[2][1] += TBactiveSmNegRR_F.Total[ia];
		}
		for (ia = 36; ia < 81; ia++) {
			InfectiousSmPos[3][0] += TBactiveSmPosRR_M.Total[ia];
			InfectiousSmPos[3][1] += TBactiveSmPosRR_F.Total[ia];
			InfectiousSmNeg[3][0] += TBactiveSmNegRR_M.Total[ia];
			InfectiousSmNeg[3][1] += TBactiveSmNegRR_F.Total[ia];
		}
	}
	for (ig2 = 0; ig2 < 2; ig2++) {
		for (ia2 = 0; ia2 < 5; ia2++) {
			ForceOfInf[ia2][ig2] = 0.0;
			for (ig1 = 0; ig1 < 2; ig1++) {
				for (ia1 = 0; ia1 < 4; ia1++) {
					ForceOfInf[ia2][ig2] += (InfectiousSmPos[ia1][ig1] + InfectiousSmNeg[ia1][ig1] *
						SmNegInfectiousness) * CrudeContact[ia1][ig1] * SocialMixMatrix[ia2][ig2][ia1][ig1];
				}
			}
			ForceOfInf[ia2][ig2] *= 30.0 * TBtransmProbCurr / TotPop2[ia2][ig2];
			if (ig2 == 0) { ForceOfInf[ia2][ig2] *= RR_TBadultM; }
			if (CurrYear == 2020 || (CurrYear == 2019 && CurrMonth >= 9)) {
				ForceOfInf[ia2][ig2] *= (1.0 - ContactRednCOVID[0]);
			}
			if (CurrYear == 2021) { ForceOfInf[ia2][ig2] *= (1.0 - ContactRednCOVID[1]); }
			if (CurrYear > 2021) { ForceOfInf[ia2][ig2] *= (1.0 - ContactRednCOVID[2]); }
			if (CurrYear <= 2000) { ForceOfInf[ia2][ig2] *= RRcontactPre2000; }
			else if(CurrYear<2011){ ForceOfInf[ia2][ig2] *= CurrYearAdj; }
			if (VaryFutureInterventionsTB == 1 && CurrYear > 2024) {
				if (CurrYear >= 2029) { ForceOfInf[ia2][ig2] *= (1.0 - FutureInterventionsTB.out[CurrSim - 1][1]); }
				else {
					ForceOfInf[ia2][ig2] *= (1.0 - FutureInterventionsTB.out[CurrSim - 1][1] * (CurrYear - 2024) / 5.0);
				}
			}
			// Arbitrary upper limit to avoid susceptibles rapidly running to 0.
			if (ForceOfInf[ia2][ig2] > 0.10) { ForceOfInf[ia2][ig2] = 0.10; }
		}
	}
	for (ig2 = 0; ig2 < 2; ig2++) {
		for (ia = 10; ia < 13; ia++) { RateNewTBinfection[ia][ig2] = ForceOfInf[1][ig2]; }
		for (ia = 13; ia < 26; ia++) { RateNewTBinfection[ia][ig2] = ForceOfInf[2][ig2]; }
		for (ia = 26; ia < 46; ia++) { RateNewTBinfection[ia][ig2] = ForceOfInf[3][ig2]; }
		for (ia = 46; ia < 91; ia++) { RateNewTBinfection[ia][ig2] = ForceOfInf[4][ig2]; }
	}
	AnnualRiskMTBpaed[CurrYear - StartYear] += 0.5 * (ForceOfInf[0][0] + ForceOfInf[0][1]);

	/*if (CurrYear == 1985 && CurrMonth==0){
		for (ia = 0; ia < 90; ia++){
			RateNewTBinfection[ia][0] = 1.0 - pow((1.0 - InitLTBIprev[ia + 1]) /
				(1.0 - InitLTBIprev[ia]), 1.0 / 12.0);
			RateNewTBinfection[ia][1] = RateNewTBinfection[ia][0];
		}
		RateNewTBinfection[90][0] = RateNewTBinfection[89][0];
		RateNewTBinfection[90][1] = RateNewTBinfection[89][1];
	}*/
}

void UpdateTBsuscep(AdultTB* Suscep, AdultTB* Latent, AdultTB* SmPos, AdultTB* SmNeg, AdultTB* SmPosRR, AdultTB* SmNegRR)
{
	// Similar to TB_SusceptilesTransitions and TB_LatentTransitions functions

	int ia, is, ig;
	double temp, temp2, newTBactive, RifPropn;

	ig = Suscep->Sex;
	RifPropn = PropnNewTBrifRes[CurrYear - StartYear];
	for (ia = 0; ia < 81; ia++) {
		for (is = 0; is < 44; is++) {
			if (is < 5) { temp2 = InitActiveTBsmPos[0]; }
			else { temp2 = InitActiveTBsmPos[1]; }
			temp = Suscep->HIVstage[ia][is] * RateNewTBinfection[ia + 10][ig];
			Suscep->HIVstage_E[ia][is] = Suscep->HIVstage_E[ia][is] - temp;
			newTBactive = PropFastProg * HIVeffectTBinc[is] * TBincAdjByAgeSex[ia][ig];
			if (newTBactive > 1.0) { newTBactive = 1.0; }
			Latent->HIVstage_E[ia][is] += temp * (1.0 - newTBactive);
			SmPos->HIVstage_E[ia][is] += temp * newTBactive * temp2 * (1.0 - RifPropn);
			SmNeg->HIVstage_E[ia][is] += temp * newTBactive * (1.0 - temp2) * (1.0 - RifPropn);
			if (IncludeDR_TB == 1) {
				SmPosRR->HIVstage_E[ia][is] += temp * newTBactive * temp2 * RifPropn;
				SmNegRR->HIVstage_E[ia][is] += temp * newTBactive * (1.0 - temp2) * RifPropn;
				NewRS_TBnaive[CurrYear - StartYear] += temp * newTBactive * (1.0 - RifPropn);
				NewRR_TBnaive[CurrYear - StartYear] += temp * newTBactive * RifPropn;
			}
			if (FixedUncertainty == 1) {
				NewActiveTBbyAgeSex[ia][ig] += temp * newTBactive;
				if (is >= 5) { NewHIVposTBbyAgeSex[ia][ig] += temp * newTBactive; }
				if (is >= 20) { NewTBonARTbyAgeSex[ia][ig] += temp * newTBactive; }
			}
		}
	}
}

void UpdateTBlatent(AdultTB* Latent, AdultTB* SmPos, AdultTB* SmNeg, AdultTB* SmPosRR, AdultTB* SmNegRR, AdultTB* IPT, AdultTB* Suscep, int IPTind)
{
	// Similar to TB_LatentTransitions function in Mmamapudi's code
	// IPTind = 0 for the group that's not currently on IPT, 1 for the group that is on IPT

	int ia, is, ig, iy;
	double temp, temp2, temp3, temp3b, newTBactive, TBincidence, ReactivationRate, IPTswitch, CurePropn;

	iy = CurrYear - StartYear;
	ig = Latent->Sex;
	ReactivationRate = Reactivation;
	if (IPTind == 1) { ReactivationRate *= (1.0 - IPTefficacy); }
	if (IPTind == 1) { CurePropn = TPTfraction3HP[iy] * Cure3HP * 0.333 / (0.333 + MnthlyTPTdropout); }
	else { CurePropn = 0.0; }
	IPTswitch = 0.0;
	if (IPTind == 1 && IPTduration[iy] > 0.0) { IPTswitch = 1.0 / CurrDurTPTprotection; }
	if (IPTind == 0 && BaseIPTuptake[iy] > 0.0) { IPTswitch = BaseIPTuptake[iy]; }
	for (ia = 0; ia < 81; ia++) {
		for (is = 0; is < 44; is++) {
			if (is < 5) { temp2 = InitActiveTBsmPos[0]; }
			else { temp2 = InitActiveTBsmPos[1]; }
			newTBactive = PropFastProg * HIVeffectTBinc[is] * TBincAdjByAgeSex[ia][ig];
			if (newTBactive > 1.0) { newTBactive = 1.0; }
			if (IPTind == 1) { newTBactive *= (1.0 - IPTefficacy); }
			TBincidence = RateNewTBinfection[ia + 10][ig] * (1.0 - PartialImmunHIVneg *
				HIVeffectTBimm[is]) * newTBactive + ReactivationRate * HIVeffectTBinc[is] * TBincAdjByAgeSex[ia][ig] / 12.0;
			if (TBincidence > 1.0) { TBincidence = 1.0; }
			temp = Latent->HIVstage[ia][is] * TBincidence;
			if (IPTswitch > 0 && IPTind == 1) { temp3 = Latent->HIVstage_E[ia][is] * IPTswitch; }
			else if (IPTswitch > 0 && IPTind == 0 && is > 15) {
				temp3 = Latent->HIVstage_E[ia][is] * IPTswitch * HIVeffectIPTstart[is];
				if (IPTswitch * HIVeffectIPTstart[is] > 1.0) { temp3 = Latent->HIVstage_E[ia][is]; }
			}
			else { temp3 = 0.0; }
			if (IPTind == 0 && PropnHHcontactTPT[iy] > 0) {
				temp3 += Latent->HIVstage[ia][is] * HHscreeningProbNeg * PropnHHcontactTPT[iy];
				temp3b = Latent->HIVstage[ia][is] * HHscreeningProbNeg * PropnHHcontactTPT[iy];
			}
			else { temp3b = 0.0; }
			Latent->HIVstage_E[ia][is] = Latent->HIVstage_E[ia][is] - temp - temp3;
			SmPos->HIVstage_E[ia][is] += temp * temp2 * (1.0 - PropnNewTBrifRes[iy]);
			SmNeg->HIVstage_E[ia][is] += temp * (1.0 - temp2) * (1.0 - PropnNewTBrifRes[iy]);
			if (IncludeDR_TB == 1) {
				SmPosRR->HIVstage_E[ia][is] += temp * temp2 * PropnNewTBrifRes[iy];
				SmNegRR->HIVstage_E[ia][is] += temp * (1.0 - temp2) * PropnNewTBrifRes[iy];
				NewRS_TBnaive[iy] += temp * (1.0 - PropnNewTBrifRes[iy]);
				NewRR_TBnaive[iy] += temp * PropnNewTBrifRes[iy];
			}
			if (IPTind == 1 && CurePropn > 0) {
				Suscep->HIVstage_E[ia][is] += temp3 * CurePropn;
				IPT->HIVstage_E[ia][is] += temp3 * (1.0 - CurePropn);
			}
			else { IPT->HIVstage_E[ia][is] += temp3; }
			if (FixedUncertainty == 1) {
				NewActiveTBbyAgeSex[ia][ig] += temp;
				if (is >= 5) { NewHIVposTBbyAgeSex[ia][ig] += temp; }
				if (is >= 20) { NewTBonARTbyAgeSex[ia][ig] += temp; }
				if (ia >= 5) {
					NewTBreactivation += Latent->HIVstage[ia][is] * ReactivationRate * HIVeffectTBinc[is] *
						TBincAdjByAgeSex[ia][ig] / 12.0;
				}
				if (IPTind == 0) {
					NewIPT_TSTpos += temp3;
					NewTPT_HH += temp3b;
				}
			}
		}
	}
}

void UpdateTBactive(AdultTB* Active, AdultTB* Latent, AdultTB* Treated, AdultTB* Treated2, int SmPos)
{
	// I'm still undecided about whether to move the natural recoveries back to the latent state
	// or move them to the recently recovered state. Currently we do the former.

	int ia, is, iy, ig, id, CD4stage;
	double ScreenTemp[2], RxRate, RxRate1, RxRate2, RxRate3, MortRate, RecoveryRate, AdjF;
	double temp1, temp1b, temp1c, temp1d, temp1e, temp2, temp3, temp4;

	iy = CurrYear - StartYear;
	ig = Active->Sex;
	if (SmPos == 0) {
		MortRate = MortalitySmNeg / 12.0;
		RecoveryRate = NaturalRecSmNeg / 12.0;
	}
	else {
		MortRate = MortalitySmPos / 12.0;
		RecoveryRate = NaturalRecSmPos / 12.0;
	}
	// Adjustment for improving mortality as diagnosis rates increase
	if (CurrYear >= 2000) { MortRate *= AnnMortTB_RxCurr[0] / AnnMortTB_Rx[0]; }

	AdjF = 1.0;
	ScreenTemp[0] = HealthSeekingGen * Cough2wkActiveSmNeg * (TBsymptomScreened[iy] /
		RRscreenSymptoms) / 12.0;
	ScreenTemp[1] = HealthSeekingTB * TBsymptomScreened[iy] / 12.0;
	if (SmPos == 1) {
		ScreenTemp[0] *= RRsymptomsSmPos;
		ScreenTemp[1] *= RRsymptomsSmPos;
	}
	if (ig == 1) {
		AdjF = RRscreenF;
		ScreenTemp[0] *= RRhealthSeekingFem * RRscreenF;
		ScreenTemp[1] *= RRhealthSeekingFem * RRscreenF;
	}
	for (ia = 0; ia < 81; ia++) {
		for (is = 0; is < 44; is++) {
			if (is < 5) {
				RxRate1 = (ScreenTemp[0] + ScreenTemp[1]) * CurrSeTB[SmPos][0];
				RxRate2 = (HealthSeekingGen * Cough2wkActiveSmNeg * (1.0 - TBsymptomScreened[iy] * AdjF /
					RRscreenSymptoms) * EmpiricRx[0][1] + HealthSeekingTB * (1.0 - TBsymptomScreened[iy] *
					AdjF) * EmpiricRx[1][1]) * pow(RRhealthSeekingFem, ig) * pow(RRsymptomsSmPos, SmPos) *
					EmpiricalAdj / 12.0;
				// The formula below was previously used (incorrectly).
				//RxRate2 = (HealthSeekingGen * Cough2wkActiveSmNeg * (1.0 - TBsymptomScreened[iy] * AdjF /
				//	RRscreenSymptoms) * EmpiricRx[0][1] + HealthSeekingTB * (1.0 - TBsymptomScreened[iy] *
				//	AdjF) * EmpiricRx[1][1]) / 12.0;
				RxRate3 = (ScreenTemp[0] * EmpiricRxNeg[0][1] + ScreenTemp[1] * EmpiricRxNeg[1][1]) *
					(1.0 - EmpiricRednXpert * (1.0 - MicroscopyPropn[iy])) * (1.0 - CurrSeTB[SmPos][0]) *
					EmpiricalAdj;
			}
			else {
				RxRate1 = (ScreenTemp[0] + ScreenTemp[1]) * RRhealthSeekingHIV * CurrSeTB[SmPos][1];
				RxRate2 = (HealthSeekingGen * Cough2wkActiveSmNeg * (1.0 - TBsymptomScreened[iy] * AdjF /
					RRscreenSymptoms) * EmpiricRx[0][1] + HealthSeekingTB * (1.0 - TBsymptomScreened[iy] *
					AdjF) * EmpiricRx[1][1]) * RRhealthSeekingHIV * pow(RRhealthSeekingFem, ig) *
					pow(RRsymptomsSmPos, SmPos) * EmpiricalAdj / 12.0;
				// The formula below was previously used (incorrectly).
				//RxRate2 = (HealthSeekingGen * Cough2wkActiveSmNeg * (1.0 - TBsymptomScreened[iy] * AdjF /
				//	RRscreenSymptoms) * EmpiricRx[0][1] + HealthSeekingTB * (1.0 - TBsymptomScreened[iy] *
				//	AdjF) * EmpiricRx[1][1]) * RRhealthSeekingHIV / 12.0;
				RxRate3 = (ScreenTemp[0] * EmpiricRxNeg[0][1] + ScreenTemp[1] * EmpiricRxNeg[1][1]) *
					(1.0 - EmpiricRednXpert * (1.0 - MicroscopyPropn[iy])) * RRhealthSeekingHIV *
					(1.0 - CurrSeTB[SmPos][1]) * EmpiricalAdj;
			}
			if (SmPos == 1) { TBadultRxSmDiag[iy] += Active->HIVstage[ia][is] * RxRate1; }
			RxRate = RxRate1 * (1.0 - CurrInitLTFU) + RxRate2 + RxRate3;
			if ((FixedUncertainty == 1 || CalibTBdiagnosesA == 1 || CalibTBcasesA == 1 ||
				CalibETRdeathsA == 1 || CalibHIVprevETR == 1 || CalibRifResPropn == 1) && ia >= 5) {
				TBadultLabDiag[iy] += Active->HIVstage[ia][is] * RxRate1;
				if (is >= 5) { TBadultRxHIV[iy][ig] += Active->HIVstage[ia][is] * RxRate; }
				TBadultRxBy5yr[iy][ia / 5 - 1][ig] += Active->HIVstage[ia][is] * RxRate;
				NewEmpiricTB[0] += Active->HIVstage[ia][is] * RxRate2;
				NewEmpiricTB[1] += Active->HIVstage[ia][is] * RxRate3;
			}
			temp1 = Active->HIVstage[ia][is] * RxRate;
			if (PropnHHcontactScreened[iy] > 0.0) {
				temp1b = Active->HIVstage[ia][is] * HHscreeningProb * CurrSeTB_HHC[SmPos] *
					(1.0 - CurrInitLTFU) * HHcontactRxUptake;
			}
			else { temp1b = 0.0; }
			if (RateART_TBscreened[iy] > 0.0 && is >= 20 && is < 40) {
				CD4stage = (is - 20) / 5;
				id = is - 20 - CD4stage * 5;
				temp1c = Active->HIVstage[ia][is] * OnARTbyIntDur[id][ig][ia] * (RateART_TBscreened[iy] / 12.0) *
					CurrSeTB_ART[SmPos] * (1.0 - CurrInitLTFU);
			}
			else { temp1c = 0.0; }
			if (RatePrevTBscreened[iy] > 0.0) {
				temp1d = Active->HIVstage[ia][is] * RelapseTBpropnLastYr * (RatePrevTBscreened[iy] / 12.0) *
					CurrSeTBprev[SmPos] * (1.0 - CurrInitLTFU);
			}
			else { temp1d = 0.0; }
			if (RateD2Dscreen[iy] > 0.0) {
				temp1e = Active->HIVstage[ia][is] * (RateD2Dscreen[iy] / 12.0) *
					CurrSeTB_D2D[SmPos] * (1.0 - CurrInitLTFU) * HHcontactRxUptake;
			}
			else { temp1e = 0.0; }
			if (SmPos == 1) { SmPosRxScreen[iy] += temp1b + temp1c + temp1d + temp1e; }
			temp2 = Active->HIVstage[ia][is] * RecoveryRate * HIVeffectTBrecov[is];
			temp3 = Active->HIVstage[ia][is] * MortRate * RR_TBmortByAge[ia] * HIVeffectTBmort[is];
			temp4 = temp1 + temp1b + temp1c + temp1d + temp1e + temp2 + temp3;
			if (temp4 > Active->HIVstage[ia][is]) {
				temp1 *= Active->HIVstage[ia][is] / temp4;
				temp1b *= Active->HIVstage[ia][is] / temp4;
				temp1c *= Active->HIVstage[ia][is] / temp4;
				temp1d *= Active->HIVstage[ia][is] / temp4;
				temp1e *= Active->HIVstage[ia][is] / temp4;
				temp2 *= Active->HIVstage[ia][is] / temp4;
				temp3 *= Active->HIVstage[ia][is] / temp4;
			}
			if (((PropnHHcontactScreened[iy + 1] > 0.0 || NutritionSupportHHcontacts[iy + 1] > 0.0) && CurrMonth == 11) ||
				PropnHHcontactScreened[iy] > 0.0) {
				TBindexCasesLastMonth += temp1;
			}
			Active->HIVstage_E[ia][is] = Active->HIVstage_E[ia][is] - (temp1 + temp1b + temp1c +
				temp1d + temp1e + temp2 + temp3);
			Latent->HIVstage_E[ia][is] += temp2;
			if (Active->RifRes == 0) {
				Treated->HIVstage_E[ia][is] += temp1 + temp1b + temp1c + temp1d + temp1e;
				Treated->NewEntrants[ia][is] += temp1 + temp1b + temp1c + temp1d + temp1e;
			}
			else {
				Treated2->HIVstage_E[ia][is] += (temp1 * (1.0 - (RxRate2 + RxRate3) / RxRate) + temp1b + temp1c +
					temp1d + temp1e) * CurrDSTcoverageRR;
				Treated->HIVstage_E[ia][is] += (temp1 * (1.0 - (RxRate2 + RxRate3) / RxRate) + temp1b + temp1c +
					temp1d + temp1e) * (1.0 - CurrDSTcoverageRR) + temp1 * (RxRate2 + RxRate3) / RxRate;
				Treated2->NewEntrants[ia][is] += (temp1 * (1.0 - (RxRate2 + RxRate3) / RxRate) + temp1b + temp1c +
					temp1d + temp1e) * CurrDSTcoverageRR;
				Treated->NewEntrants[ia][is] += (temp1 * (1.0 - (RxRate2 + RxRate3) / RxRate) + temp1b + temp1c +
					temp1d + temp1e) * (1.0 - CurrDSTcoverageRR) + temp1 * (RxRate2 + RxRate3) / RxRate;
				if (IncludeDR_TB == 1) {
					New2ndLineTB_NF[iy] += (temp1 * (1.0 - (RxRate2 + RxRate3) / RxRate) + temp1b + temp1c +
						temp1d + temp1e) * CurrDSTcoverageRR;
					RifResFoundPreRx[iy] += (temp1 * ((RxRate1 + RxRate2 + RxRate3) / RxRate) + temp1b + temp1c +
						temp1d + temp1e) * CurrDSTcoverageRR;
				}
			}
			if ((FixedUncertainty == 1 || CalibTBdeathsA == 1) && ia >= 5) {
				TBadultMortBy5yr[iy][ia / 5 - 1][ig] += temp3;
			}
			if (FixedUncertainty == 1) {
				if (SmPos == 0) { TBmortSmNeg[ia][ig] += temp3; }
				if (SmPos == 1) { TBmortSmPos[ia][ig] += temp3; }
			}
			if (FixedUncertainty == 1) {
				NewRxACF[SmPos] += temp1b;
				NewRxART_ICF[SmPos] += temp1c;
				NewRxTBscreenPrev[SmPos] += temp1d;
				NewRxTBscreenD2D[SmPos] += temp1e;
			}
			if (ia >= 5 && is >= 5) {
				TBdeathsAdultHIV[iy] += temp3;
			}
		}
	}
}

void UpdateTBtreated(AdultTB* Treated, AdultTB* Treated2, AdultTB* Active1, AdultTB* Active2, AdultTB* SmPosRR, AdultTB* SmNegRR, AdultTB* PostRx, AdultTB* IPT)
{
	int ia, is, ig, iy;
	double MortRate, DropoutRate, CureRate, ReturnToActive, GetDST, GetDST2, RifPropn[44], OddsFail[2];
	double temp, temp1, temp2, temp3, temp3b, temp4, temp4b, temp5, InitMortPropn, FullCure, PartialCure;

	ig = Treated->Sex;
	iy = CurrYear - StartYear;

	DropoutRate = (DOTrollout[iy] + (1.0 - DOTrollout[iy]) / (RRdefaultDOT + (1.0 - RRdefaultDOT) *
		(1.0 - DOTSeffectivenessAdj))) * AnnDropoutTB_Rx[ig] / 12.0;
	if (CurrYear > 2021) { DropoutRate *= UltTBdefaultAdj; }
	else if (CurrYear > 2016) { DropoutRate *= 0.2 * ((2021 - CurrYear) + UltTBdefaultAdj * (CurrYear - 2016)); }
	//if (CurrYear >= 2023){ DropoutRate *= 0.5; }
	FullCure = TBfullRxCure;
	PartialCure = TBpartialRxCure;
	if (VaryFutureInterventionsTB == 1 && CurrYear >= 2024) {
		FullCure = 1.0 / (1.0 + (1.0 - TBfullRxCure) / (TBfullRxCure * FutureInterventionsTB.out[CurrSim - 1][29]));
		PartialCure = 1.0 / (1.0 + (1.0 - TBpartialRxCure) / (TBpartialRxCure * FutureInterventionsTB.out[CurrSim - 1][29]));
		if (CurrYear < 2028) {
			FullCure = 0.2 * (TBfullRxCure * (2028 - CurrYear) + FullCure * (CurrYear - 2023));
			PartialCure = 0.2 * (TBpartialRxCure * (2028 - CurrYear) + PartialCure * (CurrYear - 2023));
		}
	}
	GetDST = 0.0;
	GetDST2 = 0.0;
	if (Treated->RifRes == 0) {
		CureRate = PartialCure * DropoutRate + FullCure * (1.0 / Dur1stLineRxTB[iy]);
		ReturnToActive = (1.0 - PartialCure) * DropoutRate + (1.0 - FullCure) * (1.0 / Dur1stLineRxTB[iy]);
		if (IncludeDR_TB == 1) {
			GetDST = (1.0 - FullCure) * (1.0 / Dur1stLineRxTB[iy]) * ProbDSTifFailingRx;
			GetDST2 = (1.0 - PartialCure) * DropoutRate * ProbDSTifFailingRx * RR_DSTdropout;
		}
	}
	else if (Treated->SecondLine == 0) {
		OddsFail[0] = ((1.0 - PartialCure) / PartialCure) * ORfailureRifRes;
		OddsFail[1] = ((1.0 - FullCure) / FullCure) * ORfailureRifRes;
		CureRate = (1.0 / (1.0 + OddsFail[0])) * DropoutRate + (1.0 / (1.0 + OddsFail[1])) * (1.0 / Dur1stLineRxTB[iy]);
		ReturnToActive = (OddsFail[0] / (1.0 + OddsFail[0])) * DropoutRate + (OddsFail[1] /
			(1.0 + OddsFail[1])) * (1.0 / Dur1stLineRxTB[iy]);
		GetDST = (OddsFail[1] / (1.0 + OddsFail[1])) * (1.0 / 2.0) * ProbDSTifFailingRx;
		GetDST2 = (OddsFail[0] / (1.0 + OddsFail[0])) * DropoutRate * ProbDSTifFailingRx * RR_DSTdropout;
	}
	else {
		CureRate = PartialCure * DropoutRate + FullCure * (1.0 / Dur2ndLineRxTB[iy]);
		ReturnToActive = (1.0 - PartialCure) * DropoutRate + (1.0 - FullCure) * (1.0 / Dur2ndLineRxTB[iy]);
	}
	if (IncludeDR_TB == 0) {
		for (is = 0; is < 44; is++) { RifPropn[is] = 0.0; }
	}
	else {
		if (Treated->RifRes == 1) {
			for (is = 0; is < 44; is++) { RifPropn[is] = 1.0; }
		}
		else {
			for (is = 0; is < 44; is++) {
				RifPropn[is] = (AcquireRifResIfFail / (1.0 - AcquireRifResIfFail)) * HIVeffectRifRes[is];
				RifPropn[is] = RifPropn[is] / (1.0 + RifPropn[is]);
			}
		}
	}
	for (ia = 0; ia < 81; ia++) {
		for (is = 0; is < 44; is++) {
			if (is < 5) { temp = InitActiveTBsmPos[0]; }
			else { temp = InitActiveTBsmPos[1]; }
			MortRate = (AnnMortTB_RxCurr[ig] / 12.0) * RR_TBmortByAge[ia] * HIVeffectTBmort[is];
			if (Dur1stLineRxTB[iy] == 4) { MortRate *= 1.25; }
			if (Treated->RifRes == 1 && Treated->SecondLine == 0) { MortRate *= RRmortRifRes1st; }
			InitMortPropn = MortRate * ExcessMort1stMoTB_Rx;
			temp1 = Treated->HIVstage[ia][is] * MortRate + Treated->NewEntrants[ia][is] * InitMortPropn;
			if (IncludeDR_TB == 0 || Treated->SecondLine == 1) {
				temp2 = Treated->HIVstage[ia][is] * ReturnToActive * temp;
				temp3 = Treated->HIVstage[ia][is] * ReturnToActive * (1.0 - temp);
				temp3b = 0.0;
			}
			else if (Treated->RifRes == 0) {
				// If resistance is acquired, assume it's only detected at end of 6 months
				temp2 = Treated->HIVstage[ia][is] * (ReturnToActive - GetDST * RifPropn[is]) * temp;
				temp3 = Treated->HIVstage[ia][is] * (ReturnToActive - GetDST * RifPropn[is]) * (1.0 - temp);
				temp3b = Treated->HIVstage[ia][is] * GetDST * RifPropn[is];
			}
			else {
				// But if resistance was already present before Rx initiation, assume it can be picked
				// up at 2-monthly screening for Rx failure
				temp2 = Treated->HIVstage[ia][is] * ReturnToActive * temp;
				temp3 = Treated->HIVstage[ia][is] * ReturnToActive * (1.0 - temp);
				temp3b = Treated->HIVstage[ia][is] * GetDST;
			}
			temp4 = Treated->HIVstage[ia][is] * CureRate;
			temp4b = Treated->HIVstage[ia][is] * FullCure * (1.0 / 6.0) * IPTcontinuePostRx[iy];
			temp4 = temp4 - temp4b;
			temp5 = temp1 + temp2 + temp3 + temp3b + temp4 + temp4b;
			if (temp5 > Treated->HIVstage_E[ia][is]) {
				temp1 *= Treated->HIVstage_E[ia][is] / temp5;
				temp2 *= Treated->HIVstage_E[ia][is] / temp5;
				temp3 *= Treated->HIVstage_E[ia][is] / temp5;
				temp3b *= Treated->HIVstage_E[ia][is] / temp5;
				temp4 *= Treated->HIVstage_E[ia][is] / temp5;
				temp4b *= Treated->HIVstage_E[ia][is] / temp5;
			}
			Treated->HIVstage_E[ia][is] = Treated->HIVstage_E[ia][is] - (temp1 + temp2 + temp3 + temp3b +
				temp4 + temp4b);
			Active1->HIVstage_E[ia][is] += temp2 * (1.0 - RifPropn[is]);
			Active2->HIVstage_E[ia][is] += temp3 * (1.0 - RifPropn[is]);
			PostRx->HIVstage_E[ia][is] += temp4;
			IPT->HIVstage_E[ia][is] += temp4b;
			if (IncludeDR_TB == 1) {
				SmPosRR->HIVstage_E[ia][is] += temp2 * RifPropn[is];
				SmNegRR->HIVstage_E[ia][is] += temp3 * RifPropn[is];
				Treated2->HIVstage_E[ia][is] += temp3b;
				RifResFoundOnRx[iy] += temp3b + Treated->HIVstage[ia][is] * GetDST2 * RifPropn[is];
				New2ndLineTB_F[iy] += temp3b;
				if (FixedUncertainty == 1) {
					CultureOrLPAfailing[iy] += Treated->HIVstage[ia][is] * (GetDST + GetDST2);
				}
				FailTB_Rx_RS[iy] += (temp2 + temp3) * (1.0 - RifPropn[is]);
				FailTB_Rx_RR[iy] += (temp2 + temp3) * RifPropn[is];
				if (Treated->RifRes == 0) { FailTB_Rx_RR[iy] = FailTB_Rx_RR[iy] - temp3b; }
				if (Treated->RifRes == 0 && FixedUncertainty == 1) {
					FailTB_RxNewRR[iy] += (temp2 + temp3) * RifPropn[is];
				}
			}
			if (ia >= 5) {
				TBadultMortOnRx[iy][ig] += temp1;
				if (IncludeDR_TB == 1) {
					if (Treated->SecondLine == 0) { TBadultMortOnRx1[iy][ig] += temp1; }
					else { TBadultMortOnRx2[iy][ig] += temp1; }
				}
			}
			if ((FixedUncertainty == 1 || CalibTBdeathsA == 1) && ia >= 5) {
				TBadultMortBy5yr[iy][ia / 5 - 1][ig] += temp1;
			}
			if (ia >= 5 && is >= 5) {
				TBdeathsAdultHIV[iy] += temp1;
			}
			if (FixedUncertainty == 1) { TBmortTreated[ia][ig] += temp1; }
			if (FixedUncertainty == 1) { NewIPT_TSTpos += temp4b; }
		}
	}
}

void UpdateTBrecovST(AdultTB* PostRxST, AdultTB* PostRxLT, AdultTB* Active1, AdultTB* Active2, AdultTB* SmPosRR, AdultTB* SmNegRR, AdultTB* IPT, AdultTB* Suscep, int IPTind)
{
	// IPTind = 0 for the group that's not currently on IPT, 1 for the group that is on IPT

	int ia, is, ig, iy;
	double RelapseRate, TransitionToLT, newTBactive, TBincidence, TransitionToActive;
	double temp, temp1, temp2, temp3, temp4, temp4b, IPTswitch, CurePropn;
	// 'Relapse' here is synonymous with reactivation in the UpdateTBrecovLT function.

	iy = CurrYear - StartYear;
	ig = PostRxST->Sex;
	RelapseRate = RelapseST / 12.0;
	if (IPTind == 1) { RelapseRate *= (1.0 - IPTefficacy); }
	if (IPTind == 1) { CurePropn = TPTfraction3HP[iy] * Cure3HP * 0.333 / (0.333 + MnthlyTPTdropout); }
	else { CurePropn = 0.0; }
	TransitionToLT = (1.0 / DurSTpostRxRisk) / 12.0;
	IPTswitch = 0.0;
	if (IPTind == 1 && IPTduration[iy] > 0.0) { IPTswitch = 1.0 / CurrDurTPTprotection; }
	if (IPTind == 0 && BaseIPTuptake[iy] > 0.0) { IPTswitch = BaseIPTuptake[iy]; }
	for (ia = 0; ia < 81; ia++) {
		for (is = 0; is < 44; is++) {
			if (is < 5) { temp = InitActiveTBsmPos[0]; }
			else { temp = InitActiveTBsmPos[1]; }
			newTBactive = PropFastProg * HIVeffectTBinc[is] * TBincAdjByAgeSex[ia][ig];
			if (IPTind == 1) { newTBactive *= (1.0 - IPTefficacy); }
			if (newTBactive > 1.0) { newTBactive = 1.0; }
			TBincidence = RateNewTBinfection[ia + 10][ig] * PastTBfactor * (1.0 -
				PartialImmunHIVneg * HIVeffectTBimm[is]) * newTBactive + RelapseRate;
			if (TBincidence > 1.0) { TBincidence = 1.0; }
			TransitionToActive = PostRxST->HIVstage[ia][is] * TBincidence;
			temp1 = PostRxST->HIVstage[ia][is] * TransitionToLT;
			temp2 = TransitionToActive * temp;
			temp3 = TransitionToActive * (1.0 - temp);
			if (IPTswitch > 0 && IPTind == 1) { temp4 = PostRxST->HIVstage_E[ia][is] * IPTswitch; }
			else if (IPTswitch > 0 && IPTind == 0 && is > 15) {
				temp4 = PostRxST->HIVstage_E[ia][is] * IPTswitch * HIVeffectIPTstart[is];
				if (IPTswitch * HIVeffectIPTstart[is] > 1.0) { temp4 = PostRxST->HIVstage_E[ia][is]; }
			}
			else { temp4 = 0.0; }
			if (IPTind == 0 && PropnHHcontactTPT[iy] > 0) {
				temp4 += PostRxST->HIVstage[ia][is] * HHscreeningProbNeg * PropnHHcontactTPT[iy];
				temp4b = PostRxST->HIVstage[ia][is] * HHscreeningProbNeg * PropnHHcontactTPT[iy];
			}
			else { temp4b = 0.0; }
			PostRxST->HIVstage_E[ia][is] = PostRxST->HIVstage_E[ia][is] - (temp1 + temp2 + temp3 + temp4);
			PostRxLT->HIVstage_E[ia][is] += temp1;
			Active1->HIVstage_E[ia][is] += temp2 * (1.0 - PropnNewTBrifRes[iy]);
			Active2->HIVstage_E[ia][is] += temp3 * (1.0 - PropnNewTBrifRes[iy]);
			if (IncludeDR_TB == 1) {
				SmPosRR->HIVstage_E[ia][is] += temp2 * PropnNewTBrifRes[iy];
				SmNegRR->HIVstage_E[ia][is] += temp3 * PropnNewTBrifRes[iy];
				NewRS_TBprevRx[iy] += TransitionToActive * (1.0 - PropnNewTBrifRes[iy]);
				NewRR_TBprevRx[iy] += TransitionToActive * PropnNewTBrifRes[iy];
			}
			if (IPTind == 1 && CurePropn > 0) {
				Suscep->HIVstage_E[ia][is] += temp4 * CurePropn;
				IPT->HIVstage_E[ia][is] += temp4 * (1.0 - CurePropn);
			}
			else { IPT->HIVstage_E[ia][is] += temp4; }
			if (FixedUncertainty == 1) {
				NewActiveTBbyAgeSex[ia][ig] += TransitionToActive;
				NewRecurrentTBbyAgeSex[ia][ig] += TransitionToActive;
				NewRelapseTBbyAgeSex[ia][ig] += TransitionToActive;
				if (is >= 5) { NewHIVposTBbyAgeSex[ia][ig] += TransitionToActive; }
				if (is >= 20) { NewTBonARTbyAgeSex[ia][ig] += TransitionToActive; }
				if (ia >= 5) {
					NewTBreactivation += PostRxST->HIVstage[ia][is] * RelapseRate;
				}
				if (IPTind == 0) {
					NewIPT_TSTpos += temp4;
					NewTPT_HH += temp4b;
				}
			}
		}
	}
}

void UpdateTBrecovLT(AdultTB* PostRxLT, AdultTB* Active1, AdultTB* Active2, AdultTB* SmPosRR, AdultTB* SmNegRR, AdultTB* IPT, AdultTB* Suscep, int IPTind)
{
	// IPTind = 0 for the group that's not currently on IPT, 1 for the group that is on IPT

	int ia, is, ig, iy;
	double ReactivationRate, newTBactive, TBincidence, TransitionToActive;
	double temp, temp2, temp3, temp4, temp4b, IPTswitch, CurePropn;

	iy = CurrYear - StartYear;
	ig = PostRxLT->Sex;
	ReactivationRate = Reactivation * PastTBfactor / 12.0;
	if (IPTind == 1) { ReactivationRate *= (1.0 - IPTefficacy); }
	if (IPTind == 1) { CurePropn = TPTfraction3HP[iy] * Cure3HP * 0.333 / (0.333 + MnthlyTPTdropout); }
	else { CurePropn = 0.0; }
	IPTswitch = 0.0;
	if (IPTind == 1 && IPTduration[iy] > 0.0) { IPTswitch = 1.0 / CurrDurTPTprotection; }
	if (IPTind == 0 && BaseIPTuptake[iy] > 0.0) { IPTswitch = BaseIPTuptake[iy]; }
	for (ia = 0; ia < 81; ia++) {
		for (is = 0; is < 44; is++) {
			if (is < 5) { temp = InitActiveTBsmPos[0]; }
			else { temp = InitActiveTBsmPos[1]; }
			newTBactive = PropFastProg * HIVeffectTBinc[is] * TBincAdjByAgeSex[ia][ig];
			if (IPTind == 1) { newTBactive *= (1.0 - IPTefficacy); }
			if (newTBactive > 1.0) { newTBactive = 1.0; }
			TBincidence = RateNewTBinfection[ia + 10][ig] * PastTBfactor * (1.0 - PartialImmunHIVneg * HIVeffectTBimm[is]) *
				newTBactive + ReactivationRate * HIVeffectTBinc[is] * TBincAdjByAgeSex[ia][ig];
			if (TBincidence > 1.0) { TBincidence = 1.0; }
			TransitionToActive = PostRxLT->HIVstage[ia][is] * TBincidence;
			temp2 = TransitionToActive * temp;
			temp3 = TransitionToActive * (1.0 - temp);
			if (IPTswitch > 0 && IPTind == 1) { temp4 = PostRxLT->HIVstage_E[ia][is] * IPTswitch; }
			else if (IPTswitch > 0 && IPTind == 0 && is > 15) {
				temp4 = PostRxLT->HIVstage_E[ia][is] * IPTswitch * HIVeffectIPTstart[is];
				if (IPTswitch * HIVeffectIPTstart[is] > 1.0) { temp4 = PostRxLT->HIVstage_E[ia][is]; }
			}
			else { temp4 = 0.0; }
			if (IPTind == 0 && PropnHHcontactTPT[iy] > 0) {
				temp4 += PostRxLT->HIVstage[ia][is] * HHscreeningProbNeg * PropnHHcontactTPT[iy];
				temp4b = PostRxLT->HIVstage[ia][is] * HHscreeningProbNeg * PropnHHcontactTPT[iy];
			}
			else { temp4b = 0.0; }
			PostRxLT->HIVstage_E[ia][is] = PostRxLT->HIVstage_E[ia][is] - (temp2 + temp3 + temp4);
			Active1->HIVstage_E[ia][is] += temp2 * (1.0 - PropnNewTBrifRes[iy]);
			Active2->HIVstage_E[ia][is] += temp3 * (1.0 - PropnNewTBrifRes[iy]);
			if (IncludeDR_TB == 1) {
				SmPosRR->HIVstage_E[ia][is] += temp2 * PropnNewTBrifRes[iy];
				SmNegRR->HIVstage_E[ia][is] += temp3 * PropnNewTBrifRes[iy];
				NewRS_TBprevRx[iy] += TransitionToActive * (1.0 - PropnNewTBrifRes[iy]);
				NewRR_TBprevRx[iy] += TransitionToActive * PropnNewTBrifRes[iy];
			}
			if (IPTind == 1 && CurePropn > 0) {
				Suscep->HIVstage_E[ia][is] += temp4 * CurePropn;
				IPT->HIVstage_E[ia][is] += temp4 * (1.0 - CurePropn);
			}
			else { IPT->HIVstage_E[ia][is] += temp4; }
			if (FixedUncertainty == 1) {
				NewActiveTBbyAgeSex[ia][ig] += TransitionToActive;
				NewRecurrentTBbyAgeSex[ia][ig] += TransitionToActive;
				if (is >= 5) { NewHIVposTBbyAgeSex[ia][ig] += TransitionToActive; }
				if (is >= 20) { NewTBonARTbyAgeSex[ia][ig] += TransitionToActive; }
				if (ia >= 5) {
					NewTBreactivation += PostRxLT->HIVstage[ia][is] * ReactivationRate * HIVeffectTBinc[is] * TBincAdjByAgeSex[ia][ig];
				}
				if (IPTind == 0) {
					NewIPT_TSTpos += temp4;
					NewTPT_HH += temp4b;
				}
			}
		}
	}
}

void CalcTBtransitions()
{
	int ia, is;

	// Reset NewEntrants to zero
	for (ia = 0; ia < 81; ia++) {
		for (is = 0; is < 44; is++) {
			TBtreatedM.NewEntrants[ia][is] = 0.0;
			TBtreatedF.NewEntrants[ia][is] = 0.0;
			if (IncludeDR_TB == 1) {
				RR_TBtreated1stM.NewEntrants[ia][is] = 0.0;
				RR_TBtreated2ndM.NewEntrants[ia][is] = 0.0;
				RR_TBtreated1stF.NewEntrants[ia][is] = 0.0;
				RR_TBtreated2ndF.NewEntrants[ia][is] = 0.0;
			}
		}
	}

	CalcTBforceOfInf();
	TBsuscepM.UpdateEndProfile();
	TBlatentM.UpdateEndProfile();
	TBactiveSmPosM.UpdateEndProfile();
	TBactiveSmNegM.UpdateEndProfile();
	TBtreatedM.UpdateEndProfile();
	TBrecoveredST_M.UpdateEndProfile();
	TBrecoveredLT_M.UpdateEndProfile();
	TBlatentIPT_M.UpdateEndProfile();
	TBrecST_IPT_M.UpdateEndProfile();
	TBrecLT_IPT_M.UpdateEndProfile();
	TBsuscepF.UpdateEndProfile();
	TBlatentF.UpdateEndProfile();
	TBactiveSmPosF.UpdateEndProfile();
	TBactiveSmNegF.UpdateEndProfile();
	TBtreatedF.UpdateEndProfile();
	TBrecoveredST_F.UpdateEndProfile();
	TBrecoveredLT_F.UpdateEndProfile();
	TBlatentIPT_F.UpdateEndProfile();
	TBrecST_IPT_F.UpdateEndProfile();
	TBrecLT_IPT_F.UpdateEndProfile();
	if (IncludeDR_TB == 1) {
		TBactiveSmPosRR_M.UpdateEndProfile();
		TBactiveSmNegRR_M.UpdateEndProfile();
		RR_TBtreated1stM.UpdateEndProfile();
		RR_TBtreated2ndM.UpdateEndProfile();
		TBactiveSmPosRR_F.UpdateEndProfile();
		TBactiveSmNegRR_F.UpdateEndProfile();
		RR_TBtreated1stF.UpdateEndProfile();
		RR_TBtreated2ndF.UpdateEndProfile();
	}

	UpdateTBsuscep(&TBsuscepM, &TBlatentM, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M);
	UpdateTBsuscep(&TBsuscepF, &TBlatentF, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F);
	UpdateTBlatent(&TBlatentM, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBlatentIPT_M, &TBsuscepM, 0);
	UpdateTBlatent(&TBlatentF, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBlatentIPT_F, &TBsuscepF, 0);
	UpdateTBactive(&TBactiveSmPosM, &TBlatentM, &TBtreatedM, &RR_TBtreated2ndM, 1);
	UpdateTBactive(&TBactiveSmPosF, &TBlatentF, &TBtreatedF, &RR_TBtreated2ndF, 1);
	UpdateTBactive(&TBactiveSmNegM, &TBlatentM, &TBtreatedM, &RR_TBtreated2ndM, 0);
	UpdateTBactive(&TBactiveSmNegF, &TBlatentF, &TBtreatedF, &RR_TBtreated2ndF, 0);
	UpdateTBtreated(&TBtreatedM, &RR_TBtreated2ndM, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBrecoveredST_M, &TBrecST_IPT_M);
	UpdateTBtreated(&TBtreatedF, &RR_TBtreated2ndF, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBrecoveredST_F, &TBrecST_IPT_F);
	UpdateTBrecovST(&TBrecoveredST_M, &TBrecoveredLT_M, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBrecST_IPT_M, &TBsuscepM, 0);
	UpdateTBrecovST(&TBrecoveredST_F, &TBrecoveredLT_F, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBrecST_IPT_F, &TBsuscepF, 0);
	UpdateTBrecovLT(&TBrecoveredLT_M, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBrecLT_IPT_M, &TBsuscepM, 0);
	UpdateTBrecovLT(&TBrecoveredLT_F, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBrecLT_IPT_F, &TBsuscepF, 0);
	if (BaseIPTuptake[CurrYear - StartYear] > 0.0) {
		UpdateTBlatent(&TBlatentIPT_M, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBlatentM, &TBsuscepM, 1);
		UpdateTBlatent(&TBlatentIPT_F, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBlatentF, &TBsuscepF, 1);
		UpdateTBrecovST(&TBrecST_IPT_M, &TBrecoveredLT_M, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBrecoveredST_M, &TBsuscepM, 1);
		UpdateTBrecovST(&TBrecST_IPT_F, &TBrecoveredLT_F, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBrecoveredST_F, &TBsuscepF, 1);
		UpdateTBrecovLT(&TBrecLT_IPT_M, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBrecoveredLT_M, &TBsuscepM, 1);
		UpdateTBrecovLT(&TBrecLT_IPT_F, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBrecoveredLT_F, &TBsuscepF, 1);
	}
	if (IncludeDR_TB == 1) {
		UpdateTBactive(&TBactiveSmPosRR_M, &TBlatentM, &RR_TBtreated1stM, &RR_TBtreated2ndM, 1);
		UpdateTBactive(&TBactiveSmPosRR_F, &TBlatentF, &RR_TBtreated1stF, &RR_TBtreated2ndF, 1);
		UpdateTBactive(&TBactiveSmNegRR_M, &TBlatentM, &RR_TBtreated1stM, &RR_TBtreated2ndM, 0);
		UpdateTBactive(&TBactiveSmNegRR_F, &TBlatentF, &RR_TBtreated1stF, &RR_TBtreated2ndF, 0);
		UpdateTBtreated(&RR_TBtreated1stM, &RR_TBtreated2ndM, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBrecoveredST_M, &TBrecST_IPT_M);
		UpdateTBtreated(&RR_TBtreated1stF, &RR_TBtreated2ndF, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBrecoveredST_F, &TBrecST_IPT_F);
		UpdateTBtreated(&RR_TBtreated2ndM, &RR_TBtreated1stM, &TBactiveSmPosM, &TBactiveSmNegM, &TBactiveSmPosRR_M, &TBactiveSmNegRR_M, &TBrecoveredST_M, &TBrecST_IPT_M);
		UpdateTBtreated(&RR_TBtreated2ndF, &RR_TBtreated1stF, &TBactiveSmPosF, &TBactiveSmNegF, &TBactiveSmPosRR_F, &TBactiveSmNegRR_F, &TBrecoveredST_F, &TBrecST_IPT_F);
	}
}

void GetHIVtoTBpopRatios()
{
	// Similar to TB_SumTBandHIVPopTotals function in Mmamapudi's code

	int ia, is;
	double temp1, temp2;

	for (ia = 0; ia < 81; ia++) {
		temp1 = 0.0;
		temp2 = 0.0;
		for (is = 0; is < 44; is++) {
			SumTBgroupsM[ia][is] = TBsuscepM.HIVstage[ia][is] + TBlatentM.HIVstage[ia][is] +
				TBactiveSmPosM.HIVstage[ia][is] + TBactiveSmNegM.HIVstage[ia][is] + TBtreatedM.HIVstage[ia][is] +
				TBrecoveredST_M.HIVstage[ia][is] + TBrecoveredLT_M.HIVstage[ia][is] +
				TBlatentIPT_M.HIVstage[ia][is] + TBrecST_IPT_M.HIVstage[ia][is] + TBrecLT_IPT_M.HIVstage[ia][is];
			SumTBgroupsF[ia][is] = TBsuscepF.HIVstage[ia][is] + TBlatentF.HIVstage[ia][is] +
				TBactiveSmPosF.HIVstage[ia][is] + TBactiveSmNegF.HIVstage[ia][is] + TBtreatedF.HIVstage[ia][is] +
				TBrecoveredST_F.HIVstage[ia][is] + TBrecoveredLT_F.HIVstage[ia][is] +
				TBlatentIPT_F.HIVstage[ia][is] + TBrecST_IPT_F.HIVstage[ia][is] + TBrecLT_IPT_F.HIVstage[ia][is];
			if (IncludeDR_TB == 1) {
				SumTBgroupsM[ia][is] += TBactiveSmPosRR_M.HIVstage[ia][is] + TBactiveSmNegRR_M.HIVstage[ia][is] +
					RR_TBtreated1stM.HIVstage[ia][is] + RR_TBtreated2ndM.HIVstage[ia][is];
				SumTBgroupsF[ia][is] += TBactiveSmPosRR_F.HIVstage[ia][is] + TBactiveSmNegRR_F.HIVstage[ia][is] +
					RR_TBtreated1stF.HIVstage[ia][is] + RR_TBtreated2ndF.HIVstage[ia][is];
			}
			temp1 += SumTBgroupsM[ia][is];
			temp2 += SumTBgroupsF[ia][is];
			if (SumTBgroupsM[ia][is] > 0.0 && SumGroupsM[ia][is] > 0.0) {
				RatioHIVtoTBpopM[ia][is] = SumGroupsM[ia][is] / SumTBgroupsM[ia][is];
			}
			if (SumTBgroupsF[ia][is] > 0.0 && SumGroupsF[ia][is] > 0.0) {
				RatioHIVtoTBpopF[ia][is] = SumGroupsF[ia][is] / SumTBgroupsF[ia][is];
			}
			if (SumTBgroupsM[ia][is] >= 0.0 && SumGroupsM[ia][is] == 0.0) {
				RatioHIVtoTBpopM[ia][is] = 0.0;
			}
			if (SumTBgroupsF[ia][is] >= 0.0 && SumGroupsF[ia][is] == 0.0) {
				RatioHIVtoTBpopF[ia][is] = 0.0;
			}
			// - 1 below is just an indicator of an undefined ratio (dealt with differently)
			if (SumTBgroupsM[ia][is] == 0.0 && SumGroupsM[ia][is] > 0.0) {
				RatioHIVtoTBpopM[ia][is] = -1.0;
			}
			if (SumTBgroupsF[ia][is] == 0.0 && SumGroupsF[ia][is] > 0.0) {
				RatioHIVtoTBpopF[ia][is] = -1.0;
			}
		}
		SumTB[ia][0] = temp1;
		SumTB[ia][1] = temp2;
	}
}

