void ResultsAtEndOfYr()
{
	int ia, ig, ii, iy;
	double Temp[2], NewART_P;

	iy = CurrYear - StartYear;
	Temp[0] = 0.0;
	Temp[1] = 0.0;

	// Results in the Monthly sheet

	for(ia=0; ia<81; ia++){
		for(ig=0; ig<2; ig++){
			NonAIDSdeathsA[ia][ig] = TotalPop[ia+10][ig] * CurrNonAIDSmortALB[ia+10][ig];
			TotDeathsByAge[ia][ig] = NonAIDSdeathsA[ia][ig] + AIDSdeathsByAge[ia][ig];
		}
	}
	if (FixedUncertainty == 1){
		for (ia = 0; ia<10; ia++){
			NonAIDSdeathsPosM.out[ia][iy] += NonAIDSdeathsP[ia][0] * 0.5 * (TotalPositive_S[ia][0] /
				TotalPop_S[ia][0] + TotalPositive[ia][0] / TotalPop[ia][0]);
			NonAIDSdeathsPosF.out[ia][iy] += NonAIDSdeathsP[ia][1] * 0.5 * (TotalPositive_S[ia][1] /
				TotalPop_S[ia][1] + TotalPositive[ia][1] / TotalPop[ia][1]);
			NonAIDSdeathsNegM.out[ia][iy] += NonAIDSdeathsP[ia][0] * (1.0 - 0.5 * (TotalPositive_S[ia][0] /
				TotalPop_S[ia][0] + TotalPositive[ia][0] / TotalPop[ia][0]));
			NonAIDSdeathsNegF.out[ia][iy] += NonAIDSdeathsP[ia][1] * (1.0 - 0.5 * (TotalPositive_S[ia][1] /
				TotalPop_S[ia][1] + TotalPositive[ia][1] / TotalPop[ia][1]));
		}
		for (ia = 0; ia<81; ia++){
			NonAIDSdeathsPosM.out[ia+10][iy] += NonAIDSdeathsA[ia][0] * 0.5 * (TotalPositive_S[ia + 10][0] /
				TotalPop_S[ia + 10][0] + TotalPositive[ia + 10][0] / TotalPop[ia + 10][0]);
			NonAIDSdeathsPosF.out[ia + 10][iy] += NonAIDSdeathsA[ia][1] * 0.5 * (TotalPositive_S[ia + 10][1] /
				TotalPop_S[ia + 10][1] + TotalPositive[ia + 10][1] / TotalPop[ia + 10][1]);
			NonAIDSdeathsNegM.out[ia + 10][iy] += NonAIDSdeathsA[ia][0] * (1.0 - 0.5 * (TotalPositive_S[ia + 10][0] /
				TotalPop_S[ia + 10][0] + TotalPositive[ia + 10][0] / TotalPop[ia + 10][0]));
			NonAIDSdeathsNegF.out[ia + 10][iy] += NonAIDSdeathsA[ia][1] * (1.0 - 0.5 * (TotalPositive_S[ia + 10][1] /
				TotalPop_S[ia + 10][1] + TotalPositive[ia + 10][1] / TotalPop[ia + 10][1]));
		}
	}

	// Results in the main Results sheet

	for(ia=0; ia<15; ia++){
		for(ig=0; ig<2; ig++){
			AdultMortBy5yr[iy][ia][ig] = 0.5 * (TotDeathsByAge[ia * 5 + 4][ig] + TotDeathsByAge[ia * 5 + 9][ig]);
			NonAIDSmortBy5yr[iy][ia][ig] = 0.5 * (NonAIDSdeathsA[ia * 5 + 4][ig] + NonAIDSdeathsA[ia * 5 + 9][ig]);
			for(ii=0; ii<4; ii++){
				AdultMortBy5yr[iy][ia][ig] += TotDeathsByAge[ia*5+5+ii][ig];
				NonAIDSmortBy5yr[iy][ia][ig] += NonAIDSdeathsA[ia * 5 + 5 + ii][ig];
			}
		}
	}
	AdultMortBy5yr[iy][15][0] = 0.5 * TotDeathsByAge[79][0] + TotDeathsByAge[80][0];
	AdultMortBy5yr[iy][15][1] = 0.5 * TotDeathsByAge[79][1] + TotDeathsByAge[80][1];
	NonAIDSmortBy5yr[iy][15][0] = 0.5 * NonAIDSdeathsA[79][0] + NonAIDSdeathsA[80][0];
	NonAIDSmortBy5yr[iy][15][1] = 0.5 * NonAIDSdeathsA[79][1] + NonAIDSdeathsA[80][1];

	for(ia=15; ia<91; ia++){
		Temp[0] += 0.5 * (TotalNaiveElig_S[ia][0] + TotalNaiveElig[ia][0]);
		Temp[1] += 0.5 * (TotalNaiveElig_S[ia][1] + TotalNaiveElig[ia][1]);
	}
	RateARTstartU200[iy][0] = AdultsNewARTbyCD4[3][0]/Temp[0];
	RateARTstartU200[iy][1] = AdultsNewARTbyCD4[3][1]/Temp[1];
	Temp[0] = 0.0;
	for (ia = 0; ia<10; ia++){
		Temp[0] += 0.5 * (TotalNaiveElig_S[ia][0] + TotalNaiveElig[ia][0] +
			TotalNaiveElig_S[ia][1] + TotalNaiveElig[ia][1]);
	}
	RateARTstartLate[iy] = ChildNewARTlate / Temp[0];

	if(CalibAIDStrend==1 && iy<10 && iy>=5){
		OIsDiagnosedByYr[iy-5] = 0.0;
		for(ia=0; ia<10; ia++){
			for(ig=0; ig<2; ig++){
				OIsDiagnosedByYr[iy-5] += NewOIdiagnoses[ia][ig];}
		}
	}
	if(CalibAIDSage==1 && iy<10 && iy>=8){
		if(iy==8){
			for(ia=0; ia<10; ia++){
				for(ig=0; ig<2; ig++){
					OIsDiagnosedProfile[ia][ig] = 0.0;}
			}
		}
		for(ia=0; ia<10; ia++){
			for(ig=0; ig<2; ig++){
				OIsDiagnosedProfile[ia][ig] += NewOIdiagnoses[ia][ig];}
		}
	}
	if (CalibHCTprev == 1 && CurrYear >=2004){
		Temp[0] = (NewlyTestedPos[0] + NewlyTestedPos[1] + (NewlyTestedNeg[0] + NewlyTestedNeg[1]) * 
			(1.0 - RapidDiagSp)) / (NewlyTestedPos[0] + NewlyTestedPos[1] +
			NewlyTestedNeg[0] + NewlyTestedNeg[1]);
		if (CurrYear <= 2008){ ModelPrevHCT[CurrYear - 2004] = Temp[0];}
		if (CurrYear == 2010){ ModelPrevHCT[5] = Temp[0]; }
		if (CurrYear == 2012){ ModelPrevHCT[6] = Temp[0]; }
		if (CurrYear >= 2015 && CurrYear<2024){ ModelPrevHCT[iy-23] = Temp[0]; }
	}
	if (CalibHCTprevP == 1 && CurrYear >= 2015 && CurrYear <= 2022){
		ModelPrevHCT_P[CurrYear - 2015] = (NewlyTestedPos[2] + NewlyTestedNeg[2] * 
			(1.0 - RapidDiagSp)) / (NewlyTestedPos[2] + NewlyTestedNeg[2]);
	}

	// Paediatric mortality outputs needed in calibration
	if (FixedUncertainty == 1 || CalibDeathsP == 1 || CalibChildPIP == 1){
		// Total deaths in children
		for (ia = 0; ia < 11; ia++){
			for (ig = 0; ig < 2; ig++){
				TotDeathsByAgeP[ia][ig] = AIDSdeathsByAgeP[ia][ig] +
					NonAIDSdeathsP[ia][ig];
			}
		}
		ChildMortBy5yr[iy][0][0] = TotDeathsByAgeP[0][0];
		ChildMortBy5yr[iy][0][1] = TotDeathsByAgeP[0][1];
		ChildMortBy5yr[iy][1][0] = TotDeathsByAgeP[1][0] + TotDeathsByAgeP[2][0] +
			TotDeathsByAgeP[3][0] + TotDeathsByAgeP[4][0];
		ChildMortBy5yr[iy][1][1] = TotDeathsByAgeP[1][1] + TotDeathsByAgeP[2][1] +
			TotDeathsByAgeP[3][1] + TotDeathsByAgeP[4][1];
		ChildMortBy5yr[iy][2][0] = TotDeathsByAgeP[5][0] + TotDeathsByAgeP[6][0] +
			TotDeathsByAgeP[7][0] + TotDeathsByAgeP[8][0] + TotDeathsByAgeP[9][0];
		ChildMortBy5yr[iy][2][1] = TotDeathsByAgeP[5][1] + TotDeathsByAgeP[6][1] +
			TotDeathsByAgeP[7][1] + TotDeathsByAgeP[8][1] + TotDeathsByAgeP[9][1];
		ChildMortBy5yr[iy][3][0] = 0.0;
		ChildMortBy5yr[iy][3][1] = 0.0;
		for (ia = 0; ia < 5; ia++){
			ChildMortBy5yr[iy][3][0] += AIDSdeathsByAge[ia][0] + NonAIDSdeathsA[ia][0];
			ChildMortBy5yr[iy][3][1] += AIDSdeathsByAge[ia][1] + NonAIDSdeathsA[ia][1];
		}
		Deaths0M.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][0][0];
		Deaths0F.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][0][1];
		Deaths1M.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][1][0];
		Deaths1F.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][1][1];
		Deaths5M.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][2][0];
		Deaths5F.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][2][1];
		Deaths10M.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][3][0];
		Deaths10F.out[CurrSim - 1][iy] = ChildMortBy5yr[iy][3][1];
	}
	if (FixedUncertainty == 1 || CalibChildPIP == 1){
		ChildAIDSmortDiag[iy][0] = AIDSdeathsDiagP[0];
		ChildAIDSmortDiag[iy][1] = AIDSdeathsDiagP[1];
		ChildAIDSmortART[iy][0] = AIDSdeathsART_P[0];
		ChildAIDSmortART[iy][1] = AIDSdeathsART_P[1];
		DiagDeaths1to4.out[CurrSim - 1][iy] = AIDSdeathsDiagP[0];
		DiagDeaths5to9.out[CurrSim - 1][iy] = AIDSdeathsDiagP[1];
		ARTdeaths1to4.out[CurrSim - 1][iy] = AIDSdeathsART_P[0];
		ARTdeaths5to9.out[CurrSim - 1][iy] = AIDSdeathsART_P[1];
		Temp[0] = ChildMortBy5yr[iy][1][0] + ChildMortBy5yr[iy][1][1] - AIDSdeathsDiagP[0];
		Temp[1] = ((AIDSdeathsDiagP[0] - AIDSdeathsART_P[0]) / RRdiagDeathsPIP[0]) +
			AIDSdeathsART_P[0] / (RRdiagDeathsPIP[0] * RRdiagDeathsPIP[1]);
		DeathsDiagPos1to4.out[CurrSim - 1][iy] = Temp[1] / (Temp[0] + Temp[1]);
		Temp[0] = ChildMortBy5yr[iy][2][0] + ChildMortBy5yr[iy][2][1] - AIDSdeathsDiagP[1];
		Temp[1] = ((AIDSdeathsDiagP[0] - AIDSdeathsART_P[0]) / RRdiagDeathsPIP[0]) +
			AIDSdeathsART_P[1] / (RRdiagDeathsPIP[0] * RRdiagDeathsPIP[1]);
		DeathsDiagPos5to9.out[CurrSim - 1][iy] = Temp[1] / (Temp[0] + Temp[1]);
	}

	NewART_P = 0.0;
	for (ia = 0; ia < 15; ia++){ NewART_P += PaedNewARTbyAge[ia]; }
	StartingART0to14.out[CurrSim - 1][iy] = NewART_P;

	// Fraction of infections acquired recently
	if (CalibANCprev == 1 || CalibYouthPrev){
		for (ia = 0; ia < 6; ia++){
			FractionRecentF[ia][CurrYear - StartYear + 1] = 0.0;
			for (ii = 0; ii < 5; ii++){
				FractionRecentF[ia][CurrYear - StartYear + 1] += NewHIVbyAgeSex[4 + ia * 5 + ii][1];
				// Note we use 4+, not 5+, because we haven't yet updated ages.
			}
		}
	}

	// New ART by baseline CD4 count
	if (FixedUncertainty == 1 || CalibCD4atARTstart == 1){
		NewARTunder200.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[3][0] + AdultsNewARTbyCD4[3][1];
		NewART200to349.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[2][0] + AdultsNewARTbyCD4[2][1];
		NewART350to499.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[1][0] + AdultsNewARTbyCD4[1][1];
		NewARTover500.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[0][0] + AdultsNewARTbyCD4[0][1];
		NewARTunder200F.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[3][1];
		NewART200to349F.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[2][1];
		NewART350to499F.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[1][1];
		NewARTover500F.out[CurrSim - 1][iy] = AdultsNewARTbyCD4[0][1];
		ReinitARTunder200.out[CurrSim - 1][iy] = AdultsReinitARTbyCD4[3][0] + AdultsReinitARTbyCD4[3][1];
		AdultsRestartingART.out[CurrSim - 1][iy] = AdultsReinitARTbyCD4[0][0] + AdultsReinitARTbyCD4[0][1] +
			AdultsReinitARTbyCD4[1][0] + AdultsReinitARTbyCD4[1][1] +
			AdultsReinitARTbyCD4[2][0] + AdultsReinitARTbyCD4[2][1] +
			AdultsReinitARTbyCD4[3][0] + AdultsReinitARTbyCD4[3][1];
		RestartARTchild.out[CurrSim - 1][iy] += ChildReinitARTearly + ChildReinitARTlate;
		RestartARTpaedAdvanced.out[CurrSim - 1][iy] += ChildReinitARTlate;
	}

	// Generate outputs not required for calculating likelihood
	if (FixedUncertainty == 1){
		// Mortality outputs
		Deaths15M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][0][0];
		Deaths20M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][1][0];
		Deaths25M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][2][0];
		Deaths30M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][3][0];
		Deaths35M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][4][0];
		Deaths40M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][5][0];
		Deaths45M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][6][0];
		Deaths50M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][7][0];
		Deaths55M.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][8][0];
		Deaths15F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][0][1];
		Deaths20F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][1][1];
		Deaths25F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][2][1];
		Deaths30F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][3][1];
		Deaths35F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][4][1];
		Deaths40F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][5][1];
		Deaths45F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][6][1];
		Deaths50F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][7][1];
		Deaths55F.out[CurrSim - 1][iy] = AdultMortBy5yr[iy][8][1];
		NonAIDSdeaths15M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][0][0];
		NonAIDSdeaths20M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][1][0];
		NonAIDSdeaths25M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][2][0];
		NonAIDSdeaths30M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][3][0];
		NonAIDSdeaths35M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][4][0];
		NonAIDSdeaths40M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][5][0];
		NonAIDSdeaths45M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][6][0];
		NonAIDSdeaths50M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][7][0];
		NonAIDSdeaths55M.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][8][0];
		NonAIDSdeaths15F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][0][1];
		NonAIDSdeaths20F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][1][1];
		NonAIDSdeaths25F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][2][1];
		NonAIDSdeaths30F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][3][1];
		NonAIDSdeaths35F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][4][1];
		NonAIDSdeaths40F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][5][1];
		NonAIDSdeaths45F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][6][1];
		NonAIDSdeaths50F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][7][1];
		NonAIDSdeaths55F.out[CurrSim - 1][iy] = NonAIDSmortBy5yr[iy][8][1];
		AIDSdeathsPaed.out[CurrSim - 1][iy] = 0.0;
		AIDSdeathsBoys.out[CurrSim - 1][iy] = 0.0;
		AIDSdeathsGirls.out[CurrSim - 1][iy] = 0.0;
		for (ii = 0; ii <= 10; ii++){
			AIDSdeathsPaed.out[CurrSim - 1][iy] += AIDSdeathsByAgeP[ii][0] +
				AIDSdeathsByAgeP[ii][1];
			AIDSdeathsBoys.out[CurrSim - 1][iy] += AIDSdeathsByAgeP[ii][0];
			AIDSdeathsGirls.out[CurrSim - 1][iy] += AIDSdeathsByAgeP[ii][1];
			if (ii == 0){ AIDSdeaths0.out[CurrSim - 1][iy] = AIDSdeathsPaed.out[CurrSim - 1][iy]; }
			if (ii == 4){ AIDSdeaths1to4.out[CurrSim - 1][iy] = AIDSdeathsPaed.out[CurrSim - 1][iy] - 
				AIDSdeaths0.out[CurrSim - 1][iy]; }
			if (ii == 9){
				AIDSdeaths5to9.out[CurrSim - 1][iy] = AIDSdeathsPaed.out[CurrSim - 1][iy] -
					AIDSdeaths0.out[CurrSim - 1][iy] - AIDSdeaths1to4.out[CurrSim - 1][iy];
			}
		}
		for (ii = 10; ii < 15; ii++){
			AIDSdeathsPaed.out[CurrSim - 1][iy] += AIDSdeathsByAge[ii - 10][0] +
				AIDSdeathsByAge[ii - 10][1];
			AIDSdeathsBoys.out[CurrSim - 1][iy] += AIDSdeathsByAge[ii - 10][0];
			AIDSdeathsGirls.out[CurrSim - 1][iy] += AIDSdeathsByAge[ii - 10][1];
			if (ii == 14){
				AIDSdeaths10to14.out[CurrSim - 1][iy] = AIDSdeathsPaed.out[CurrSim - 1][iy] -
					AIDSdeaths0.out[CurrSim - 1][iy] - AIDSdeaths1to4.out[CurrSim - 1][iy] - 
					AIDSdeaths5to9.out[CurrSim - 1][iy];
			}
		}
		AIDSdeaths20to59M.out[CurrSim - 1][iy] = AIDSdeathsByAge[10][0];
		for (ii = 1; ii < 40; ii++){
			AIDSdeaths20to59M.out[CurrSim - 1][iy] += AIDSdeathsByAge[10 + ii][0];
		}
		AIDSdeaths20to59F.out[CurrSim - 1][iy] = AIDSdeathsByAge[10][1];
		for (ii = 1; ii < 40; ii++){
			AIDSdeaths20to59F.out[CurrSim - 1][iy] += AIDSdeathsByAge[10 + ii][1];
		}
		AIDSdeathsAdultM.out[CurrSim - 1][iy] = AIDSdeaths20to59M.out[CurrSim - 1][iy];
		AIDSdeathsAdultF.out[CurrSim - 1][iy] = AIDSdeaths20to59F.out[CurrSim - 1][iy];
		for (ii = 0; ii < 5; ii++){
			AIDSdeathsAdultM.out[CurrSim - 1][iy] += AIDSdeathsByAge[5 + ii][0];
			AIDSdeathsAdultF.out[CurrSim - 1][iy] += AIDSdeathsByAge[5 + ii][1];
		}
		for (ii = 45; ii < 76; ii++){
			AIDSdeathsAdultM.out[CurrSim - 1][iy] += AIDSdeathsByAge[5 + ii][0];
			AIDSdeathsAdultF.out[CurrSim - 1][iy] += AIDSdeathsByAge[5 + ii][1];
		}
		AIDSdeathsTot.out[CurrSim - 1][iy] = AIDSdeathsPaed.out[CurrSim - 1][iy] + 
			AIDSdeathsAdultM.out[CurrSim - 1][iy] + AIDSdeathsAdultF.out[CurrSim - 1][iy];
		Temp[0] = 0.0;
		Temp[1] = 0.0;
		for (ii = 5; ii < 15; ii++){
			Temp[0] += AIDSdeathsByAge[ii][0];
			Temp[1] += AIDSdeathsByAge[ii][1];
		}
		AIDSdeaths15to24M.out[CurrSim - 1][iy] = Temp[0];
		AIDSdeaths15to24F.out[CurrSim - 1][iy] = Temp[1];
		AIDSdeaths15to24.out[CurrSim - 1][iy] = Temp[0] + Temp[1];
		Temp[0] = 0.0;
		Temp[1] = 0.0;
		for (ii = 15; ii < 40; ii++){
			Temp[0] += AIDSdeathsByAge[ii][0];
			Temp[1] += AIDSdeathsByAge[ii][1];
		}
		AIDSdeaths25to49M.out[CurrSim - 1][iy] = Temp[0];
		AIDSdeaths25to49F.out[CurrSim - 1][iy] = Temp[1];
		AIDSdeaths25to49.out[CurrSim - 1][iy] = Temp[0] + Temp[1];
		AIDSdeaths15to49M.out[CurrSim - 1][iy] = Temp[0] + AIDSdeaths15to24M.out[CurrSim - 1][iy];
		AIDSdeaths15to49F.out[CurrSim - 1][iy] = Temp[1] + AIDSdeaths15to24F.out[CurrSim - 1][iy];
		AIDSdeaths15to49.out[CurrSim - 1][iy] = Temp[0] + Temp[1] + AIDSdeaths15to24.out[CurrSim - 1][iy];
		Temp[0] = 0.0;
		Temp[1] = 0.0;
		for (ii = 40; ii < 81; ii++){
			Temp[0] += AIDSdeathsByAge[ii][0];
			Temp[1] += AIDSdeathsByAge[ii][1];
		}
		AIDSdeaths50plusM.out[CurrSim - 1][iy] = Temp[0];
		AIDSdeaths50plusF.out[CurrSim - 1][iy] = Temp[1];
		AIDSdeaths50plus.out[CurrSim - 1][iy] = Temp[0] + Temp[1];
		CrudeAIDSmort.out[CurrSim - 1][iy] = 100000 * AIDSdeathsTot.out[CurrSim - 1][iy] /
			TotPop.out[CurrSim - 1][iy];
		if (CurrYear == 2005){
			for (ia = 2; ia < 10; ia++){
				for (ig = 0; ig < 2; ig++){
					Temp[ig] = 0.0;
					for (ii = 0; ii < 5; ii++){
						Temp[ig] += NonAIDSdeathsA[ia * 5 + ii][ig];
					}
				}
				NonAIDSdeaths2005.out[CurrSim - 1][ia - 2] = Temp[0];
				NonAIDSdeaths2005.out[CurrSim - 1][ia + 6] = Temp[1];
			}
		}
		// Additional mortality outputs for Investment Case
		NonAIDSdeaths.out[CurrSim - 1][iy] = 0.0;
		TotDeathsM.out[CurrSim - 1][iy] = 0.0;
		TotDeathsF.out[CurrSim - 1][iy] = 0.0;
		for (ii = 0; ii <= 10; ii++){
			NonAIDSdeaths.out[CurrSim - 1][iy] += NonAIDSdeathsP[ii][0] +
				NonAIDSdeathsP[ii][1];
			TotDeathsM.out[CurrSim - 1][iy] += NonAIDSdeathsP[ii][0];
			TotDeathsF.out[CurrSim - 1][iy] += NonAIDSdeathsP[ii][1];
		}
		for (ii = 0; ii < 81; ii++){
			NonAIDSdeaths.out[CurrSim - 1][iy] += NonAIDSdeathsA[ii][0] +
				NonAIDSdeathsA[ii][1];
			TotDeathsM.out[CurrSim - 1][iy] += NonAIDSdeathsA[ii][0];
			TotDeathsF.out[CurrSim - 1][iy] += NonAIDSdeathsA[ii][1];
		}
		TotDeathsM.out[CurrSim - 1][iy] += AIDSdeathsBoys.out[CurrSim - 1][iy] +
			AIDSdeathsAdultM.out[CurrSim - 1][iy];
		TotDeathsF.out[CurrSim - 1][iy] += AIDSdeathsGirls.out[CurrSim - 1][iy] +
			AIDSdeathsAdultF.out[CurrSim - 1][iy];
		LYlostAIDS.out[CurrSim - 1][iy] = 0.0;
		for (ii = 0; ii <= 10; ii++){
			LYlostAIDS.out[CurrSim - 1][iy] += AIDSdeathsByAgeP[ii][0] * WestLifeExpectP[ii][0] +
				AIDSdeathsByAgeP[ii][1] * WestLifeExpectP[ii][1];
		}
		for (ii = 0; ii < 81; ii++){
			LYlostAIDS.out[CurrSim - 1][iy] += AIDSdeathsByAge[ii][0] * WestLifeExpectA[ii][0] +
				AIDSdeathsByAge[ii][1] * WestLifeExpectA[ii][1];
			if (ii == 4){ LYlostAIDSpaed.out[CurrSim - 1][iy] = LYlostAIDS.out[CurrSim - 1][iy]; }
		}
		DALY_HIV.out[CurrSim - 1][iy] = LYlostAIDS.out[CurrSim - 1][iy] + YLD_HIV.out[CurrSim - 1][iy];
		DALY_HIVpaed.out[CurrSim - 1][iy] = LYlostAIDSpaed.out[CurrSim - 1][iy] + YLD_HIVpaed.out[CurrSim - 1][iy];

		// Mortality probabilities by exact age
		for (ia = 0; ia < 10; ia++){
			for (ig = 0; ig < 2; ig++){
				MortProbExact[ia][ig] = 1.0 - exp(-TotDeathsByAgeP[ia][ig] / (0.5 *
					(TotalPop_S[ia][ig] + TotalPop[ia][ig])));
			}
		}
		for (ig = 0; ig < 2; ig++){
			MortProbExact[10][ig] = 1.0 - exp(-(TotDeathsByAgeP[10][ig] + 0.5 *
				TotDeathsByAge[0][ig]) / (0.5 * (TotalPop_S[10][ig] + TotalPop[10][ig])));
		}
		for (ia = 11; ia < 90; ia++){
			for (ig = 0; ig < 2; ig++){
				MortProbExact[ia][ig] = 0.5 * ((TotDeathsByAge[ia - 11][ig] /
					TotalPop_S[ia - 1][ig]) + (TotDeathsByAge[ia - 10][ig] / TotalPop_S[ia][ig]));
			}
		}
		for (ig = 0; ig < 2; ig++){
			MortProbExact[90][ig] = 1.0 - exp(-(TotDeathsByAge[80][ig] + 0.5 *
				TotDeathsByAge[79][ig]) / (0.5 * (TotalPop_S[90][ig] + TotalPop[89][ig] +
				TotalPop[90][ig])));
		}
		for (ia = 0; ia < 91; ia++){
			MaleMortAS.out[ia][iy] += MortProbExact[ia][0];
			FemMortAS.out[ia][iy] += MortProbExact[ia][1];
		}

		// Life tables
		for (ig = 0; ig < 2; ig++){
			LifeTable[0][ig] = 1.0;
			for (ia = 1; ia < 91; ia++){
				LifeTable[ia][ig] = LifeTable[ia - 1][ig] * (1.0 - MortProbExact[ia - 1][ig]);
			}
		}

		// Mortality indicators
		IMR.out[CurrSim - 1][iy] = 1000.0 * (SexRatio * MortProbExact[0][0] +
			(1.0 - SexRatio) * MortProbExact[0][1]);
		U5MR.out[CurrSim - 1][iy] = 1000.0 * (1.0 - SexRatio * LifeTable[5][0] -
			(1.0 - SexRatio) * LifeTable[5][1]);
		M45q15.out[CurrSim - 1][iy] = 1.0 - (LifeTable[60][0] / LifeTable[15][0]);
		F45q15.out[CurrSim - 1][iy] = 1.0 - (LifeTable[60][1] / LifeTable[15][1]);
		Tot45q15.out[CurrSim - 1][iy] = 0.5 * (M45q15.out[CurrSim - 1][iy] + F45q15.out[CurrSim - 1][iy]);
		for (ig = 0; ig < 2; ig++){
			Temp[ig] = 0.3 + 1.2 * LifeTable[1][ig];
			for (ia = 2; ia < 90; ia++){
				Temp[ig] += LifeTable[ia][ig];
			}
			Temp[ig] += 0.5 * LifeTable[90][ig];
			Temp[ig] += LifeTable[90][ig] / (-log(1.0 - MortProbExact[90][ig]));
		}
		LifeExpectM.out[CurrSim - 1][iy] = Temp[0];
		LifeExpectF.out[CurrSim - 1][iy] = Temp[1];
		LifeExpectTot.out[CurrSim - 1][iy] = Temp[0] * SexRatio + Temp[1] * (1.0 - SexRatio);

		// ART/disease stage outputs
		StartingART15to24M.out[CurrSim - 1][iy] = AdultsNewARTbyAge[0][0];
		StartingART25to34M.out[CurrSim - 1][iy] = AdultsNewARTbyAge[1][0];
		StartingART35to44M.out[CurrSim - 1][iy] = AdultsNewARTbyAge[2][0];
		StartingART45M.out[CurrSim - 1][iy] = AdultsNewARTbyAge[3][0];
		StartingART15to24F.out[CurrSim - 1][iy] = AdultsNewARTbyAge[0][1];
		StartingART25to34F.out[CurrSim - 1][iy] = AdultsNewARTbyAge[1][1];
		StartingART35to44F.out[CurrSim - 1][iy] = AdultsNewARTbyAge[2][1];
		StartingART45F.out[CurrSim - 1][iy] = AdultsNewARTbyAge[3][1];
		StartingARTtot.out[CurrSim - 1][iy] = StartingART0to14.out[CurrSim - 1][iy];
		StartingART_M15.out[CurrSim - 1][iy] = 0.0;
		StartingART_F15.out[CurrSim - 1][iy] = 0.0;
		for (ia = 0; ia < 4; ia++){
			StartingART_M15.out[CurrSim - 1][iy] += AdultsNewARTbyAge[ia][0];
			StartingART_F15.out[CurrSim - 1][iy] += AdultsNewARTbyAge[ia][1];
			for (ig = 0; ig < 2; ig++){
				StartingARTtot.out[CurrSim - 1][iy] += AdultsNewARTbyAge[ia][ig];
			}
		}
		TotNewNeed15M.out[CurrSim - 1][iy] = NewElig350[0];
		TotNewNeed15F.out[CurrSim - 1][iy] = NewElig350[1];

		// Additional ART outputs for Investment Case
		StartingART1to2.out[CurrSim - 1][iy] = PaedNewARTbyAge[1] + PaedNewARTbyAge[2];
		StartingART3to5.out[CurrSim - 1][iy] = PaedNewARTbyAge[3] + PaedNewARTbyAge[4] + PaedNewARTbyAge[5];
		StartingART6to13.out[CurrSim - 1][iy] = 0.0;
		StartingART6to9.out[CurrSim - 1][iy] = 0.0;  //LJ
		StartingART10to14.out[CurrSim - 1][iy] = 0.0;//LJ
		for (ia = 6; ia < 14; ia++){
			StartingART6to13.out[CurrSim - 1][iy] += PaedNewARTbyAge[ia];
			if (ia >= 6 && ia <= 9) {
				StartingART6to9.out[CurrSim - 1][iy] += PaedNewARTbyAge[ia]; //LJ
			}
			if (ia >= 10 && ia <= 14) {
				StartingART10to14.out[CurrSim - 1][iy] += PaedNewARTbyAge[ia];//LJ
			}
		}
		TotNewNeed500M.out[CurrSim - 1][iy] = NewElig500[0];
		TotNewNeed500F.out[CurrSim - 1][iy] = NewElig500[1];
	}

	if (FixedUncertainty == 1 || CalibHCTprevP == 1 || CalibHCTtotP == 1 || CalibHCTageSex == 1){
		// HIV testing outputs
		TotalHIVtests.out[CurrSim-1][iy] = NewlyTestedNeg[0] + NewlyTestedNeg[1] +
			NewlyTestedPos[0] + NewlyTestedPos[1];

		TotalHIVtests15_19.out[CurrSim - 1][iy] = NewlyTestedNeg15_19 + NewlyTestedPos15_19; //LJ
		TotalHIVtestsNeg15_19.out[CurrSim - 1][iy] = NewlyTestedNeg15_19;  //LJ
		TotalHIVtestsPos15_19.out[CurrSim - 1][iy] = NewlyTestedPos15_19;  //LJ
		TotalHIVtestsPrEP.out[CurrSim - 1][iy] = NewlyTestedNeg_PrEP[0] + NewlyTestedNeg_PrEP[1]; //LJ
		HIVtestsPosNoPrEP.out[CurrSim - 1][iy] = (NewlyTestedPos[0] + NewlyTestedPos[1]) / //this is to separate out PrEP HCT to use in costs later (because our PrEP cost accounts for tests)
			(TotalHIVtests.out[CurrSim - 1][iy] - TotalHIVtestsPrEP.out[CurrSim - 1][iy]); // LJ



		if (CurrYear > 1990){
			HIVtestsPos.out[CurrSim - 1][iy] = (NewlyTestedPos[0] + NewlyTestedPos[1] + (NewlyTestedNeg[0] +
				NewlyTestedNeg[1]) * (1.0 - RapidDiagSp)) / TotalHIVtests.out[CurrSim - 1][iy];
		}
		FirstHIVtestsPos.out[CurrSim - 1][iy] = (NewlyTested1stPos[0] + NewlyTested1stPos[1]) /
			(NewlyTestedPos[0] + NewlyTestedPos[1]);
		TotalHIVtestsU15.out[CurrSim - 1][iy] = NewlyTestedNeg[2] + NewlyTestedPos[2];
		TotalHIVtests15to24M.out[CurrSim - 1][iy] = NewlyTestedAdult[0][0];
		TotalHIVtests15to24F.out[CurrSim - 1][iy] = NewlyTestedAdult[0][1];
		TotalHIVtests25to49M.out[CurrSim - 1][iy] = NewlyTestedAdult[1][0];
		TotalHIVtests25to49F.out[CurrSim - 1][iy] = NewlyTestedAdult[1][1];
		TotalHIVtests50plusM.out[CurrSim - 1][iy] = NewlyTestedAdult[2][0];
		TotalHIVtests50plusF.out[CurrSim - 1][iy] = NewlyTestedAdult[2][1];
		PregTests15to24.out[CurrSim - 1][iy] = ANCtestsByAge[0][0] + ANCtestsByAge[0][1];
		PregTests25to49.out[CurrSim - 1][iy] = ANCtestsByAge[1][0] + ANCtestsByAge[1][1];
		PosHIVtests15to24M.out[CurrSim - 1][iy] = PosTestedAdult[0][0];
		PosHIVtests15to24F.out[CurrSim - 1][iy] = PosTestedAdult[0][1];
		PosHIVtests25to49M.out[CurrSim - 1][iy] = PosTestedAdult[1][0];
		PosHIVtests25to49F.out[CurrSim - 1][iy] = PosTestedAdult[1][1];
		PosHIVtests50plusM.out[CurrSim - 1][iy] = PosTestedAdult[2][0];
		PosHIVtests50plusF.out[CurrSim - 1][iy] = PosTestedAdult[2][1];
		PregDiag15to24.out[CurrSim - 1][iy] = ANCtestsByAge[0][1];
		PregDiag25to49.out[CurrSim - 1][iy] = ANCtestsByAge[1][1];
		if (iy >= 35 && iy < 39){
			ModelTestsAgeSex[0][iy - 35] = NewlyTestedAdult[0][0];
			ModelTestsAgeSex[1][iy - 35] = NewlyTestedAdult[0][1] - ANCtestsByAge[0][0] - ANCtestsByAge[0][1];
			ModelTestsAgeSex[2][iy - 35] = NewlyTestedAdult[1][0] + NewlyTestedAdult[1][1] -
				ANCtestsByAge[1][0] - ANCtestsByAge[1][1];
			ModelTestsAgeSex[3][iy - 35] = NewlyTestedAdult[2][0] + NewlyTestedAdult[2][1];
			ModelTestsAgeSex[4][iy - 35] = ANCtestsByAge[0][0] + ANCtestsByAge[0][1] + ANCtestsByAge[1][0] +
				ANCtestsByAge[1][1];
			ModelPosTestsAgeSex[0][iy - 35] = PosTestedAdult[0][0];
			ModelPosTestsAgeSex[1][iy - 35] = PosTestedAdult[0][1] - ANCtestsByAge[0][1];
			ModelPosTestsAgeSex[2][iy - 35] = PosTestedAdult[1][0] + PosTestedAdult[1][1] - ANCtestsByAge[1][1];
			ModelPosTestsAgeSex[3][iy - 35] = PosTestedAdult[2][0] + PosTestedAdult[2][1];
			ModelPosTestsAgeSex[4][iy - 35] = ANCtestsByAge[0][1] + ANCtestsByAge[1][1];
		}
		if (CurrYear > 1990){
			HIVtestsPosU15.out[CurrSim - 1][iy] = (NewlyTestedPos[2] + NewlyTestedNeg[2] * (1.0 - RapidDiagSp)) /
				TotalHIVtestsU15.out[CurrSim - 1][iy];
		}
		HIVtestsPos18mo.out[CurrSim - 1][iy] = (NewlyTestedPaed[0][1] + NewlyTestedPaed[0][0] * (1.0 - RapidDiagSp)) /
			(NewlyTestedPaed[0][1] + NewlyTestedPaed[0][0]);
		HIVtestsPos19to59mo.out[CurrSim - 1][iy] = (NewlyTestedPaed[1][1] + NewlyTestedPaed[1][0] * (1.0 - RapidDiagSp)) /
			(NewlyTestedPaed[1][1] + NewlyTestedPaed[1][0]);
		HIVtestsPos5to14.out[CurrSim - 1][iy] = (NewlyTestedPaed[2][1] + NewlyTestedPaed[2][0] * (1.0 - RapidDiagSp)) /
			(NewlyTestedPaed[2][1] + NewlyTestedPaed[2][0]);
		FalseNegPropn.out[CurrSim - 1][iy] = (NewlyTestedFalseNeg[0] + NewlyTestedFalseNeg[1]) / 
			(NewlyTestedPos[0] + NewlyTestedPos[1] + NewlyTestedFalseNeg[0] + NewlyTestedFalseNeg[1]);
	}

	// Self-testing outputs
	if (FixedUncertainty == 1){
		TotSTestFixedPoint.out[CurrSim - 1][iy] = NewlyTestedNegST[0] + NewlyTestedPosST[0];
		TotSTestTaxi.out[CurrSim - 1][iy] = NewlyTestedNegST[1] + NewlyTestedPosST[1];
		TotSTestANC.out[CurrSim - 1][iy] = NewlyTestedNegST[2] + NewlyTestedPosST[2];
		TotSTestIndex.out[CurrSim - 1][iy] = NewlyTestedNegST[3] + NewlyTestedPosST[3];
		TotSTestWork1.out[CurrSim - 1][iy] = NewlyTestedNegST[4] + NewlyTestedPosST[4];
		TotSTestWork2.out[CurrSim - 1][iy] = NewlyTestedNegST[5] + NewlyTestedPosST[5];
		PosSTestFixedPoint.out[CurrSim - 1][iy] = NewlyTestedPosST[0];
		PosSTestTaxi.out[CurrSim - 1][iy] = NewlyTestedPosST[1];
		PosSTestANC.out[CurrSim - 1][iy] = NewlyTestedPosST[2];
		PosSTestIndex.out[CurrSim - 1][iy] = NewlyTestedPosST[3];
		PosSTestWork1.out[CurrSim - 1][iy] = NewlyTestedPosST[4];
		PosSTestWork2.out[CurrSim - 1][iy] = NewlyTestedPosST[5];
		STtoARTfixedPoint.out[CurrSim - 1][iy] = NewSTtoART[0];
		STtoARTtaxi.out[CurrSim - 1][iy] = NewSTtoART[1];
		STtoART_ANC.out[CurrSim - 1][iy] = NewSTtoART[2];
		STtoARTindex.out[CurrSim - 1][iy] = NewSTtoART[3];
		STtoARTwork1.out[CurrSim - 1][iy] = NewSTtoART[4];
		STtoARTwork2.out[CurrSim - 1][iy] = NewSTtoART[5];
	}

	if (FixedUncertainty == 1 || CalibARTbyAgeP == 1 || CalibAHDpaedART == 1){
		// Paediatric ART initiation
		StartingART0.out[CurrSim - 1][iy] = PaedNewARTbyAge[0];
		StartingART1.out[CurrSim - 1][iy] = PaedNewARTbyAge[1];
		StartingART2to4.out[CurrSim - 1][iy] = PaedNewARTbyAge[2] + PaedNewARTbyAge[3] + PaedNewARTbyAge[4];
		StartingART5to14.out[CurrSim - 1][iy] = 0.0;
		for (ia = 5; ia < 15; ia++){
			StartingART5to14.out[CurrSim - 1][iy] += PaedNewARTbyAge[ia];
		}
		Temp[0] = 0.0;
		Temp[1] = 0.0;
		for (ia = 0; ia < 11; ia++){ Temp[0] += PaedNewARTlate[ia]; }
		for (ia = 0; ia < 5; ia++){ Temp[1] += SumGroupsM[ia][35] + SumGroupsF[ia][35]; }
		NewARTpaedAdvanced.out[CurrSim - 1][iy] = Temp[0] + Temp[1];
		// The Temp[1] term is not strictly correct because it's net of mortality among ART initiators.
		if (CurrYear >= 2020 && CurrYear <= 2023){
			ModelAHDpaedART[iy - 35] = (Temp[0] + Temp[1]) / NewART_P; }
	}

	// Cumulative paed ART initiation
	for (ia = 10; ia > 0; ia--){
		CumPaedARTearly[ia][4] = CumPaedARTearly[ia - 1][4] + CumPaedARTearly[ia - 1][3];
		CumPaedARTlate[ia][4] = CumPaedARTlate[ia - 1][4] + CumPaedARTlate[ia - 1][3];
		for (ii = 3; ii > 0; ii--){
			CumPaedARTearly[ia][ii] = CumPaedARTearly[ia - 1][ii - 1];
			CumPaedARTlate[ia][ii] = CumPaedARTlate[ia - 1][ii - 1];
		}
		// In the next few lines, average across ages ia and ia-1 because the PaedNewART arrays
		// are defined by age at ART start, and age at end of year will be on average 6 mo older
		CumPaedARTearly[ia][0] = 0.5 *(PaedNewARTbyAge[ia - 1] - PaedNewARTlate[ia - 1] +
			PaedNewARTbyAge[ia] - PaedNewARTlate[ia]);
		CumPaedARTlate[ia][0] = 0.5 * (PaedNewARTlate[ia - 1] + PaedNewARTlate[ia]);
	}
	CumPaedARTearly[0][0] = 0.5 *(PaedNewARTbyAge[0] - PaedNewARTlate[0]);
	CumPaedARTlate[0][0] = 0.5 * PaedNewARTlate[0];
}

void ResultsAtEndOfYr2()
{
	int ia, iy, ii;
	double Temp1, Temp2, Temp3, Temp4, Temp5, Temp6, IncAdj[2];

	iy = CurrYear - StartYear;

	// AIDS deaths on ART
	AIDSdeathsART.out[CurrSim - 1][iy] = AIDSdeathsOnART;

	// TFR, total births, births to mothers previously on ART
	Temp1 = 0.0;
	for (ia = 0; ia < 36; ia++){
		Temp1 += TotBirthsByMatAge[ia] / (0.5 *(TotalPop[ia + 15][1] + TotalPop_S[ia + 14][1]));}
	TotFertRate.out[CurrSim - 1][iy] = Temp1;
	TotBirths.out[CurrSim - 1][iy] = BirthsPosMothers + BirthsNegMothers;
	BirthRate.out[CurrSim - 1][iy] = 1000.0 * (BirthsPosMothers + BirthsNegMothers)/(TotPop.out[CurrSim - 1][iy] + 
		0.5 * (BirthsPosMothers + BirthsNegMothers - AIDSdeathsTot.out[CurrSim - 1][iy] -
		NonAIDSdeaths.out[CurrSim - 1][iy]));
	NeonatalMMCops.out[CurrSim - 1][iy] = TotBirths.out[CurrSim - 1][iy] * SexRatio * NeonatalMMC[iy];
	ARTpreConcep15.out[CurrSim - 1][iy] = AnyARTpreConcep[iy][0];
	ARTpreConcep20.out[CurrSim - 1][iy] = AnyARTpreConcep[iy][1];
	ARTpreConcep25.out[CurrSim - 1][iy] = AnyARTpreConcep[iy][2];
	ARTpreConcep30.out[CurrSim - 1][iy] = AnyARTpreConcep[iy][3];
	ARTpreConcep35.out[CurrSim - 1][iy] = AnyARTpreConcep[iy][4];
	EverARTpreConcep.out[CurrSim - 1][iy] = AnyARTpreConcep[iy][5];

	// HIV incidence in children
	NewMTCT.out[CurrSim - 1][iy] = NewPerinatal + NewPostnatal;
	NewHIVatBirth.out[CurrSim-1][iy] = NewPerinatal;
	NewHIVatBirthART.out[CurrSim - 1][iy] = NewPerinatalART;
	NewHIVatBirthNoKOS.out[CurrSim - 1][iy] = NewPerinatalNoKOS;
	NewHIVafterBirth.out[CurrSim-1][iy] = NewPostnatal;
	NewHIVafterBirthART.out[CurrSim - 1][iy] = NewPostnatalART;
	NewHIVafterBirthNoKOS.out[CurrSim - 1][iy] = NewPostnatalNoKOS;
	NewHIVto18mo.out[CurrSim - 1][iy] = NewPostnatal18;
	NewHIVinANCandBF.out[CurrSim - 1][iy] = NewHIVinANC + NewHIVlactating;
	NewHIVmothersBF.out[CurrSim - 1][iy] = NewHIVlactating;
	TotBirthsHIV.out[CurrSim-1][iy] = BirthsPosMothers;
	TotBirthsART.out[CurrSim-1][iy] = BirthsARTmothers;
	TotBirthDiagnosed.out[CurrSim - 1][iy] = BirthsDiagMothers;
	MTCTrateAtBirth.out[CurrSim - 1][iy] = NewPerinatal/BirthsPosMothers;
	if (BirthsDiagMothers > 0){
		MTCTrateBirthDiag.out[CurrSim - 1][iy] = (NewPerinatal - NewPerinatalNoKOS) / BirthsDiagMothers;
		MTCTrate18moDiag.out[CurrSim - 1][iy] = NewPostnatal18 / BirthsDiagMothers;
	}
	else{
		MTCTrateBirthDiag.out[CurrSim - 1][iy] = 0.0;
		MTCTrate18moDiag.out[CurrSim - 1][iy] = 0.0;
	}
	TotMTCTrate.out[CurrSim - 1][iy] = (NewPerinatal + NewPostnatal) / BirthsPosMothers;
	TotMTCTallBirths.out[CurrSim - 1][iy] = (NewPerinatal + NewPostnatal) / TotBirths.out[CurrSim - 1][iy];
	Temp1 = 0.0;
	Temp2 = 0.0;
	for (ia = 0; ia < 5; ia++){ Temp1 += NewHIVbyAgeSex[ia][0] + NewHIVbyAgeSex[ia][1]; }
	for (ia = 0; ia < 15; ia++){
		Temp2 += TotalPop_S[ia][0] + TotalPop_S[ia][1] - TotalPositive_S[ia][0] - TotalPositive_S[ia][1];}
	HIVinc0to14.out[CurrSim - 1][iy] = (NewPerinatal + NewPostnatal + Temp1) / Temp2;
	NewHIVU15.out[CurrSim - 1][iy] = NewPerinatal + NewPostnatal + Temp1;
	NewDiagAtBirth.out[CurrSim - 1][iy] = NewPCRdiagBirth;
	NewDiagInfants.out[CurrSim - 1][iy] = NewPCRdiagBirth + NewPCRdiag12mo;
	NewDiag1yrOlds.out[CurrSim - 1][iy] = NewPCRdiag24mo;

	// Age-specific incidence output table
	for (ia = 0; ia < 81; ia++){
		MaleIncAS.out[ia][iy] += NewHIVbyAgeSex[ia][0] / (TotalPop_S[ia + 10][0] - TotalPositive_S[ia + 10][0]);
		FemIncAS.out[ia][iy] += NewHIVbyAgeSex[ia][1] / (TotalPop_S[ia + 10][1] - TotalPositive_S[ia + 10][1]);
		NewHIVmen.out[ia][iy] += NewHIVbyAgeSex[ia][0];
		NewHIVwomen.out[ia][iy] += NewHIVbyAgeSex[ia][1];
	}

	// HIV incidence in 15 to 49 age group
	Temp1 = 0.0;
	Temp2 = 0.0;
	IncAdj[0] = 0.0;
	for(ia=5; ia<15; ia++){
		Temp1 += NewHIVbyAgeSex[ia][0];
		IncAdj[0] += NewHIVbyAgeSex[ia][0] * ((1.0 - exp(-HCTtoART_SE[ia][6][0] * 12.0)) /
			(HCTtoART_SE[ia][6][0] * 12.0) - exp(-HCTtoART_SE[ia][6][0] * 12.0));
		Temp2 += TotalPop_S[ia+10][0] - TotalPositive_S[ia+10][0];
	}
	HIVinc15to24M.out[CurrSim-1][iy] = Temp1/Temp2;
	NewHIV15to24M.out[CurrSim - 1][iy] = Temp1;
	Temp5 = Temp1;
	Temp6 = Temp2;
	for(ia=15; ia<40; ia++){
		Temp1 += NewHIVbyAgeSex[ia][0];
		IncAdj[0] += NewHIVbyAgeSex[ia][0] * ((1.0 - exp(-HCTtoART_SE[ia][6][0] * 12.0)) /
			(HCTtoART_SE[ia][6][0] * 12.0) - exp(-HCTtoART_SE[ia][6][0] * 12.0));
		Temp2 += TotalPop_S[ia+10][0] - TotalPositive_S[ia+10][0];
	}
	HIVinc15to49M.out[CurrSim-1][iy] = Temp1/Temp2;
	NewHIV15to49M.out[CurrSim - 1][iy] = Temp1;
	HIVinc25to49M.out[CurrSim-1][iy] = (Temp1 - Temp5)/(Temp2 - Temp6);
	NewHIV25to49M.out[CurrSim - 1][iy] = Temp1 - Temp5;
	Temp3 = 0.0;
	Temp4 = 0.0;
	IncAdj[1] = 0.0;
	for(ia=5; ia<15; ia++){
		Temp3 += NewHIVbyAgeSex[ia][1];
		IncAdj[1] += NewHIVbyAgeSex[ia][1] * ((1.0 - exp(-HCTtoART_SE[ia][6][1] * 12.0)) /
			(HCTtoART_SE[ia][6][1] * 12.0) - exp(-HCTtoART_SE[ia][6][1] * 12.0));
		Temp4 += TotalPop_S[ia+10][1] - TotalPositive_S[ia+10][1];
	}
	HIVinc15to24F.out[CurrSim-1][iy] = Temp3/Temp4;
	NewHIV15to24F.out[CurrSim - 1][iy] = Temp3;
	HIVinc15to24.out[CurrSim - 1][iy] = (Temp3 + Temp5) / (Temp4 + Temp6);
	NewHIV15to24.out[CurrSim - 1][iy] = Temp3 + Temp5;
	Temp5 = Temp3;
	Temp6 = Temp4;
	for(ia=15; ia<40; ia++){
		Temp3 += NewHIVbyAgeSex[ia][1];
		IncAdj[1] += NewHIVbyAgeSex[ia][1] * ((1.0 - exp(-HCTtoART_SE[ia][6][1] * 12.0)) /
			(HCTtoART_SE[ia][6][1] * 12.0) - exp(-HCTtoART_SE[ia][6][1] * 12.0));
		Temp4 += TotalPop_S[ia+10][1] - TotalPositive_S[ia+10][1];
	}
	HIVinc15to49F.out[CurrSim-1][iy] = Temp3/Temp4;
	NewHIV15to49F.out[CurrSim - 1][iy] = Temp3;
	HIVinc25to49F.out[CurrSim-1][iy] = (Temp3 - Temp5)/(Temp4 - Temp6);
	NewHIV25to49F.out[CurrSim - 1][iy] = Temp3 - Temp5;
	NewHIV25to49.out[CurrSim - 1][iy] = Temp3 - Temp5 + NewHIV25to49M.out[CurrSim - 1][iy];
	HIVinc25to49.out[CurrSim - 1][iy] = NewHIV25to49.out[CurrSim - 1][iy] / 
		(Neg25to49M.out[CurrSim - 1][iy] + Neg25to49F.out[CurrSim - 1][iy]);
	HIVinc15to49.out[CurrSim-1][iy] = (Temp1 + Temp3)/(Temp2 + Temp4);
	HIVinc15to49adj.out[CurrSim - 1][iy] = (Temp1 + Temp3 - IncAdj[0] - IncAdj[1]) / 
		(Temp2 + Temp4);
	NewHIV15to49.out[CurrSim - 1][iy] = Temp1 + Temp3;

	// Total new HIV and % of heterosexual transmission attributable to commercial sex
	for(ia=0; ia<5; ia++){
		Temp1 += NewHIVbyAgeSex[ia][0];
		Temp3 += NewHIVbyAgeSex[ia][1];
	}
	for(ia=40; ia<81; ia++){
		Temp1 += NewHIVbyAgeSex[ia][0];
		Temp3 += NewHIVbyAgeSex[ia][1];
	}
	TotalNewHIV.out[CurrSim-1][iy] = Temp1 + Temp3 + NewPerinatal + NewPostnatal;
	NewAdultHIV.out[CurrSim - 1][iy] = Temp1 + Temp3;
	NewHIV_M.out[CurrSim - 1][iy] = Temp1;
	NewHIV_F.out[CurrSim - 1][iy] = Temp3;
	TotNegPop.out[CurrSim - 1][iy] = TotPop.out[CurrSim - 1][iy] - TotalHIV.out[CurrSim - 1][iy];
	TotIncidence.out[CurrSim - 1][iy] = TotalNewHIV.out[CurrSim - 1][iy] / TotNegPop.out[CurrSim - 1][iy];
	NewHIVclients.out[CurrSim-1][iy] = NewHIVinClients;
	NewHIVclientsNotSW.out[CurrSim - 1][iy] = NewHIVinClientsNotFromSW;
	PAFforCSW.out[CurrSim-1][iy] = (NewHIVinFSW.out[CurrSim-1][iy] + NewHIVinClients)/
		(Temp1 + Temp3);

	// HIV incidence in 50+ age group (and 15+)
	Temp1 = 0.0;
	Temp2 = 0.0;
	for (ia = 40; ia<81; ia++){
		Temp1 += NewHIVbyAgeSex[ia][0];
		Temp2 += TotalPop_S[ia + 10][0] - TotalPositive_S[ia + 10][0];
	}
	HIVinc50M.out[CurrSim - 1][iy] = Temp1 / Temp2;
	NewHIV50M.out[CurrSim - 1][iy] = Temp1;
	NewHIV15M.out[CurrSim - 1][iy] = Temp1 + NewHIV15to49M.out[CurrSim - 1][iy];
	HIVinc15plusM.out[CurrSim - 1][iy] = NewHIV15M.out[CurrSim - 1][iy] /
		(MalesOver15.out[CurrSim - 1][iy] * (1.0 - Prev15plusM.out[CurrSim - 1][iy]));
	Temp3 = 0.0;
	Temp4 = 0.0;
	for (ia = 40; ia<81; ia++){
		Temp3 += NewHIVbyAgeSex[ia][1];
		Temp4 += TotalPop_S[ia + 10][1] - TotalPositive_S[ia + 10][1];
	}
	HIVinc50F.out[CurrSim - 1][iy] = Temp3 / Temp4;
	NewHIV50F.out[CurrSim - 1][iy] = Temp3;
	NewHIV15F.out[CurrSim - 1][iy] = Temp3 + NewHIV15to49F.out[CurrSim - 1][iy];
	HIVinc15plusF.out[CurrSim - 1][iy] = NewHIV15F.out[CurrSim - 1][iy] / 
		(FemalesOver15.out[CurrSim - 1][iy] * (1.0 - Prev15plusF.out[CurrSim - 1][iy]));
	HIVinc15plus.out[CurrSim - 1][iy] = (NewHIV15M.out[CurrSim - 1][iy] + NewHIV15F.out[CurrSim - 1][iy]) /
		(Neg15to49.out[CurrSim - 1][iy] + Neg50.out[CurrSim - 1][iy]);
	HIVinc50.out[CurrSim - 1][iy] = (Temp1 + Temp3) / (Temp2 + Temp4);
	NewHIV50.out[CurrSim - 1][iy] = Temp1 + Temp3;

	// HIV incidence in key populations
	HIVincFSW.out[CurrSim - 1][iy] = NewHIVinFSW.out[CurrSim - 1][iy] / NegFSW.out[CurrSim - 1][iy];
	HIVincClients.out[CurrSim - 1][iy] = (NewHIVclients.out[CurrSim - 1][iy] + NewHIVclientsNotSW.out[CurrSim - 1][iy]) / 
		NegClients1.out[CurrSim - 1][iy];
	NewHIVinMSM.out[CurrSim - 1][iy] = HIVincMSM.out[CurrSim - 1][iy] * (1.0 - PropnTGW) /
		(PropnTGW * RR_HIV_TGW + 1.0 - PropnTGW);
	NewHIVinTGW.out[CurrSim - 1][iy] = HIVincMSM.out[CurrSim - 1][iy] * PropnTGW * RR_HIV_TGW /
		(PropnTGW * RR_HIV_TGW + 1.0 - PropnTGW);
	HIVincMSM.out[CurrSim - 1][iy] = HIVincMSM.out[CurrSim - 1][iy] / NegMSM.out[CurrSim - 1][iy];
	HIVincMSM.out[CurrSim - 1][iy] *= 1.0 / (PropnTGW * RR_HIV_TGW + 1.0 - PropnTGW);
	HIVincTGW.out[CurrSim - 1][iy] = HIVincMSM.out[CurrSim - 1][iy] * RR_HIV_TGW;
	HIVincPWID.out[CurrSim - 1][iy] = NewHIVinPWID.out[CurrSim - 1][iy] / NegPWID.out[CurrSim - 1][iy];

	// Incidence:prevalence ratio
	IncPrevRatio.out[CurrSim - 1][iy] = TotalNewHIV.out[CurrSim - 1][iy] / TotalHIV.out[CurrSim - 1][iy];
	IncPrevRatioFtoM.out[CurrSim - 1][iy] = NewHIV15F.out[CurrSim - 1][iy] / TotHIV15M.out[CurrSim - 1][iy];
	IncPrevRatioMtoF.out[CurrSim - 1][iy] = NewHIV15M.out[CurrSim - 1][iy] / TotHIV15F.out[CurrSim - 1][iy];

	// HIV incidence by age in 2000 and 2010
	if(CurrYear==2000 || CurrYear==2010){
		for(ia=1; ia<10; ia++){
			Temp1 = 0.0;
			Temp2 = 0.0;
			Temp3 = 0.0;
			Temp4 = 0.0;
			for(ii=0; ii<5; ii++){
				Temp1 += NewHIVbyAgeSex[ia*5+ii][0];
				Temp3 += NewHIVbyAgeSex[ia*5+ii][1];
				Temp2 += TotalPop_S[ia*5+ii+10][0] - TotalPositive_S[ia*5+ii+10][0];
				Temp4 += TotalPop_S[ia*5+ii+10][1] - TotalPositive_S[ia*5+ii+10][1];
			}
			if(CurrYear==2000){
				HIVinc2000.out[CurrSim-1][ia-1] = Temp1/Temp2;
				HIVinc2000.out[CurrSim-1][9+ia-1] = Temp3/Temp4;
			}
			if(CurrYear==2010){
				HIVinc2010.out[CurrSim-1][ia-1] = Temp1/Temp2;
				HIVinc2010.out[CurrSim-1][9+ia-1] = Temp3/Temp4;
			}
		}
	}

	// ART enrolment ratios
	// I've simplified by including the new infections in 10-14 years olds in the adult
	// denominator, which is not strictly correct.
	EnrolmentRatio.out[CurrSim - 1][iy] = StartingARTtot.out[CurrSim - 1][iy] /
		TotalNewHIV.out[CurrSim - 1][iy];
	EnrolmentRatio15M.out[CurrSim - 1][iy] = StartingART_M15.out[CurrSim - 1][iy] /
		NewHIV_M.out[CurrSim - 1][iy];
	EnrolmentRatio15F.out[CurrSim - 1][iy] = StartingART_F15.out[CurrSim - 1][iy] /
		NewHIV_F.out[CurrSim - 1][iy];
	EnrolmentRatioU15.out[CurrSim - 1][iy] = StartingART0to14.out[CurrSim - 1][iy] /
		(NewPerinatal + NewPostnatal);

	// AIDS deaths by age
	MaleAIDSdeathsAS.out[0][iy] += AIDSdeathsByAgeP[0][0] + 0.5 * AIDSdeathsByAgeP[1][0] -
		AIDSdeathsYOB[0];
	FemAIDSdeathsAS.out[0][iy] += AIDSdeathsByAgeP[0][1] + 0.5 * AIDSdeathsByAgeP[1][1] -
		AIDSdeathsYOB[1];
	for (ia = 1; ia < 9; ia++){
		MaleAIDSdeathsAS.out[ia][iy] += 0.5 * (AIDSdeathsByAgeP[ia][0] + AIDSdeathsByAgeP[ia+1][0]);
		FemAIDSdeathsAS.out[ia][iy] += 0.5 * (AIDSdeathsByAgeP[ia][1] + AIDSdeathsByAgeP[ia + 1][1]);
	}
	MaleAIDSdeathsAS.out[9][iy] += 0.5 * AIDSdeathsByAgeP[9][0] + AIDSdeathsByAgeP[10][0];
	FemAIDSdeathsAS.out[9][iy] += 0.5 * AIDSdeathsByAgeP[9][1] + AIDSdeathsByAgeP[10][1];
	for (ia = 10; ia <= 90; ia++){
		MaleAIDSdeathsAS.out[ia][iy] += AIDSdeathsByAge[ia - 10][0];
		FemAIDSdeathsAS.out[ia][iy] += AIDSdeathsByAge[ia - 10][1];
	}
	MaleAIDSdeathsAS.out[91][iy] += AIDSdeathsYOB[0];
	FemAIDSdeathsAS.out[91][iy] += AIDSdeathsYOB[1];

	// Migration by HIV status
	for (ia = 0; ia < 91; ia++){
		NetMigrantsNegM.out[ia][iy] += NetMigrNeg[ia][0];
		NetMigrantsNegF.out[ia][iy] += NetMigrNeg[ia][1];
		NetMigrantsPosM.out[ia][iy] += NetMigrPos[ia][0];
		NetMigrantsPosF.out[ia][iy] += NetMigrPos[ia][1];
	}

	// New PrEP initiations in key populations
	NewPrEPinAGYW.out[CurrSim - 1][iy] = NewPrEP_AGYW;
	NewPrEPinFSW.out[CurrSim - 1][iy] = NewPrEP_FSW;
	NewPrEPinMSM.out[CurrSim - 1][iy] = NewPrEP_MSM;
	NewPrEPinNonMSM.out[CurrSim - 1][iy] = NewPrEP_nonMSM; //LJ
	NewPrEPinNonFSW.out[CurrSim - 1][iy] = NewPrEP_nonFSW; //LJ
	NewPrEPinPWID.out[CurrSim - 1][iy] = NewPrEP_PWID;

	NewCABLAinAGYW.out[CurrSim - 1][iy] = NewCABLA_AGYW;
	NewCABLAinFSW.out[CurrSim - 1][iy] = NewCABLA_FSW;
	NewCABLAinMSM.out[CurrSim - 1][iy] = NewCABLA_MSM;
	NewCABLAinNonMSM.out[CurrSim - 1][iy] = NewCABLA_nonMSM; //LJ
	NewCABLAinNonFSW.out[CurrSim - 1][iy] = NewCABLA_nonFSW; //LJ
	NewCABLAinPWID.out[CurrSim - 1][iy] = NewCABLA_PWID;
}

void TBresultsAtEndOfYr()
{
	int ia, ig, iy, ii, is, id, CD4stage;
	double temp1, temp2, temp3, temp4, temp5, temp6, FalsePosRx[4];

	iy = CurrYear - StartYear;
	for (ii = 0; ii < 4; ii++) { FalsePosRx[ii] = 0.0; }

	// Incidence outputs
	if (FixedUncertainty == 1 || RatePrevTBscreened[iy + 1] > 0.0) {
		temp1 = 0.0;
		temp2 = 0.0;
		temp3 = 0.0;
		temp4 = 0.0;
		temp5 = 0.0;
		temp6 = 0.0;
		for (ia = 5; ia < 81; ia++) {
			temp1 += NewActiveTBbyAgeSex[ia][0] + NewActiveTBbyAgeSex[ia][1];
			temp2 += NewHIVposTBbyAgeSex[ia][0] + NewHIVposTBbyAgeSex[ia][1];
			temp3 += NewTBonARTbyAgeSex[ia][0] + NewTBonARTbyAgeSex[ia][1];
			temp4 += NewRecurrentTBbyAgeSex[ia][0] + NewRecurrentTBbyAgeSex[ia][1];
			temp5 += NewActiveTBbyAgeSex[ia][0];
			temp6 += NewRelapseTBbyAgeSex[ia][0] + NewRelapseTBbyAgeSex[ia][1];
		}
		NewActiveTBadult.out[CurrSim - 1][iy] = temp1;
		NewActiveTB_HIVpos.out[CurrSim - 1][iy] = temp2;
		NewActiveTBonART.out[CurrSim - 1][iy] = temp3;
		NewActiveTBprevTB.out[CurrSim - 1][iy] = temp4;
		NewActiveTBprevTBpropn.out[CurrSim - 1][iy] = temp4 / temp1;
		RelapseTBpropnLastYr = temp6 / temp1;
		NewActiveTBadultM.out[CurrSim - 1][iy] = temp5;
		NewActiveTBadultF.out[CurrSim - 1][iy] = temp1 - temp5;
		NewTBrateAdult.out[CurrSim - 1][iy] = temp1 / (MalesOver15.out[CurrSim - 1][iy] +
			FemalesOver15.out[CurrSim - 1][iy]);
		NewTBrateAdultM.out[CurrSim - 1][iy] = temp5 / MalesOver15.out[CurrSim - 1][iy];
		NewTBrateAdultF.out[CurrSim - 1][iy] = (temp1 - temp5) / FemalesOver15.out[CurrSim - 1][iy];
		PropnTBreactivation.out[CurrSim - 1][iy] = NewTBreactivation / temp1;
		TBincFastProg.out[CurrSim - 1][iy] = NewTBrateAdult.out[CurrSim - 1][iy] *
			(1.0 - PropnTBreactivation.out[CurrSim - 1][iy]);
		TBincReactivation.out[CurrSim - 1][iy] = NewTBrateAdult.out[CurrSim - 1][iy] *
			PropnTBreactivation.out[CurrSim - 1][iy];
		// Duration outputs (prevalence-to-incidence ratios)
		DurTBadult.out[CurrSim - 1][iy] = TotTBadult.out[CurrSim - 1][iy] / temp1;
		DurTBadultM.out[CurrSim - 1][iy] = TotTBadultM.out[CurrSim - 1][iy] / temp5;
		DurTBadultF.out[CurrSim - 1][iy] = TotTBadultF.out[CurrSim - 1][iy] / (temp1 - temp5);
		DurTBadultHIVpos.out[CurrSim - 1][iy] = TotTBadultHIVpos.out[CurrSim - 1][iy] / temp2;
		DurTBadultHIVneg.out[CurrSim - 1][iy] = TotTBadultHIVneg.out[CurrSim - 1][iy] / (temp1 - temp2);
	}
	if (FixedUncertainty == 1) { AnnMTBriskPaed.out[CurrSim - 1][iy] = AnnualRiskMTBpaed[iy]; }

	// Diagnosis and treatment outputs
	SmPosRxDelay[iy] = TotSmPosTB[iy] / (TBadultRxSmDiag[iy] + SmPosRxScreen[iy]);
	if (FixedUncertainty == 1 || CalibTBdiagnosesA == 1) {
		NewRxAdultTBsmPos.out[CurrSim - 1][iy] = TBadultRxSmDiag[iy];
		TotNewRxAdultTBsmPos.out[CurrSim - 1][iy] = TBadultRxSmDiag[iy] + NewRxACF[1] + 
			NewRxART_ICF[1] + NewRxTBscreenPrev[1] + NewRxTBscreenD2D[1];
		LabDiagAdultTB.out[CurrSim - 1][iy] = TBadultLabDiag[iy] + FalseTBadultLabDiag[iy];
		TBempiricRxAdults.out[CurrSim - 1][iy] += NewEmpiricTB[0] + NewEmpiricTB[1];
		TBempiricRxNoLab.out[CurrSim - 1][iy] += NewEmpiricTB[0];
		TBempiricRxNegLab.out[CurrSim - 1][iy] += NewEmpiricTB[1];
		temp1 = 0.0;
		temp2 = 0.0;
		temp3 = 0.0;
		for (ia = 0; ia < 16; ia++) {
			for (ig = 0; ig < 2; ig++) {
				temp1 += TBadultRxBy5yr[iy][ia][ig];
				if (ia < 2) { temp2 += TBadultRxBy5yr[iy][ia][ig]; }
			}
			if (FixedUncertainty == 1) {
				temp3 += TBadultRxBy5yr[iy][ia][0];
				MaleTBtreatAS.out[ia][iy] += TBadultRxBy5yr[iy][ia][0];
				FemTBtreatAS.out[ia][iy] += TBadultRxBy5yr[iy][ia][1];
			}
		}
		NewRxAdultTB.out[CurrSim - 1][iy] += temp1;
		if (FixedUncertainty == 1) {
			TreatedTB15to24.out[CurrSim - 1][iy] = temp2 / temp1;
			NewRxAdultTB_M.out[CurrSim - 1][iy] = temp3;
			NewRxAdultTB_F.out[CurrSim - 1][iy] = temp1 - temp3;
		}
		NewRxAdultTB_HIV.out[CurrSim - 1][iy] += TBadultRxHIV[iy][0] + TBadultRxHIV[iy][1];
		TotNewRxAdultTB_HIV.out[CurrSim - 1][iy] = NewRxAdultTB_HIV.out[CurrSim - 1][iy] +
			NewRxART_ICF[0] + NewRxART_ICF[1]; // Quick fix, ignoring other active case finding
	}
	if (FixedUncertainty == 1) {
		for (ig = 0; ig < 2; ig++) {
			temp1 = 0.0;
			for (ia = 0; ia < 16; ia++) {
				temp1 += TBadultRxBy5yr[iy][ia][ig];
			}
			if (ig == 0) { HIVprevNewRxTB_M.out[CurrSim - 1][iy] = TBadultRxHIV[iy][ig] / temp1; }
			else { HIVprevNewRxTB_F.out[CurrSim - 1][iy] = TBadultRxHIV[iy][ig] / temp1; }
		}
	}
	if (FixedUncertainty == 1) {
		NewRxAdultTB_ACF.out[CurrSim - 1][iy] = NewRxACF[0] + NewRxACF[1];
		TotalScreensACF.out[CurrSim - 1][iy] = TBindexCasesLastYr * HHcontactsPerCase * PropnHHcontactScreened[iy];
		TotalXpertScreensACF.out[CurrSim - 1][iy] = TBindexCasesLastYr * HHcontactsPerCase * PropnHHcontactScreened[iy] *
			(PropnHHcontactTUTT[iy] + (1.0 - PropnHHcontactTUTT[iy]) * (TBprevHHcontacts * Cough2wkActiveSmNeg + (1.0 -
				TBprevHHcontacts) * Cough2wkGen));
		// Add false positives
		FalsePosRx[0] = TBindexCasesLastYr * HHcontactsPerCase * PropnHHcontactScreened[iy] * (1.0 - TBprevHHcontacts) *
			(PropnHHcontactTUTT[iy] + (1.0 - PropnHHcontactTUTT[iy]) * Cough2wkGen) * (1.0 - CurrXpertSp) *
			(1.0 - CurrInitLTFU) * HHcontactRxUptake;
		NewRxAdultTB_ACF.out[CurrSim - 1][iy] += FalsePosRx[0];
		NewRxAdultTB_ART_ICF.out[CurrSim - 1][iy] = NewRxART_ICF[0] + NewRxART_ICF[1];
		if (RateART_TBscreened[iy] > 0.0 || RateART_TBscreened[iy + 1] > 0.0) {
			temp1 = 0.0;
			temp2 = 0.0;
			temp3 = 0.0;
			for (ia = 0; ia < 81; ia++) {
				for (is = 20; is < 40; is++) {
					CD4stage = (is - 20) / 5;
					id = is - 20 - CD4stage * 5;
					temp1 += TBactiveSmNegM.HIVstage[ia][is] * OnARThalfIntDur[id][0][ia] + 
						TBactiveSmNegF.HIVstage[ia][is] * OnARThalfIntDur[id][1][ia];
					temp2 += TBactiveSmPosM.HIVstage[ia][is] * OnARThalfIntDur[id][0][ia] + 
						TBactiveSmPosF.HIVstage[ia][is] * OnARThalfIntDur[id][1][ia];
					if (IncludeDR_TB == 1) {
						temp1 += TBactiveSmNegRR_M.HIVstage[ia][is] * OnARThalfIntDur[id][0][ia] +
							TBactiveSmNegRR_F.HIVstage[ia][is] * OnARThalfIntDur[id][1][ia];
						temp2 += TBactiveSmPosRR_M.HIVstage[ia][is] * OnARThalfIntDur[id][0][ia] +
							TBactiveSmPosRR_F.HIVstage[ia][is] * OnARThalfIntDur[id][1][ia];
					}
				}
				temp3 += TotalART[ia + 10][0] + TotalART[ia + 10][1];
			}
			temp3 = temp3 - temp1 - temp2;
			if (RateART_TBscreened[iy] > 0.0) {
				TotalScreensART_ICF.out[CurrSim - 1][iy] = 0.5 * (temp1 + TotARTbyTB[0] + temp2 + TotARTbyTB[1] +
					temp3 + TotARTbyTB[2]) * RateART_TBscreened[iy];
				TotalXpertScreensART_ICF.out[CurrSim - 1][iy] = ((0.5 * (temp1 + TotARTbyTB[0]) * Cough2wkActiveSmNeg +
					0.5 * (temp2 + TotARTbyTB[1]) * Cough2wkActiveSmNeg * RRsymptomsSmPos + 0.5 * (temp3 + TotARTbyTB[2]) *
					Cough2wkGen) * (1.0 - PropnART_TB_TUTT[iy]) + PropnART_TB_TUTT[iy] * 0.5 * (temp1 + TotARTbyTB[0] +
						temp2 + TotARTbyTB[1] + temp3 + TotARTbyTB[2])) * RateART_TBscreened[iy];
				// Add false positives
				FalsePosRx[1] = 0.5 * (temp3 + TotARTbyTB[2]) * (Cough2wkGen * (1.0 - PropnART_TB_TUTT[iy]) +
					PropnART_TB_TUTT[iy]) * RateART_TBscreened[iy] * (1.0 - CurrXpertSp) * (1.0 - CurrInitLTFU);
				NewRxAdultTB_ART_ICF.out[CurrSim - 1][iy] += FalsePosRx[1];
			}
			TotARTbyTB[0] = temp1;
			TotARTbyTB[1] = temp2;
			TotARTbyTB[2] = temp3;
		}
		NewRxAdultTBscreenPrev.out[CurrSim - 1][iy] = NewRxTBscreenPrev[0] + NewRxTBscreenPrev[1];
		if (RatePrevTBscreened[iy] > 0.0 || RatePrevTBscreened[iy + 1] > 0.0) {
			temp1 = 0.0;
			temp2 = 0.0;
			temp3 = 0.0;
			for (ia = 0; ia < 81; ia++) {
				temp1 += TBactiveSmNegM.Total[ia] + TBactiveSmNegF.Total[ia];
				temp2 += TBactiveSmPosM.Total[ia] + TBactiveSmPosF.Total[ia];
				temp3 += (TBrecoveredST_M.Total[ia] + TBrecoveredST_F.Total[ia] + TBrecST_IPT_M.Total[ia] +
					TBrecST_IPT_F.Total[ia]) * 4.0;
			}
			if (IncludeDR_TB == 1) {
				for (ia = 0; ia < 81; ia++) {
					temp1 += TBactiveSmNegRR_M.Total[ia] + TBactiveSmNegRR_F.Total[ia];
					temp2 += TBactiveSmPosRR_M.Total[ia] + TBactiveSmPosRR_F.Total[ia];
				}
			}
			temp1 *= RelapseTBpropnLastYr;
			temp2 *= RelapseTBpropnLastYr;
			if (RatePrevTBscreened[iy] > 0.0) {
				TotalScreensPrevTB.out[CurrSim - 1][iy] = 0.5 * (temp1 + PrevTBbyCurrTB[0] + temp2 + PrevTBbyCurrTB[1] +
					temp3 + PrevTBbyCurrTB[2]) * RatePrevTBscreened[iy];
				TotalXpertScreensPrevTB.out[CurrSim - 1][iy] = ((0.5 * (temp1 + PrevTBbyCurrTB[0]) * Cough2wkActiveSmNeg +
					0.5 * (temp2 + PrevTBbyCurrTB[1]) * Cough2wkActiveSmNeg * RRsymptomsSmPos + 0.5 * (temp3 +
						PrevTBbyCurrTB[2]) * Cough2wkGen) * (1.0 - PropnPrevTB_TUTT[iy]) + PropnPrevTB_TUTT[iy] * 0.5 * (temp1 +
							PrevTBbyCurrTB[0] + temp2 + PrevTBbyCurrTB[1] + temp3 + PrevTBbyCurrTB[2])) * RatePrevTBscreened[iy];
				// Add false positives
				FalsePosRx[2] = 0.5 * (temp3 + PrevTBbyCurrTB[2]) * (Cough2wkGen * (1.0 - PropnPrevTB_TUTT[iy]) +
					PropnPrevTB_TUTT[iy]) * RatePrevTBscreened[iy] * (1.0 - CurrXpertSp) * (1.0 - CurrInitLTFU);
				NewRxAdultTBscreenPrev.out[CurrSim - 1][iy] += FalsePosRx[2];
			}
			PrevTBbyCurrTB[0] = temp1;
			PrevTBbyCurrTB[1] = temp2;
			PrevTBbyCurrTB[2] = temp3;
		}
		NewRxAdultTBscreenD2D.out[CurrSim - 1][iy] = NewRxTBscreenD2D[0] + NewRxTBscreenD2D[1];
		if (RateD2Dscreen[iy] > 0.0) {
			temp1 = 0.0;
			temp2 = 0.0;
			temp3 = 0.0;
			for (ia = 0; ia < 81; ia++) {
				temp1 += TBactiveSmNegM.Total[ia] + TBactiveSmNegF.Total[ia];
				temp2 += TBactiveSmPosM.Total[ia] + TBactiveSmPosF.Total[ia];
				temp3 += TotalPop[ia + 10][0] + TotalPop[ia + 10][1];
			}
			if (IncludeDR_TB == 1) {
				for (ia = 0; ia < 81; ia++) {
					temp1 += TBactiveSmNegRR_M.Total[ia] + TBactiveSmNegRR_F.Total[ia];
					temp2 += TBactiveSmPosRR_M.Total[ia] + TBactiveSmPosRR_F.Total[ia];
				}
			}
			temp3 = temp3 - temp1 - temp2;
			TotalScreensD2D.out[CurrSim - 1][iy] = (temp1 + temp2 + temp3) * RateD2Dscreen[iy];
			Total_dCXRscreensD2D.out[CurrSim - 1][iy] = (temp1 * (1.0 - Cough2wkActiveSmNeg) + temp2 * (1.0 -
				Cough2wkActiveSmNeg * RRsymptomsSmPos) + temp3 * (1.0 - Cough2wkGen)) * RateD2Dscreen[iy] *
				PropnD2DdCXR[iy];
			TotalXpertScreensD2D.out[CurrSim - 1][iy] = (temp1 * (Cough2wkActiveSmNeg + (1.0 - Cough2wkActiveSmNeg) *
				PropnD2DdCXR[iy] * Se_dCXR) + temp2 * (Cough2wkActiveSmNeg * RRsymptomsSmPos + (1.0 - Cough2wkActiveSmNeg *
					RRsymptomsSmPos) * PropnD2DdCXR[iy] * Se_dCXR) + temp3 * (Cough2wkGen + (1.0 - Cough2wkGen) * PropnD2DdCXR[iy] *
						(1.0 - Sp_dCXR))) * RateD2Dscreen[iy];
			temp4 = (1.0 - AbleSputum[1]) * TongueSwabTested / AbleSputum[1];
			temp5 = (1.0 - AbleSputum[0]) * TongueSwabTested / AbleSputum[0];
			TotTongueSwabsD2D.out[CurrSim - 1][iy] = (temp1 * (Cough2wkActiveSmNeg * temp4 + (1.0 - Cough2wkActiveSmNeg) *
				PropnD2DdCXR[iy] * Se_dCXR * temp5) + temp2 * (Cough2wkActiveSmNeg * RRsymptomsSmPos * temp4 + (1.0 -
					Cough2wkActiveSmNeg * RRsymptomsSmPos) * PropnD2DdCXR[iy] * Se_dCXR * temp5) + temp3 * (Cough2wkGen * temp4 +
						(1.0 - Cough2wkGen) * PropnD2DdCXR[iy] * (1.0 - Sp_dCXR) * temp5)) * RateD2Dscreen[iy];
			// Add false positives
			FalsePosRx[3] = temp3 * (Cough2wkGen * (1.0 + temp4) + (1.0 - Cough2wkGen) * (1.0 + temp5) * PropnD2DdCXR[iy] *
				(1.0 - Sp_dCXR)) * RateD2Dscreen[iy] * (1.0 - CurrXpertSp) * (1.0 - CurrInitLTFU) * HHcontactRxUptake;
			NewRxAdultTBscreenD2D.out[CurrSim - 1][iy] += FalsePosRx[3];
		}
		TotLabDiagAllTBscreening.out[CurrSim - 1][iy] = LabDiagAdultTB.out[CurrSim - 1][iy] +
			NewRxAdultTB_ACF.out[CurrSim - 1][iy] / ((1.0 - CurrInitLTFU) * HHcontactRxUptake) +
			NewRxAdultTB_ART_ICF.out[CurrSim - 1][iy] / (1.0 - CurrInitLTFU) +
			NewRxAdultTBscreenPrev.out[CurrSim - 1][iy] / (1.0 - CurrInitLTFU) +
			NewRxAdultTBscreenD2D.out[CurrSim - 1][iy] / ((1.0 - CurrInitLTFU) * HHcontactRxUptake);
		TBtestingYield.out[CurrSim - 1][iy] = TotLabDiagAllTBscreening.out[CurrSim - 1][iy] /
			ModelTBtests[iy];
		TotNewRxAdultTBfalsePos.out[CurrSim - 1][iy] = NewRxAdultTBfalsePos.out[CurrSim - 1][iy] +
			FalsePosRx[0] + FalsePosRx[1] + FalsePosRx[2] + FalsePosRx[3];
		LabDiagFalsePosActive[iy] = ((FalsePosRx[0] + FalsePosRx[3])/(HHcontactRxUptake) + FalsePosRx[1] + 
			FalsePosRx[2]) / (1.0 - CurrInitLTFU);
		TotLabDiagAdultFalsePos.out[CurrSim - 1][iy] = LabDiagAdultTBfalsePos.out[CurrSim - 1][iy] +
			LabDiagFalsePosActive[iy];
		TotNewRxAdultTB.out[CurrSim - 1][iy] = NewRxAdultTB.out[CurrSim - 1][iy] + 
			NewRxAdultTB_ACF.out[CurrSim - 1][iy] + NewRxAdultTB_ART_ICF.out[CurrSim - 1][iy] +
			NewRxAdultTBscreenPrev.out[CurrSim - 1][iy] + NewRxAdultTBscreenD2D.out[CurrSim - 1][iy];
		HIVprevNewRxAdultTB.out[CurrSim - 1][iy] = TotNewRxAdultTB_HIV.out[CurrSim - 1][iy] /
			TotNewRxAdultTB.out[CurrSim - 1][iy];
		DiagnosisDelay.out[CurrSim - 1][iy] = AdultTBprevN.out[CurrSim - 1][iy] /
			TotNewRxAdultTB.out[CurrSim - 1][iy];
		CaseDetectionRatioT.out[CurrSim - 1][iy] = (TotNewRxAdultTB.out[CurrSim - 1][iy] -
			TotNewRxAdultTBfalsePos.out[CurrSim - 1][iy]) / NewActiveTBadult.out[CurrSim - 1][iy];
		if (CurrYear >= 2004 && CurrYear <= 2016) {
			temp1 = 0.0;
			for (ia = 0; ia < 16; ia++) {
				temp1 += RecordedTBcasesA[ia][iy - 19][0] + RecordedTBcasesA[ia][iy - 19][1];
			}
			CaseDetectionRatioR.out[CurrSim - 1][iy] = temp1 / NewActiveTBadult.out[CurrSim - 1][iy];
		}
		temp1 = 0.0;
		temp2 = 0.0;
		for (ii = 0; ii < 5 && ii <= iy; ii++) { // ii is years prior to current; guard against negative index
			temp1 += exp(-(ii + 0.5) / DurTBadult.out[CurrSim - 1][iy]) *
				NewActiveTBadult.out[CurrSim - 1][iy - ii];
			temp2 += exp(-(ii + 0.5) / DurTBadult.out[CurrSim - 1][iy]);
		}
		LagAdjCaseDetectionRatio.out[CurrSim - 1][iy] = (TotNewRxAdultTB.out[CurrSim - 1][iy] -
			TotNewRxAdultTBfalsePos.out[CurrSim - 1][iy]) / (temp1 / temp2);
	}
	if (FixedUncertainty == 1) {
		TotLabTestedAllScreening.out[CurrSim - 1][iy] = TotalScreens.out[CurrSim - 1][iy] +
			TotalXpertScreensACF.out[CurrSim - 1][iy] + TotalXpertScreensART_ICF.out[CurrSim - 1][iy] +
			TotalXpertScreensPrevTB.out[CurrSim - 1][iy] + TotalXpertScreensD2D.out[CurrSim - 1][iy];
	}

	// Drug resistance outputs
	if (FixedUncertainty == 1 && IncludeDR_TB == 1) {
		NewRifResAcquired.out[CurrSim - 1][iy] = FailTB_RxNewRR[iy] / (FailTB_RxNewRR[iy] +
			NewRR_TBnaive[iy] + NewRR_TBprevRx[iy]);
		/*RifResDetected.out[CurrSim - 1][iy] = (TBadultLabDiag[iy] - FalseTBadultLabDiag[iy]) *
			((NewRR_TBprevRx[iy - 1] + FailTB_Rx_RR[iy - 1]) * DSTcoveragePrevTB[iy] + NewRR_TBnaive[iy - 1] *
			DSTcoverageNewTB[iy]) / (NewRR_TBprevRx[iy - 1] + FailTB_Rx_RR[iy - 1] + NewRS_TBprevRx[iy - 1] +
			FailTB_Rx_RS[iy - 1] + NewRR_TBnaive[iy - 1] + NewRS_TBnaive[iy - 1]) + RifResFoundOnRx[iy];*/
		RifResDetected.out[CurrSim - 1][iy] = RifResFoundPreRx[iy] + RifResFoundOnRx[iy];
		RifResDetectedFailing.out[CurrSim - 1][iy] = RifResFoundOnRx[iy];
		New2ndRxAdultTB.out[CurrSim - 1][iy] = New2ndLineTB_NF[iy] + New2ndLineTB_F[iy];
		New2ndRxFailing1st.out[CurrSim - 1][iy] = New2ndLineTB_F[iy];
		CultureLPAtestsFailing.out[CurrSim - 1][iy] = CultureOrLPAfailing[iy];
	}

	// Mortality outputs
	if (FixedUncertainty == 1) {
		temp1 = 0.0;
		temp2 = 0.0;
		for (ia = 0; ia < 16; ia++) {
			MaleTBdeathsAS.out[ia][iy] += TBadultMortBy5yr[iy][ia][0];
			FemTBdeathsAS.out[ia][iy] += TBadultMortBy5yr[iy][ia][1];
			temp1 += TBadultMortBy5yr[iy][ia][0];
			temp2 += TBadultMortBy5yr[iy][ia][1];
		}
		TotTBdeathsM.out[CurrSim - 1][iy] = temp1;
		TotTBdeathsF.out[CurrSim - 1][iy] = temp2;
		TotTBmortRate.out[CurrSim - 1][iy] = (temp1 + temp2) / (MalesOver15.out[CurrSim - 1][iy] +
			FemalesOver15.out[CurrSim - 1][iy]);
		TotTBmortRateM.out[CurrSim - 1][iy] = temp1 / MalesOver15.out[CurrSim - 1][iy];
		TotTBmortRateF.out[CurrSim - 1][iy] = temp2 / FemalesOver15.out[CurrSim - 1][iy];
		TotTBdeathsAdult.out[CurrSim - 1][iy] = temp1 + temp2;
		TBdeathsOnRxM.out[CurrSim - 1][iy] = TBadultMortOnRx[iy][0];
		TBdeathsOnRxF.out[CurrSim - 1][iy] = TBadultMortOnRx[iy][1];
		TBdeathsOnRx.out[CurrSim - 1][iy] = TBadultMortOnRx[iy][0] + TBadultMortOnRx[iy][1];
		MortRateTB_RxM.out[CurrSim - 1][iy] = TBadultMortOnRx[iy][0] / NewRxAdultTB_M.out[CurrSim - 1][iy];
		MortRateTB_RxF.out[CurrSim - 1][iy] = TBadultMortOnRx[iy][1] / NewRxAdultTB_F.out[CurrSim - 1][iy];
		TBdeathsHIV.out[CurrSim - 1][iy] = TBdeathsAdultHIV[iy];
		CaseFatalityRatioA.out[CurrSim - 1][iy] = TotTBdeathsAdult.out[CurrSim - 1][iy] /
			NewActiveTBadult.out[CurrSim - 1][iy];
		CaseFatalityRatioT.out[CurrSim - 1][iy] = TBdeathsOnRx.out[CurrSim - 1][iy] /
			NewRxAdultTB.out[CurrSim - 1][iy];
		// Calculate adjustment to discontinuation rates for post-2016 period
		temp1 = 1.0;
		if (CurrYear > 2021) { temp1 = UltTBdefaultAdj; }
		else if (CurrYear > 2016) { temp1 = 0.2 * ((2021 - CurrYear) + (CurrYear - 2016) * UltTBdefaultAdj); }
		if (IncludeDR_TB == 0) {
			TBRxCompletion.out[CurrSim - 1][iy] = (1.0 - TBdeathsOnRx.out[CurrSim - 1][iy] /
				(NewRxAdultTB.out[CurrSim - 1][iy] - NewRxAdultTBfalsePos.out[CurrSim - 1][iy])) *
				exp(-0.5 * temp1 * (AnnDropoutTB_Rx[0] * 0.6 + AnnDropoutTB_Rx[1] * 0.4) *
					(DOTrollout[iy] + (1.0 - DOTrollout[iy]) / (RRdefaultDOT + (1.0 - RRdefaultDOT) *
						(1.0 - DOTSeffectivenessAdj))));
		}
		else {
			TBRxCompletion.out[CurrSim - 1][iy] = (1.0 - (TBadultMortOnRx1[iy][0] +
				TBadultMortOnRx1[iy][1]) / (NewRxAdultTB.out[CurrSim - 1][iy] -
					NewRxAdultTBfalsePos.out[CurrSim - 1][iy] - New2ndRxAdultTB.out[CurrSim - 1][iy])) *
				exp(-0.5 * temp1 * (AnnDropoutTB_Rx[0] * 0.6 + AnnDropoutTB_Rx[1] * 0.4) *
					(DOTrollout[iy] + (1.0 - DOTrollout[iy]) / (RRdefaultDOT + (1.0 - RRdefaultDOT) *
						(1.0 - DOTSeffectivenessAdj))));
			TBRx2Completion.out[CurrSim - 1][iy] = (1.0 - (TBadultMortOnRx2[iy][0] +
				TBadultMortOnRx2[iy][1]) / New2ndRxAdultTB.out[CurrSim - 1][iy]) *
				exp(-(Dur2ndLineRxTB[iy] / 12.0) * temp1 * (AnnDropoutTB_Rx[0] * 0.6 + AnnDropoutTB_Rx[1] * 0.4) *
					(DOTrollout[iy] + (1.0 - DOTrollout[iy]) / (RRdefaultDOT + (1.0 - RRdefaultDOT) *
						(1.0 - DOTSeffectivenessAdj))));
		}
		AdultLYlostTB.out[CurrSim - 1][iy] = 0.0;
		for (ia = 5; ia < 81; ia++) {
			AdultLYlostTB.out[CurrSim - 1][iy] += (TBmortSmNeg[ia][0] + TBmortSmPos[ia][0] +
				TBmortTreated[ia][0]) * WestLifeExpectA[ia][0] + (TBmortSmNeg[ia][1] +
					TBmortSmPos[ia][1] + TBmortTreated[ia][1]) * WestLifeExpectA[ia][1];
		}
	}

	// IPT outputs
	if (FixedUncertainty == 1) {
		NewIPTlatent.out[CurrSim - 1][iy] = NewIPT_TSTpos;
		NewTPTinHHcontacts.out[CurrSim - 1][iy] = NewTPT_HH;
		IPTstartRate.out[CurrSim - 1][iy] = BaseIPTuptake[iy] * RR_IPTuptakeARTdur[1];
		if (CurrYear == StartYear) { temp1 = 0.0; }
		else {
			//temp1 = 0.5 * (AdultARTinterrupters.out[CurrSim - 1][iy - 1] + 
			//	AdultARTinterrupters.out[CurrSim - 1][iy]) * ARTresumptionRate;
			temp1 = (TotalART15M.out[CurrSim - 1][iy] + TotalART15F.out[CurrSim - 1][iy]) *
				RR_IPTuptakeARTdur[2] / RR_IPTuptakeARTdur[1];
			temp1 += 0.5 * (DiagnosedHIV_M.out[CurrSim - 1][iy] - TotalART15M.out[CurrSim - 1][iy] +
				DiagnosedHIV_F.out[CurrSim - 1][iy] - TotalART15F.out[CurrSim - 1][iy]) *
				RR_IPTuptakeARTdur[0] / RR_IPTuptakeARTdur[1];
		}
		IPTcoverage.out[CurrSim - 1][iy] = NewIPT_TSTpos / (StartingART_M15.out[CurrSim - 1][iy] +
			StartingART_F15.out[CurrSim - 1][iy] + temp1);
	}
}

void OneYear()
{
	int im;

	CurrYear +=1;
	if(CurrYear==1985){
		GetCurrBehavDbnF();
		GetCurrBehavDbnM();
		UpdatePop();
	}
	ResetMonthlyCum();
	//ResultsAtStartOfYr();
	if (RRperCalYr != 1.00){ SetProgression(1); }
	UpdateNonAIDSmort();
	UpdateAIDSmort();
	SetCurrYearParameters();
	SetAnnPaedParameters();
	MaleChild.NewNonVertCurrY = 0.0;
	FemChild.NewNonVertCurrY = 0.0;
	// Temporarily changing placement of functions called monthly
	UpdateAgePrefsF();
	UpdatePartnerAcqM();
	UpdateMixingST();
	UpdateARTmort();
	SetCD4byARTdur();
	//if(CurrYear==StartYear){
	//	UpdateCondomUse();}
	UpdateCondomUse();
	//CalcOIsTested();
	CalcPosPartnerProb();
	CalcSelfTestingRates();
	UpdateTestingRates();
	if (UseNumbersTests==1 && (NumbersTested[CurrYear - 1985] > 0.0)){
		CalcHCT1stTime();
		if (NumbersTested5to14[CurrYear - 1985] > 0.0){ CalcRRtestVirgin(); }
		UpdateTestingRates();
	}
	GetTotalTesting();
	ResultsAtStartOfYr(); // Should come after updating rates of condom use
	if (IncludeTB == 1) {
		CalcTBincAdjByAgeSex();
		CalcTBscreenPropn();
		CalcHIVeffectTB();
	}
	for(im=0; im<12; im++){
		OneMonth(im);
		if(im==7){GetPrevPregnant();}
		if (im == 11 && IncludeTB == 1) { UpdateIPTuptake(); }
	}

	// Update calculation of annual RATES
	// (Note that we first have to update the calcs of totals, since these are our denominators.)
	GetCurrBehavDbnF();
	GetCurrBehavDbnM();
	UpdatePop();
	ResultsAtEndOfYr();
	UpdateAgePrefsF();
	UpdatePartnerAcqM();
	UpdateCircProb();
	UpdateMigration();
	GetMarriageAndDivorceRates();

	// Update male circumcision
	UpdateMC(&MHU_virgin, &MHC_virgin);
	UpdateMC(&MHU_ST, &MHC_ST);
	UpdateMC(&MHU_STM, &MHC_STM);
	UpdateMC(&MHU_ID, &MHC_ID);
	UpdateMC(&MHU_LTH, &MHC_LTH);
	UpdateMC(&MHU_LTL, &MHC_LTL);
	UpdateMC(&MHU_LTM, &MHC_LTM);
	UpdateMC(&MLU_virgin, &MLC_virgin);
	UpdateMC(&MLU_ST, &MLC_ST);
	UpdateMC(&MLU_STM, &MLC_STM);
	UpdateMC(&MLU_ID, &MLC_ID);
	UpdateMC(&MLU_LTH, &MLC_LTH);
	UpdateMC(&MLU_LTL, &MLC_LTL);
	UpdateMC(&MLU_LTM, &MLC_LTM);

	// Update marital status
	UpdateMarital(&MHU_ST, &MHU_LTH, &MHU_LTL);
	UpdateMarital(&MHC_ST, &MHC_LTH, &MHC_LTL);
	UpdateMarital(&MLU_ST, &MLU_LTH, &MLU_LTL);
	UpdateMarital(&MLC_ST, &MLC_LTH, &MLC_LTL);
	UpdateMarital(&FH_ST, &FH_LTH, &FH_LTL);
	UpdateMarital(&FL_ST, &FL_LTH, &FL_LTL);
	UpdateMarriedMSM(&MHU_STM, &MHU_LTM);
	UpdateMarriedMSM(&MHC_STM, &MHC_LTM);
	UpdateMarriedMSM(&MLU_STM, &MLU_LTM);
	UpdateMarriedMSM(&MLC_STM, &MLC_LTM);

	UpdateAllDemog();

	// Update sexual debut
	UpdateDebut(&MHU_virgin, &MHU_ST, &MHU_STM, 1);
	UpdateDebut(&MHC_virgin, &MHC_ST, &MHC_STM, 1);
	UpdateDebut(&MLU_virgin, &MLU_ST, &MLU_STM, 1);
	UpdateDebut(&MLC_virgin, &MLC_ST, &MLC_STM, 1);
	UpdateDebut(&FH_virgin, &FH_ST, &FH_ST, 1);
	UpdateDebut(&FL_virgin, &FL_ST, &FL_ST, 1);

	// Update injecting drug use
	UpdatePWID(&MHU_ST, &MHU_ID);
	UpdatePWID(&MHC_ST, &MHC_ID);
	UpdatePWID(&MLU_ST, &MLU_ID);
	UpdatePWID(&MLC_ST, &MLC_ID);
	UpdatePWID(&FH_ST, &FH_ID);
	UpdatePWID(&FL_ST, &FL_ID);

	// Update totals
	UpdateStartTot();
	GetCurrBehavDbnF();
	GetCurrBehavDbnM();
	UpdatePop();
	if (IncludeTB == 1) { UpdateAllDemogTB(); }
	
	if(FixedUncertainty==1){
		ResultsAtEndOfYr2();} // None of these outputs are required for calibration
	if (IncludeTB == 1) { TBresultsAtEndOfYr(); }
}

